                    @if (selectedId() === app.id) {
                      <div class="ak-card-actions">
                        @if (col.id === 'applied') {
                          <button type="button" class="ak-action-btn ak-action-btn--review"
                            (click)="moveToReview(app.id, $event)">
                            <span class="material-symbols-outlined">search</span>
                            Em Análise
                          </button>
