        <!-- X-axis labels -->
        <g class="x-labels">
          @for (label of xLabels(); track $index) {
            <text
              [attr.x]="label.x"
              [attr.y]="svgHeight() - padding.bottom + 16"
              class="axis-label"
              text-anchor="middle"
            >{{ label.text }}</text>
          }
        </g>

        <!-- Series paths -->
        @for (series of computedSeries(); track series.name) {
          <!-- Area fill -->
          <path
            [attr.d]="series.areaPath"
            [attr.fill]="series.color"
            class="area-fill"
            opacity="0.12"
          />
          <!-- Line -->
          <path
            [attr.d]="series.linePath"
            [attr.stroke]="series.color"
            class="line-path"
            fill="none"
          />
          <!-- Data points -->
          @for (point of series.points; track $index) {
            <circle
              [attr.cx]="point.x"
              [attr.cy]="point.y"
              r="4"
              [attr.fill]="series.color"
              [attr.stroke]="series.color"
              class="data-point"
              (mouseenter)="onPointHover($event, series.name, point.label, point.value)"
              (mouseleave)="onPointLeave()"
            />
          }
        }

        <!-- Tooltip -->
        @if (tooltip().visible) {
          <g class="tooltip-group">
            <rect
              [attr.x]="tooltip().x + 8"
              [attr.y]="tooltip().y - 28"
              [attr.width]="tooltip().width"
              height="24"
              rx="4"
              class="tooltip-bg"
            />
            <text
              [attr.x]="tooltip().x + 8 + tooltip().width / 2"
              [attr.y]="tooltip().y - 11"
              class="tooltip-text"
              text-anchor="middle"
            >{{ tooltip().text }}</text>
          </g>
        }
      </svg>

      <!-- Legend -->
      @if (showLegend() && series().length > 1) {
        <div class="chart-legend">
          @for (s of series(); track s.name) {
            <div class="legend-item">
              <span class="legend-dot" [style.background]="getSeriesColor($index)"></span>
              <span class="legend-label">{{ s.name }}</span>
            </div>
          }
        </div>
      }
    </div>
  `,
  styles: [`
    .iu-line-chart {
      display: flex;
      flex-direction: column;
      font-family: var(--md-sys-typescale-body-small-font, 'Roboto', sans-serif);
    }
    .chart-title {
      font-size: 14px;
      font-weight: 500;
      color: var(--md-sys-color-on-surface);
      margin-bottom: 8px;
      padding-left: 4px;
    }
    .chart-svg { overflow: visible; }
    .grid-line {
      stroke: var(--md-sys-color-outline-variant, #ccc);
      stroke-width: 1;
      stroke-dasharray: 4 4;
    }
    .axis-label {
      fill: var(--md-sys-color-on-surface-variant, #666);
