      fill: var(--md-sys-color-inverse-surface, #333);
      opacity: 0.9;
    }
    .tooltip-text {
      fill: var(--md-sys-color-inverse-on-surface, #fff);
      font-size: 11px;
      font-weight: 500;
    }
    .chart-legend {
      display: flex;
      flex-wrap: wrap;
      gap: 12px;
