    const inputs = fixture.nativeElement.querySelectorAll('.dre-top .dre-input') as NodeListOf<HTMLInputElement>;
    expect(inputs[1].value).toBe('10');
  });

  it('typing in the withholding input calls service.setWithholdingPct', () => {
