        <!-- LANDLORD SIGNED — waiting for tenant -->
        @case ('landlord_signed') {
          <div class="lsf-wait-panel">
            <div class="lsf-sig-preview">
              <div class="lsf-sig-preview-label">
                <span class="material-symbols-outlined">check_circle</span>
