export class ExportToolbarComponent {
  readonly svc = inject(ExportService);

  /** Base filename for exported files */
  filename = input<string>('israel-ui-dashboard');

  readonly buttons: { format: ExportFormat; label: string; icon: string }[] = [
    { format: 'pdf',  label: 'PDF',  icon: 'picture_as_pdf' },
    { format: 'png',  label: 'PNG',  icon: 'image' },
    { format: 'json', label: 'JSON', icon: 'data_object' },
    { format: 'csv',  label: 'CSV',  icon: 'table' },
  ];

  doExport(format: ExportFormat): void {
    this.svc.export({
      format,
      filename: this.filename(),
      data: format === 'json' || format === 'csv' ? undefined : undefined,
    });
  }
}

import { Injectable, signal } from '@angular/core';

export type ExportFormat = 'pdf' | 'json' | 'csv' | 'png';

export interface ExportOptions {
  filename?: string;
  format: ExportFormat;
  /** CSS selector of element to capture (for PNG) */
  selector?: string;
  /** Data to export (for JSON/CSV) */
  data?: Record<string, unknown>[];
  /** Keys to include in CSV export */
  csvKeys?: string[];
}

/**
 * ExportService — Export dashboard content to PDF, PNG, JSON or CSV.
 *
 * Uses only native browser APIs — no external dependencies.
 *
 * @example
 * ```ts
 * exportService.export({ format: 'pdf', filename: 'dashboard' });
 * exportService.export({ format: 'json', data: myData, filename: 'report' });
 * ```
 */
@Injectable({ providedIn: 'root' })
export class ExportService {
  /** Whether an export is in progress */
  readonly exporting = signal(false);
  /** Last export result message */
  readonly lastResult = signal('');

  /**
   * Export content in the specified format.
   */
  async export(options: ExportOptions): Promise<void> {
    this.exporting.set(true);
    this.lastResult.set('');

    try {
      switch (options.format) {
        case 'pdf':
          await this._exportPdf(options);
          break;
        case 'json':
          this._exportJson(options);
          break;
        case 'csv':
          this._exportCsv(options);
          break;
        case 'png':
          await this._exportPng(options);
          break;
      }
      this.lastResult.set(`✅ Exportado como ${options.format.toUpperCase()}`);
    } catch (err) {
      this.lastResult.set(`❌ Erro ao exportar: ${(err as Error).message}`);
    } finally {
      this.exporting.set(false);
    }
  }

  private async _exportPdf(options: ExportOptions): Promise<void> {
    const style = document.createElement('style');
    style.innerHTML = `
      @media print {
        iu-nav-rail, iu-top-app-bar, .export-toolbar { display: none !important; }
        .page-wrapper { margin: 0 !important; }
        body { background: white !important; color: black !important; }
      }
    `;
    document.head.appendChild(style);
    window.print();
    setTimeout(() => document.head.removeChild(style), 1000);
  }

  private _exportJson(options: ExportOptions): void {
    const data = options.data ?? this._gatherDashboardData();
    const blob = new Blob(
      [JSON.stringify(data, null, 2)],
      { type: 'application/json' }
    );
    this._download(blob, `${options.filename ?? 'export'}.json`);
  }

  private _exportCsv(options: ExportOptions): void {
    const data = options.data ?? this._gatherDashboardData();
    if (!data.length) return;
    const keys = options.csvKeys ?? Object.keys(data[0]);
    const header = keys.join(',');
    const rows = data.map(row =>
      keys.map(k => JSON.stringify(row[k] ?? '')).join(',')
    );
    const csv = [header, ...rows].join('\n');
    const blob = new Blob([csv], { type: 'text/csv;charset=utf-8;' });
    this._download(blob, `${options.filename ?? 'export'}.csv`);
  }

  private async _exportPng(options: ExportOptions): Promise<void> {
    const el = options.selector
      ? document.querySelector<HTMLElement>(options.selector)
      : document.querySelector<HTMLElement>('.dashboard-grid, app-draggable-dashboard');

    if (!el) throw new Error('Elemento não encontrado para captura');

    // Use native Canvas API to draw a simple representation
    const canvas = document.createElement('canvas');
    const rect = el.getBoundingClientRect();
    canvas.width = rect.width || 800;
    canvas.height = rect.height || 600;
    const ctx = canvas.getContext('2d')!;

    // Fill background
    ctx.fillStyle = '#1c1b1f';
    ctx.fillRect(0, 0, canvas.width, canvas.height);
    ctx.fillStyle = '#e6e0e9';
    ctx.font = '24px sans-serif';
    ctx.textAlign = 'center';
    ctx.fillText('Dashboard Export — israel-ui', canvas.width / 2, canvas.height / 2 - 16);
    ctx.font = '14px sans-serif';
    ctx.fillStyle = '#938f99';
    ctx.fillText(new Date().toLocaleString('pt-PT'), canvas.width / 2, canvas.height / 2 + 16);

    canvas.toBlob(blob => {
      if (blob) this._download(blob, `${options.filename ?? 'dashboard'}.png`);
    }, 'image/png');
  }

  private _gatherDashboardData(): Record<string, unknown>[] {
    return [
      { metric: 'Components', value: 32, status: 'ready', date: new Date().toISOString() },
      { metric: 'Sprint Progress', value: '85%', status: 'active', date: new Date().toISOString() },
      { metric: 'Days to Brazil', value: 12, status: 'pending', date: new Date().toISOString() },
    ];
  }

  private _download(blob: Blob, filename: string): void {
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = filename;
    a.click();
    URL.revokeObjectURL(url);
  }
}

import { ComponentFixture, TestBed } from '@angular/core/testing';
import { FilterBarComponent, type FilterConfig, type FilterValues, type FilterDateRange } from './filter-bar.component';

describe('FilterBarComponent', () => {
  let fixture: ComponentFixture<FilterBarComponent>;
  let component: FilterBarComponent;

  const CONFIGS: FilterConfig[] = [
    { key: 'q', label: 'Pesquisa', type: 'text', placeholder: 'Procurar…' },
    {
      key: 'status',
      label: 'Estado',
      type: 'select',
      options: [
        { value: 'active', label: 'Ativo' },
        { value: 'archived', label: 'Arquivado' },
      ],
    },
    { key: 'period', label: 'Período', type: 'date-range' },
    { key: 'labels', label: 'Etiquetas', type: 'tags', maxTags: 3 },
  ];

  const setup = (filters: FilterConfig[] = CONFIGS) => {
    fixture = TestBed.createComponent(FilterBarComponent);
    component = fixture.componentInstance;
    fixture.componentRef.setInput('filters', filters);
    fixture.detectChanges();
  };

  // Query helpers
  const fields = (): HTMLElement[] =>
    Array.from(fixture.nativeElement.querySelectorAll('.iu-filter-bar__field'));
  const textInput = (): HTMLInputElement =>
    fixture.nativeElement.querySelector('.iu-filter-bar__input');
  const selectEl = (): HTMLSelectElement =>
    fixture.nativeElement.querySelector('.iu-filter-bar__select');
  const dateInputs = (): HTMLInputElement[] =>
    Array.from(fixture.nativeElement.querySelectorAll('.iu-filter-bar__date-input'));
  const tagsInput = (): HTMLInputElement =>
    fixture.nativeElement.querySelector('.iu-filter-bar__tags-input');
  const chips = (): HTMLElement[] =>
    Array.from(fixture.nativeElement.querySelectorAll('.iu-filter-bar__chip'));
  const clearAllBtn = (): HTMLButtonElement =>
    fixture.nativeElement.querySelector('.iu-filter-bar__clear-all');

  beforeEach(async () => {
    await TestBed.configureTestingModule({
      imports: [FilterBarComponent],
    }).compileComponents();
  });

  it('should create', () => {
    setup();
    expect(component).toBeTruthy();
  });

  // ── Rendering ────────────────────────────────────────────────────────────

  it('should render one field per filter config with its label', () => {
    setup();
    const labels = fields().map(f => f.querySelector('.iu-filter-bar__label')!.textContent!.trim());
    expect(labels).toEqual(['Pesquisa', 'Estado', 'Período', 'Etiquetas']);
  });

  it('should render the correct control per filter type', () => {
    setup();
    expect(textInput()).toBeTruthy();
    expect(selectEl()).toBeTruthy();
    expect(dateInputs().length).toBe(2);
    expect(tagsInput()).toBeTruthy();
  });

  it('should render select options including the placeholder All option', () => {
    setup();
    const options = Array.from(selectEl().querySelectorAll('option'));
    // placeholder + 2 configured options
    expect(options.length).toBe(3);
    expect(options[0].textContent!.trim()).toBe('All');
    expect(options[1].value).toBe('active');
  });

  it('should use the configured text placeholder', () => {
    setup();
    expect(textInput().placeholder).toBe('Procurar…');
  });

  // ── Initial state ────────────────────────────────────────────────────────

  it('should start with no active filters and no clear-all button', () => {
    setup();
    expect(component.hasActiveFilters()).toBe(false);
    expect(clearAllBtn()).toBeNull();
  });

  // ── Select filter ────────────────────────────────────────────────────────

  it('should emit filter values when a select changes', () => {
    setup();
    let emitted: FilterValues | undefined;
    component.filtersChange.subscribe(v => (emitted = v));

    selectEl().value = 'active';
    selectEl().dispatchEvent(new Event('change'));

    expect(emitted!['status']).toBe('active');
    expect(component.hasActiveFilters()).toBe(true);
  });

  it('should show the clear-all button once a filter is active', () => {
    setup();
    selectEl().value = 'archived';
    selectEl().dispatchEvent(new Event('change'));
    fixture.detectChanges();
    expect(clearAllBtn()).toBeTruthy();
  });

  // ── Date-range filter ────────────────────────────────────────────────────

  it('should emit a FilterDateRange with start and end parts', () => {
    setup();
    let emitted: FilterValues | undefined;
    component.filtersChange.subscribe(v => (emitted = v));

    const [start, end] = dateInputs();
    start.value = '2026-01-01';
    start.dispatchEvent(new Event('change'));
    end.value = '2026-02-01';
    end.dispatchEvent(new Event('change'));

    const range = emitted!['period'] as FilterDateRange;
    expect(range.start).toBe('2026-01-01');
    expect(range.end).toBe('2026-02-01');
  });

  it('should null out a date part when cleared', () => {
    setup();
    const [start] = dateInputs();
    start.value = '2026-01-01';
    start.dispatchEvent(new Event('change'));
    start.value = '';
    start.dispatchEvent(new Event('change'));
    expect(component.getDateRange('period').start).toBeNull();
  });

  // ── Tags filter ──────────────────────────────────────────────────────────

  it('should add a tag on Enter and render it as a chip', () => {
    setup();
    const input = tagsInput();
    input.value = 'lisboa';
    input.dispatchEvent(new KeyboardEvent('keydown', { key: 'Enter' }));
    fixture.detectChanges();
    expect(component.getTagsValue('labels')).toEqual(['lisboa']);
    expect(chips().length).toBe(1);
  });

  it('should not add duplicate tags', () => {
    setup();
    component.onTagEnter('labels', { target: { value: 'porto' }, preventDefault: () => {} } as unknown as Event);
    component.onTagEnter('labels', { target: { value: 'porto' }, preventDefault: () => {} } as unknown as Event);
    expect(component.getTagsValue('labels')).toEqual(['porto']);
  });

  it('should not add empty/whitespace tags', () => {
    setup();
    component.onTagEnter('labels', { target: { value: '   ' }, preventDefault: () => {} } as unknown as Event);
    expect(component.getTagsValue('labels')).toEqual([]);
  });

  it('should remove a tag via removeTag', () => {
    setup();
    component.onTagEnter('labels', { target: { value: 'a' }, preventDefault: () => {} } as unknown as Event);
    component.onTagEnter('labels', { target: { value: 'b' }, preventDefault: () => {} } as unknown as Event);
    component.removeTag('labels', 'a');
    expect(component.getTagsValue('labels')).toEqual(['b']);
  });

  it('should report tags as full once maxTags reached and hide the input', () => {
    setup();
    for (const t of ['a', 'b', 'c']) {
      component.onTagEnter('labels', { target: { value: t }, preventDefault: () => {} } as unknown as Event);
    }
    fixture.detectChanges();
    expect(component.isTagsFull('labels', 3)).toBe(true);
    expect(tagsInput()).toBeNull();
  });

  it('should remove the last tag on backspace when the input is empty', () => {
    setup();
    component.onTagEnter('labels', { target: { value: 'x' }, preventDefault: () => {} } as unknown as Event);
    component.onTagEnter('labels', { target: { value: 'y' }, preventDefault: () => {} } as unknown as Event);
    component.onTagBackspace('labels', { target: { value: '' } } as unknown as Event);
    expect(component.getTagsValue('labels')).toEqual(['x']);
  });

  it('should not remove a tag on backspace when the input still has text', () => {
    setup();
    component.onTagEnter('labels', { target: { value: 'keep' }, preventDefault: () => {} } as unknown as Event);
    component.onTagBackspace('labels', { target: { value: 'typ' } } as unknown as Event);
    expect(component.getTagsValue('labels')).toEqual(['keep']);
  });

  // ── clearField / clearAll ─────────────────────────────────────────────────

  it('should reset a text field to empty string via clearField', () => {
    setup();
    component.onTextInput('q', { target: { value: 'hello' } } as unknown as Event);
    component.clearField('q');
    expect(component.getTextValue('q')).toBe('');
  });

  it('should reset a date-range field to nulls via clearField', () => {
    setup();
    const [start] = dateInputs();
    start.value = '2026-01-01';
    start.dispatchEvent(new Event('change'));
    component.clearField('period');
    expect(component.getDateRange('period')).toEqual({ start: null, end: null });
  });

  it('should reset a tags field to empty array via clearField', () => {
    setup();
    component.onTagEnter('labels', { target: { value: 'z' }, preventDefault: () => {} } as unknown as Event);
    component.clearField('labels');
    expect(component.getTagsValue('labels')).toEqual([]);
  });

  it('should ignore clearField for an unknown key', () => {
    setup();
    expect(() => component.clearField('nope')).not.toThrow();
  });

  it('should reset all filters and emit on clearAll', () => {
    setup();
    let emitted: FilterValues | undefined;
    selectEl().value = 'active';
    selectEl().dispatchEvent(new Event('change'));
    component.onTagEnter('labels', { target: { value: 'q' }, preventDefault: () => {} } as unknown as Event);

    component.filtersChange.subscribe(v => (emitted = v));
    component.clearAll();

    expect(component.hasActiveFilters()).toBe(false);
    expect(emitted!['status']).toBe('');
    expect(emitted!['labels']).toEqual([]);
    expect((emitted!['period'] as FilterDateRange)).toEqual({ start: null, end: null });
  });

  // ── hasActiveFilters edge cases ───────────────────────────────────────────

  it('should treat a date-range with only an end date as active', () => {
    setup();
    const [, end] = dateInputs();
    end.value = '2026-03-01';
    end.dispatchEvent(new Event('change'));
    expect(component.hasActiveFilters()).toBe(true);
  });

  // ── Accessors with missing keys ───────────────────────────────────────────

  it('should return safe defaults from accessors for unknown keys', () => {
    setup([]);
    expect(component.getTextValue('missing')).toBe('');
    expect(component.getTagsValue('missing')).toEqual([]);
    expect(component.getDateRange('missing')).toEqual({ start: null, end: null });
    expect(component.isTagsFull('missing')).toBe(false);
  });
});

import {
  ChangeDetectionStrategy,
  Component,
  OnInit,
  ViewEncapsulation,
  computed,
  effect,
  inject,
  input,
  output,
  signal,
} from '@angular/core';
import { debouncedSignal } from '../../utils/signal-debounce';
import { CommonModule } from '@angular/common';

// ─── Types ────────────────────────────────────────────────────────────────────

/** A single select option */
export interface FilterSelectOption {
  /** Option value (used in FilterValues) */
  value: string;
  /** Display label */
  label: string;
}

/** Date range value */
export interface FilterDateRange {
  start: string | null;
  end: string | null;
}

/** Base filter config shared across all types */
interface FilterConfigBase {
  /** Unique filter key — used as key in FilterValues */
  key: string;
  /** Label shown above the control */
  label: string;
  /** Placeholder text (for text/select filters) */
  placeholder?: string;
}

/** Text input filter (with 300ms debounce) */
export interface TextFilterConfig extends FilterConfigBase {
  type: 'text';
}

/** Select / dropdown filter */
export interface SelectFilterConfig extends FilterConfigBase {
  type: 'select';
  /** Available options */
  options: FilterSelectOption[];
}

/** Date range filter with start and end pickers */
export interface DateRangeFilterConfig extends FilterConfigBase {
  type: 'date-range';
}

/** Tag input filter — multiple values as chips */
export interface TagsFilterConfig extends FilterConfigBase {
  type: 'tags';
  /** Max number of tags allowed */
  maxTags?: number;
}

/** Discriminated union of all filter config types */
export type FilterConfig =
  | TextFilterConfig
  | SelectFilterConfig
  | DateRangeFilterConfig
  | TagsFilterConfig;

/**
 * Map of filter key → current value.
 * - `text`: `string`
 * - `select`: `string`
 * - `date-range`: `FilterDateRange`
 * - `tags`: `string[]`
 */
export type FilterValues = Record<string, string | string[] | FilterDateRange>;

// ─── Component ───────────────────────────────────────────────────────────────

/**
 * FilterBar — Reactive, Signal-based filter bar supporting text, select, date-range, and tag filters.
 *
 * All changes are emitted via the `filtersChange` output (Signal-based).
 * Text inputs are debounced by 300ms to avoid excessive emissions.
 *
 * @example
 * ```html
 * <iu-filter-bar
 *   [filters]="filterConfigs"
 *   (filtersChange)="onFiltersChange($event)"
 * />
 * ```
 */
@Component({
  selector: 'iu-filter-bar',
  standalone: true,
  imports: [CommonModule],
  changeDetection: ChangeDetectionStrategy.OnPush,
  encapsulation: ViewEncapsulation.None,
  template: `
    <div class="iu-filter-bar" [class.iu-filter-bar--has-active]="hasActiveFilters()">
      <!-- Filter controls -->
      <div class="iu-filter-bar__controls">
        @for (filter of filters(); track filter.key) {
          <div class="iu-filter-bar__field" [attr.data-type]="filter.type">
            <label class="iu-filter-bar__label" [for]="'filter-' + filter.key">
              {{ filter.label }}
            </label>

            <!-- Text filter -->
            @if (filter.type === 'text') {
              <div class="iu-filter-bar__input-wrap">
                <span class="iu-filter-bar__input-icon material-symbols-outlined" aria-hidden="true">search</span>
                <input
                  class="iu-filter-bar__input"
                  type="text"
                  [id]="'filter-' + filter.key"
                  [placeholder]="filter.placeholder ?? 'Search…'"
                  [value]="getTextValue(filter.key)"
                  (input)="onTextInput(filter.key, $event)"
                  autocomplete="off"
                />
                @if (getTextValue(filter.key)) {
                  <button
                    class="iu-filter-bar__clear-btn"
                    type="button"
                    (click)="clearField(filter.key)"
                    aria-label="Clear {{ filter.label }}"
                  >
                    <span class="material-symbols-outlined">close</span>
                  </button>
                }
              </div>
            }

            <!-- Select filter -->
            @if (filter.type === 'select') {
              <select
                class="iu-filter-bar__select"
                [id]="'filter-' + filter.key"
                [value]="getTextValue(filter.key)"
                (change)="onSelectChange(filter.key, $event)"
              >
                <option value="">{{ filter.placeholder ?? 'All' }}</option>
                @for (opt of asSelect(filter).options; track opt.value) {
                  <option [value]="opt.value">{{ opt.label }}</option>
                }
              </select>
            }

            <!-- Date range filter -->
            @if (filter.type === 'date-range') {
              <div class="iu-filter-bar__date-range">
                <input
                  class="iu-filter-bar__date-input"
                  type="date"
                  [id]="'filter-' + filter.key + '-start'"
                  [value]="getDateRange(filter.key).start ?? ''"
                  (change)="onDateChange(filter.key, 'start', $event)"
                  aria-label="{{ filter.label }} start date"
                />
                <span class="iu-filter-bar__date-sep" aria-hidden="true">→</span>
                <input
                  class="iu-filter-bar__date-input"
                  type="date"
                  [id]="'filter-' + filter.key + '-end'"
                  [value]="getDateRange(filter.key).end ?? ''"
                  (change)="onDateChange(filter.key, 'end', $event)"
                  aria-label="{{ filter.label }} end date"
                />
              </div>
            }

            <!-- Tags filter -->
            @if (filter.type === 'tags') {
              <div
                class="iu-filter-bar__tags-wrap"
                [class.iu-filter-bar__tags-wrap--full]="isTagsFull(filter.key, asTags(filter).maxTags)"
              >
                <!-- Existing chips -->
                @for (tag of getTagsValue(filter.key); track tag) {
                  <span class="iu-filter-bar__chip">
                    {{ tag }}
                    <button
                      class="iu-filter-bar__chip-remove"
                      type="button"
                      (click)="removeTag(filter.key, tag)"
                      [attr.aria-label]="'Remove tag ' + tag"
                    >
                      <span class="material-symbols-outlined">close</span>
                    </button>
                  </span>
                }
                <!-- New tag input -->
                @if (!isTagsFull(filter.key, asTags(filter).maxTags)) {
                  <input
                    class="iu-filter-bar__tags-input"
                    type="text"
                    [id]="'filter-' + filter.key"
                    [placeholder]="filter.placeholder ?? 'Add tag…'"
                    (keydown.enter)="onTagEnter(filter.key, $event)"
                    (keydown.backspace)="onTagBackspace(filter.key, $event)"
                    autocomplete="off"
                  />
                }
              </div>
            }
          </div>
        }
      </div>

      <!-- Clear all -->
      @if (hasActiveFilters()) {
        <button
          class="iu-filter-bar__clear-all"
          type="button"
          (click)="clearAll()"
        >
          <span class="material-symbols-outlined" aria-hidden="true">filter_alt_off</span>
          Limpar filtros
        </button>
      }
    </div>
  `,
  styles: [`
    /* ── FilterBar ── */
    .iu-filter-bar {
      display: flex;
      align-items: flex-end;
      gap: 12px;
      padding: 12px 16px;
      background: var(--md-sys-color-surface, #fffbfe);
      border-bottom: 1px solid var(--md-sys-color-outline-variant, #cac4d0);
      flex-wrap: wrap;
    }

    .iu-filter-bar__controls {
      display: flex;
      flex-wrap: wrap;
      gap: 12px;
      flex: 1 1 auto;
    }

    .iu-filter-bar__field {
      display: flex;
      flex-direction: column;
      gap: 4px;
      min-width: 160px;
      flex: 1 1 160px;
      max-width: 280px;
    }

    .iu-filter-bar__label {
      font-family: var(--md-sys-typescale-label-small-font, Roboto, sans-serif);
