    expect(cfg.title).toBe('Legacy Title');
    expect(cfg.fabIcon).toBe('add');
    expect(cfg.fabLabel).toBe('Compose');
    // fabIcon present => showFab defaults to true
    expect(cfg.showFab).toBe(true);
  });

