  it('isItemActive matches the activeItemId input', () => {
    fixture.componentRef.setInput('activeItemId', 'dashboard');
    fixture.detectChanges();
    expect(component.isItemActive('dashboard')).toBe(true);
    expect(component.isItemActive('settings')).toBe(false);
  });

  // ── hasChildren ───────────────────────────────────────────────────────────
  it('hasChildren is true for items with children, false otherwise', () => {
    const items = makeMenuItems();
    expect(component.hasChildren(items[0])).toBe(false);
    expect(component.hasChildren(items[1])).toBe(true);
  });

  // ── findMenuItem ──────────────────────────────────────────────────────────
  it('findMenuItem returns the top-level item by id', () => {
    fixture.componentRef.setInput('menuItems', makeMenuItems());
    fixture.detectChanges();
    expect(component.findMenuItem('settings')?.label).toBe('Settings');
  });

  it('findMenuItem returns undefined for an unknown id', () => {
    fixture.componentRef.setInput('menuItems', makeMenuItems());
    fixture.detectChanges();
    expect(component.findMenuItem('nope')).toBeUndefined();
  });

  // ── getOverviewLabel ──────────────────────────────────────────────────────
  it('getOverviewLabel appends " overview" to the label', () => {
    expect(component.getOverviewLabel(makeMenuItems()[1])).toBe(
      'Settings overview',
    );
  });

  // ── toggleExpand / closePanel ─────────────────────────────────────────────
  it('toggleExpand flips expanded state and emits expandedChange', () => {
    const spy = jest.fn();
    component.expandedChange.subscribe(spy);
    expect(component.expanded()).toBe(false);

    component.toggleExpand();
    expect(component.expanded()).toBe(true);
    expect(spy).toHaveBeenLastCalledWith(true);

    component.toggleExpand();
    expect(component.expanded()).toBe(false);
    expect(spy).toHaveBeenLastCalledWith(false);
    expect(spy).toHaveBeenCalledTimes(2);
  });

  it('toggleExpand clears the active flyout', () => {
    component.activeFlyout.set('settings');
    component.toggleExpand();
    expect(component.activeFlyout()).toBeNull();
  });

  it('closePanel sets expanded to false and emits expandedChange(false)', () => {
    component.expanded.set(true);
    const spy = jest.fn();
    component.expandedChange.subscribe(spy);
    component.closePanel();
    expect(component.expanded()).toBe(false);
    expect(spy).toHaveBeenCalledWith(false);
  });

  // ── Accordion: toggleGroup / isGroupExpanded ──────────────────────────────
  it('isGroupExpanded is false until a group is toggled open', () => {
    expect(component.isGroupExpanded('settings')).toBe(false);
  });

  it('toggleGroup opens and then closes a group', () => {
    component.toggleGroup('settings');
    expect(component.isGroupExpanded('settings')).toBe(true);

    component.toggleGroup('settings');
    expect(component.isGroupExpanded('settings')).toBe(false);
  });

  it('toggleGroup tracks groups independently', () => {
    component.toggleGroup('settings');
    component.toggleGroup('security');
    expect(component.isGroupExpanded('settings')).toBe(true);
    expect(component.isGroupExpanded('security')).toBe(true);
    expect(component.isGroupExpanded('profile')).toBe(false);
  });

  // ── onMenuItemClick (new API navigation) ──────────────────────────────────
  it('onMenuItemClick emits navigate for an item with a route', () => {
    const items = makeMenuItems();
    fixture.componentRef.setInput('menuItems', items);
    fixture.detectChanges();

    const spy = jest.fn();
    component.navigate.subscribe(spy);
    component.onMenuItemClick(items[0], 1);

    expect(spy).toHaveBeenCalledTimes(1);
    const event = spy.mock.calls[0][0] as NavRailNavigationEvent;
    expect(event.route).toBe('/dashboard');
    expect(event.level).toBe(1);
    expect(event.item.id).toBe('dashboard');
  });

  it('onMenuItemClick clears the active flyout when navigating', () => {
    const items = makeMenuItems();
    component.activeFlyout.set('dashboard');
    component.onMenuItemClick(items[0], 1);
    expect(component.activeFlyout()).toBeNull();
  });

  it('onMenuItemClick on a parent without route does not emit navigate', () => {
    const items = makeMenuItems();
    const spy = jest.fn();
    component.navigate.subscribe(spy);
    component.onMenuItemClick(items[1], 1);
    expect(spy).not.toHaveBeenCalled();
  });

  it('onMenuItemClick on a parent without route toggles the group when expanded', () => {
    const items = makeMenuItems();
    component.expanded.set(true);
    component.onMenuItemClick(items[1], 1);
    expect(component.isGroupExpanded('settings')).toBe(true);
  });

  it('onMenuItemClick on a parent without route does not toggle when collapsed', () => {
    const items = makeMenuItems();
    component.expanded.set(false);
    component.onMenuItemClick(items[1], 1);
    expect(component.isGroupExpanded('settings')).toBe(false);
  });

  // ── onFlyoutItemClick ─────────────────────────────────────────────────────
  it('onFlyoutItemClick emits navigate for a leaf child', () => {
    const items = makeMenuItems();
    const child = items[1].children![0]; // profile (leaf with route)
    const spy = jest.fn();
    component.navigate.subscribe(spy);
    component.onFlyoutItemClick(child, 2);

    expect(spy).toHaveBeenCalledTimes(1);
    const event = spy.mock.calls[0][0] as NavRailNavigationEvent;
    expect(event.route).toBe('/settings/profile');
    expect(event.level).toBe(2);
  });

  it('onFlyoutItemClick toggles the group for a child with its own children', () => {
    const items = makeMenuItems();
    const child = items[1].children![1]; // security (has children)
    const spy = jest.fn();
    component.navigate.subscribe(spy);
    component.onFlyoutItemClick(child, 2);

    expect(spy).not.toHaveBeenCalled();
    expect(component.isGroupExpanded('security')).toBe(true);
  });

  // ── onLegacyItemClick ─────────────────────────────────────────────────────
  it('onLegacyItemClick emits itemClick with the index', () => {
    const spy = jest.fn();
    component.itemClick.subscribe(spy);
    component.onLegacyItemClick(2);
    expect(spy).toHaveBeenCalledWith(2);
  });

  // ── onToggleDarkMode ──────────────────────────────────────────────────────
  it('onToggleDarkMode flips isDarkMode and emits both darkModeChange and darkModeToggle', () => {
    const changeSpy = jest.fn();
    const toggleSpy = jest.fn();
    component.darkModeChange.subscribe(changeSpy);
    component.darkModeToggle.subscribe(toggleSpy);

    expect(component.isDarkMode()).toBe(false);
    component.onToggleDarkMode();

    expect(component.isDarkMode()).toBe(true);
    expect(changeSpy).toHaveBeenCalledWith(true);
    expect(toggleSpy).toHaveBeenCalledTimes(1);
  });

  it('onToggleDarkMode persists the theme to localStorage', () => {
    component.onToggleDarkMode();
    expect(localStorage.getItem('m3-theme')).toBe('dark');
    component.onToggleDarkMode();
    expect(localStorage.getItem('m3-theme')).toBe('light');
  });

  // ── FAB ───────────────────────────────────────────────────────────────────
  it('renders the FAB and emits fabClick when clicked', () => {
    fixture.componentRef.setInput('menuItems', makeMenuItems());
    fixture.componentRef.setInput('config', { showFab: true, fabIcon: 'add' });
    fixture.detectChanges();

    const spy = jest.fn();
    component.fabClick.subscribe(spy);
    const fab = fixture.nativeElement.querySelector(
      '.m3-rail__fab',
    ) as HTMLElement;
    expect(fab).toBeTruthy();
    fab.click();
    expect(spy).toHaveBeenCalledTimes(1);
  });

  // ── DOM smoke: new vs legacy API ──────────────────────────────────────────
  it('renders one rail item per menuItem in the collapsed new API', () => {
    fixture.componentRef.setInput('menuItems', makeMenuItems());
    fixture.detectChanges();
    const buttons = fixture.nativeElement.querySelectorAll('.m3-rail__item');
    expect(buttons.length).toBe(2);
  });

  it('renders the legacy items list when no menuItems are provided', () => {
    fixture.componentRef.setInput('items', [
      { icon: 'home', label: 'Home', active: true },
      { icon: 'search', label: 'Search' },
    ]);
    fixture.detectChanges();
    const buttons = fixture.nativeElement.querySelectorAll('.m3-rail__item');
    expect(buttons.length).toBe(2);
  });

  it('clicking a legacy item button emits itemClick with its index', () => {
    fixture.componentRef.setInput('items', [
      { icon: 'home', label: 'Home' },
      { icon: 'search', label: 'Search' },
    ]);
    fixture.detectChanges();
    const spy = jest.fn();
    component.itemClick.subscribe(spy);
    const buttons = fixture.nativeElement.querySelectorAll('.m3-rail__item');
    (buttons[1] as HTMLButtonElement).click();
    expect(spy).toHaveBeenCalledWith(1);
  });
});

import {
  ChangeDetectionStrategy,
  Component,
  ViewEncapsulation,
  HostListener,
  input,
  output,
  signal,
  computed,
  OnInit,
} from '@angular/core';
import { CommonModule } from '@angular/common';
import { NavMenuItem, NavRailConfig, NavRailNavigationEvent, NavRailFabEvent } from './m3-nav-rail.types';

// Re-export types for barrel export
export type { NavMenuItem, NavBadge, NavRailConfig, NavRailNavigationEvent, NavRailFabEvent } from './m3-nav-rail.types';

// Legacy compat — kept for existing consumers
export interface NavRailItem {
  icon: string;
  label: string;
  active?: boolean;
  badge?: number | string | boolean;
}

export interface NavRailSecondaryItem {
  icon: string;
  label: string;
  section?: string;
}

/**
 * IU Navigation Rail — M3 with flyout submenus, accordion & dark mode.
 *
 * Collapsed (88px): icon + label, hover flyout for items with children
 * Expanded (256px): side panel with inline accordion
 * Up to 3 levels of depth
 */
@Component({
  selector: 'iu-nav-rail',
  standalone: true,
  imports: [CommonModule],
  templateUrl: './nav-rail.component.html',
  styleUrl: './nav-rail.component.scss',
  encapsulation: ViewEncapsulation.None,
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class NavRailComponent implements OnInit {
  // ══════════════════════════════════════
  // INPUTS
  // ══════════════════════════════════════

  /** Navigation menu items (up to 3 levels) */
  menuItems = input<NavMenuItem[]>([]);

  /** ID of the currently active item */
  activeItemId = input<string>('');

  /** Rail configuration */
  config = input<NavRailConfig>({});

  /** Dark mode state */
  darkMode = input<boolean>(false);

  // Legacy inputs (backward compat)
  items = input<NavRailItem[]>([]);
  secondaryItems = input<NavRailSecondaryItem[]>([]);
  drawerTitle = input<string>('');
  fabIcon = input<string>('');
  fabLabel = input<string>('');

  // ══════════════════════════════════════
  // OUTPUTS
  // ══════════════════════════════════════

  /** Emitted on navigation item click */
  navigate = output<NavRailNavigationEvent>();

  /** Emitted when dark mode toggles */
  darkModeChange = output<boolean>();

  /** Emitted when FAB is clicked */
  fabClick = output<void>();

  /** Emitted when expanded state changes */
  expandedChange = output<boolean>();

  // Legacy outputs (backward compat)
  itemClick = output<number>();
  secondaryItemClick = output<NavRailSecondaryItem>();
  darkModeToggle = output<void>();

  // ══════════════════════════════════════
  // INTERNAL STATE
  // ══════════════════════════════════════

  expanded = signal(false);
  activeFlyout = signal<string | null>(null);
  expandedGroups = signal<Set<string>>(new Set());
  isDarkMode = signal(false);
  windowWidth = signal(typeof window !== 'undefined' ? window.innerWidth : 1024);

  isModalMode = computed(() => this.windowWidth() < (this.resolvedConfig().modalBreakpoint));

  /** Use new API if menuItems provided, else fall back to legacy items */
  useNewApi = computed(() => this.menuItems().length > 0);

  resolvedConfig = computed<Required<NavRailConfig>>(() => ({
    title: this.config().title ?? this.drawerTitle() ?? '',
    showFab: this.config().showFab ?? !!this.fabIcon(),
    fabIcon: this.config().fabIcon ?? this.fabIcon() ?? 'edit',
    fabLabel: this.config().fabLabel ?? this.fabLabel() ?? '',
    showDarkModeToggle: this.config().showDarkModeToggle ?? true,
    showSearch: this.config().showSearch ?? false,
    collapsedWidth: this.config().collapsedWidth ?? 88,
    expandedWidth: this.config().expandedWidth ?? 256,
    flyoutWidth: this.config().flyoutWidth ?? 224,
    modalBreakpoint: this.config().modalBreakpoint ?? 840,
  }));

  // Hover bridge timers
  private hoverTimer: ReturnType<typeof setTimeout> | null = null;
  private readonly HOVER_DELAY_OPEN = 100;
  private readonly HOVER_DELAY_CLOSE = 300;

  // ══════════════════════════════════════
  // LIFECYCLE
  // ══════════════════════════════════════

  ngOnInit(): void {
    this.isDarkMode.set(this.darkMode());
    const saved = localStorage.getItem('m3-theme');
    if (saved) {
      this.isDarkMode.set(saved === 'dark');
    }

    if (typeof window !== 'undefined') {
      window.addEventListener('resize', () => {
        this.windowWidth.set(window.innerWidth);
      });
    }
  }

  // ══════════════════════════════════════
  // EXPAND / COLLAPSE
  // ══════════════════════════════════════

  toggleExpand(): void {
    this.expanded.update((v) => !v);
    this.expandedChange.emit(this.expanded());
    this.activeFlyout.set(null);
  }

  closePanel(): void {
    this.expanded.set(false);
    this.expandedChange.emit(false);
  }

  // ══════════════════════════════════════
  // FLYOUT HOVER BRIDGE
  // ══════════════════════════════════════

  onRailItemHover(menuId: string): void {
    if (this.expanded()) return;
    this.clearHoverTimer();

    const item = this.findMenuItem(menuId);
    if (!item?.children?.length) {
      this.activeFlyout.set(null);
      return;
    }

    this.hoverTimer = setTimeout(() => {
      this.activeFlyout.set(menuId);
    }, this.HOVER_DELAY_OPEN);
  }

  onRailItemLeave(): void {
    if (this.expanded()) return;
    this.startCloseTimer();
  }

  onFlyoutEnter(): void {
    this.clearHoverTimer();
  }

  onFlyoutLeave(): void {
    this.startCloseTimer();
  }

  // ══════════════════════════════════════
  // ACCORDION
  // ══════════════════════════════════════

  toggleGroup(groupId: string): void {
    this.expandedGroups.update((groups) => {
      const next = new Set(groups);
      if (next.has(groupId)) {
        next.delete(groupId);
      } else {
        next.add(groupId);
      }
      return next;
    });
  }

  isGroupExpanded(groupId: string): boolean {
    return this.expandedGroups().has(groupId);
  }

  // ══════════════════════════════════════
  // NAVIGATION
  // ══════════════════════════════════════

  onMenuItemClick(item: NavMenuItem, level: 1 | 2 | 3): void {
    if (item.children?.length && !item.route) {
      // Has children without route → toggle accordion (in expanded mode)
      if (this.expanded()) {
        this.toggleGroup(item.id);
      }
      return;
    }

    if (item.route) {
      this.navigate.emit({ item, route: item.route, level });
      this.activeFlyout.set(null);
      if (this.isModalMode() && this.expanded()) {
        this.expanded.set(false);
        this.expandedChange.emit(false);
      }
    }
  }

  onFlyoutItemClick(item: NavMenuItem, level: 2 | 3): void {
    if (item.children?.length) {
      this.toggleGroup(item.id);
      return;
    }
    if (item.route) {
      this.navigate.emit({ item, route: item.route, level });
      this.activeFlyout.set(null);
    }
  }

  // Legacy handler
  onLegacyItemClick(index: number): void {
    this.itemClick.emit(index);
    if (this.isModalMode() && this.expanded()) {
      this.expanded.set(false);
      this.expandedChange.emit(false);
    }
  }

  // ══════════════════════════════════════
  // DARK MODE
  // ══════════════════════════════════════

  onToggleDarkMode(): void {
    this.isDarkMode.update((v) => !v);
    localStorage.setItem('m3-theme', this.isDarkMode() ? 'dark' : 'light');
    this.darkModeChange.emit(this.isDarkMode());
    this.darkModeToggle.emit(); // legacy compat
  }

  // ══════════════════════════════════════
  // HELPERS
  // ══════════════════════════════════════

  hasChildren(item: NavMenuItem): boolean {
    return !!item.children?.length;
  }

  getOverviewLabel(item: NavMenuItem): string {
    return `${item.label} overview`;
  }

  isItemActive(itemId: string): boolean {
    return this.activeItemId() === itemId;
  }

  findMenuItem(id: string): NavMenuItem | undefined {
    return this.menuItems().find((i) => i.id === id);
  }

  private clearHoverTimer(): void {
    if (this.hoverTimer) {
      clearTimeout(this.hoverTimer);
      this.hoverTimer = null;
    }
  }

  private startCloseTimer(): void {
    this.clearHoverTimer();
    this.hoverTimer = setTimeout(() => {
      this.activeFlyout.set(null);
    }, this.HOVER_DELAY_CLOSE);
  }

  @HostListener('document:keydown.escape')
  onEscape(): void {
    if (this.activeFlyout()) this.activeFlyout.set(null);
    if (this.expanded()) {
      this.expanded.set(false);
      this.expandedChange.emit(false);
    }
  }
}

