  });

  it('clicking the trigger button calls svc.toggle()', () => {
    const trigger = fixture.nativeElement.querySelector('.nc-trigger') as HTMLButtonElement;
    trigger.click();
    expect(stub.toggle).toHaveBeenCalledTimes(1);
