    expect(
      fixture.nativeElement.querySelector('img.iu-payment-card__property-img'),
    ).toBeFalsy();
    expect(
      fixture.nativeElement.querySelector(
        '.iu-payment-card__property-img--placeholder',
      ),
    ).toBeTruthy();
