              [attr.aria-selected]="bookingType() === 'inquiry'"
              (click)="setBookingType('inquiry')"
            >
              <span class="material-symbols-outlined">mail</span>
              Enviar Mensagem
            </button>
          </div>

          <!-- Form -->
          <form class="iu-pb__form" (submit)="$event.preventDefault(); onSubmit()">

            <!-- Name + Email row -->
            <div class="iu-pb__row">
              <div class="iu-pb__field">
                <label class="iu-pb__label" for="pb-name">Nome *</label>
                <input
                  id="pb-name"
                  class="iu-pb__input"
                  [class.iu-pb__input--error]="form.fields.name.showError()"
                  type="text"
                  placeholder="O seu nome completo"
                  [value]="form.fields.name.value()"
                  (input)="form.fields.name.setValue($any($event.target).value)"
                  (blur)="form.fields.name.touch()"
                  autocomplete="name"
                />
                @if (form.fields.name.showError()) {
                  <span class="iu-pb__error">{{ form.fields.name.firstError() }}</span>
                }
              </div>

              <div class="iu-pb__field">
                <label class="iu-pb__label" for="pb-email">Email *</label>
                <input
                  id="pb-email"
                  class="iu-pb__input"
                  [class.iu-pb__input--error]="form.fields.email.showError()"
                  type="email"
                  placeholder="nome@exemplo.com"
                  [value]="form.fields.email.value()"
                  (input)="form.fields.email.setValue($any($event.target).value)"
                  (blur)="form.fields.email.touch()"
                  autocomplete="email"
                />
                @if (form.fields.email.showError()) {
                  <span class="iu-pb__error">{{ form.fields.email.firstError() }}</span>
                }
              </div>
            </div>

            <!-- Phone -->
            <div class="iu-pb__field">
              <label class="iu-pb__label" for="pb-phone">Telefone</label>
              <input
                id="pb-phone"
                class="iu-pb__input"
                type="tel"
                placeholder="+351 9XX XXX XXX"
                [value]="form.fields.phone.value()"
                (input)="form.fields.phone.setValue($any($event.target).value)"
                autocomplete="tel"
              />
            </div>

            <!-- Visit-specific fields -->
            @if (bookingType() === 'visit') {
              <div class="iu-pb__row">
                <div class="iu-pb__field">
                  <label class="iu-pb__label" for="pb-visit-date">Data da Visita</label>
                  <input
                    id="pb-visit-date"
                    class="iu-pb__input"
                    type="date"
                    [min]="todayISO"
                    [value]="form.fields.visitDate.value()"
                    (input)="form.fields.visitDate.setValue($any($event.target).value)"
                  />
                </div>

                <div class="iu-pb__field">
                  <label class="iu-pb__label" for="pb-time-slot">Período</label>
                  <select
                    id="pb-time-slot"
                    class="iu-pb__select"
                    [value]="form.fields.visitTimeSlot.value()"
                    (change)="form.fields.visitTimeSlot.setValue($any($event.target).value)"
                  >
                    <option value="">-- Escolher período --</option>
                    @for (slot of timeSlots; track slot.value) {
                      <option [value]="slot.value">{{ slot.label }}</option>
                    }
                  </select>
                </div>
              </div>
            }

            <!-- Move-in date (inquiry) -->
            @if (bookingType() === 'inquiry') {
              <div class="iu-pb__field">
                <label class="iu-pb__label" for="pb-movein">Data de entrada pretendida</label>
                <input
                  id="pb-movein"
                  class="iu-pb__input"
                  type="date"
                  [min]="todayISO"
                  [value]="form.fields.moveInDate.value()"
                  (input)="form.fields.moveInDate.setValue($any($event.target).value)"
                />
              </div>
            }

            <!-- Message -->
            <div class="iu-pb__field">
              <label class="iu-pb__label" for="pb-message">Mensagem</label>
              <textarea
                id="pb-message"
                class="iu-pb__textarea"
                rows="4"
                [placeholder]="messagePlaceholder()"
                [value]="form.fields.message.value()"
                (input)="form.fields.message.setValue($any($event.target).value)"
