      height: 120px;
      object-fit: cover;
      border-radius: 8px;
      margin-bottom: 8px;
      background: var(--md-sys-color-surface-container, #F3EDF7);
      display: block;
    }

    .iu-comparison__img-placeholder {
      width: 100%;
      height: 120px;
      border-radius: 8px;
      background: var(--md-sys-color-surface-container, #F3EDF7);
