export class RadioComponent {
  private readonly el = inject(ElementRef<HTMLElement>);

  // --- Inputs ---
  checked = input<boolean>(false);
  disabled = input<boolean>(false);
  name = input<string>('');
  value = input<string>('');
  label = input<string>('');
  ariaLabel = input<string>('');

  // --- Outputs ---
