  onChange(event: Event): void {
    this.change.emit(this.value());
  }
}

import { ComponentFixture, TestBed } from '@angular/core/testing';
import { RentArrearsComponent } from './rent-arrears.component';
import { RentArrearsService, type ArrearsRecord } from '../../services/rent-arrears.service';

describe('RentArrearsComponent', () => {
  let fixture: ComponentFixture<RentArrearsComponent>;
  let component: RentArrearsComponent;
  let service: RentArrearsService;

  const cards = (): HTMLElement[] =>
    Array.from(fixture.nativeElement.querySelectorAll('.ra-card'));
  const filterBtns = (): HTMLButtonElement[] =>
    Array.from(fixture.nativeElement.querySelectorAll('.ra-filter-btn'));
  const kpiNums = (): string[] =>
    Array.from(fixture.nativeElement.querySelectorAll('.ra-kpi-num')).map(
      (e) => (e as HTMLElement).textContent!.trim(),
    );
  const empty = (): HTMLElement | null =>
    fixture.nativeElement.querySelector('.ra-empty');
  const record = (id: string): ArrearsRecord =>
    service.records().find((r) => r.id === id)!;

  beforeEach(async () => {
    await TestBed.configureTestingModule({
      imports: [RentArrearsComponent],
    }).compileComponents();

    fixture = TestBed.createComponent(RentArrearsComponent);
    component = fixture.componentInstance;
    service = TestBed.inject(RentArrearsService);
    fixture.detectChanges();
  });

  it('should create', () => {
    expect(component).toBeTruthy();
  });

  // ── Header + KPIs ──────────────────────────────────────────────────────────

  it('should render the title', () => {
    const title = fixture.nativeElement.querySelector('.ra-title');
    expect(title.textContent).toContain('Rent Arrears');
  });

  it('should compute portfolio KPIs from the mock data', () => {
    const k = service.kpis();
    // 1800 + 1600 + 475 + 5400 = 9275 outstanding across 4 non-resolved tenants
    expect(k.totalOutstanding).toBe(9275);
    expect(k.totalTenants).toBe(4);
    expect(k.avgDaysOverdue).toBe(61);
    expect(k.critical).toBe(2);
  });

  it('should render KPI values in the strip', () => {
    const nums = kpiNums();
    expect(nums).toContain('4');
    expect(nums).toContain('61d');
  });

  // ── List rendering ─────────────────────────────────────────────────────────

  it('should render one card per record by default', () => {
    expect(cards().length).toBe(service.records().length);
    expect(empty()).toBeNull();
  });

  it('should apply a severity class to each card', () => {
    expect(fixture.nativeElement.querySelector('.ra-card-critical')).toBeTruthy();
    expect(fixture.nativeElement.querySelector('.ra-card-high')).toBeTruthy();
  });

  // ── Severity classification ────────────────────────────────────────────────

  it('should classify severity by status and days overdue', () => {
    expect(service.severity(record('ar004'))).toBe('critical'); // legal
    expect(service.severity(record('ar002'))).toBe('high');     // 62d
    expect(service.severity(record('ar001'))).toBe('medium');   // 45d
    expect(service.severity(record('ar003'))).toBe('low');      // 18d
  });

  // ── Filtering ──────────────────────────────────────────────────────────────

  it('should render a button per filter option', () => {
    expect(filterBtns().length).toBe(component.filters.length);
  });

  it('should filter records when a filter button is clicked', () => {
    const legalBtn = filterBtns().find((b) => b.textContent!.trim() === 'Legal')!;
    legalBtn.click();
    fixture.detectChanges();
    expect(service.filter()).toBe('legal');
    expect(cards().length).toBe(1);
  });

  it('should show the empty state when a filter matches nothing', () => {
    service.setFilter('resolved');
    fixture.detectChanges();
    expect(cards().length).toBe(0);
    expect(empty()).toBeTruthy();
  });

  it('should mark the active filter button', () => {
    service.setFilter('overdue');
    fixture.detectChanges();
    const active = fixture.nativeElement.querySelector('.ra-filter-active');
    expect(active.textContent.trim()).toBe('Overdue');
  });

  // ── Actions wired to the service ───────────────────────────────────────────

  it('should send a reminder and bump the reminder count', () => {
    const before = record('ar003').reminderCount;
    service.sendReminder('ar003');
    fixture.detectChanges();
    const after = record('ar003');
    expect(after.status).toBe('reminder_sent');
    expect(after.reminderCount).toBe(before + 1);
  });

  it('should escalate a record to legal', () => {
    service.escalateToLegal('ar001');
    expect(record('ar001').status).toBe('legal');
  });

  it('should mark a record resolved and zero its outstanding amount', () => {
    service.markResolved('ar001');
    const r = record('ar001');
    expect(r.status).toBe('resolved');
    expect(r.amountOutstanding).toBe(0);
    expect(r.amountPaid).toBe(r.amountDue);
  });

  // ── Payment plan form ──────────────────────────────────────────────────────

  it('should open the payment plan form with a suggested instalment', () => {
    const r = record('ar003'); // outstanding 475
    component.openPlanForm(r);
    expect(component.planFormId()).toBe('ar003');
    expect(component.planAmount()).toBe(Math.ceil(475 / 4));
  });

  it('should activate a payment plan on submit and close the form', () => {
    const r = record('ar003');
    component.openPlanForm(r);
    component.submitPlan(r);
    expect(component.planFormId()).toBeNull();
    const updated = record('ar003');
    expect(updated.paymentPlanActive).toBe(true);
    expect(updated.status).toBe('payment_plan');
  });

  it('should not activate a plan when the amount is zero', () => {
    const r = record('ar003');
    component.planAmount.set(0);
    component.submitPlan(r);
    expect(record('ar003').paymentPlanActive).toBe(false);
  });

  // ── Pure helpers ───────────────────────────────────────────────────────────

  it('should build two-letter uppercase initials from a name', () => {
    expect(component.initials('Carlos Mendes')).toBe('CM');
    expect(component.initials('rita oliveira')).toBe('RO');
  });

  it('should map status codes to readable labels', () => {
    expect(component.statusLabel('reminder_sent')).toBe('Reminder Sent');
    expect(component.statusLabel('legal')).toBe('Legal');
  });

  it('should fall back to the raw status for an unknown code', () => {
    expect(component.statusLabel('unknown')).toBe('unknown');
  });
});

import {
  Component, ChangeDetectionStrategy, Input, inject, signal,
} from '@angular/core';
import { CommonModule } from '@angular/common';
import { RentArrearsService } from '../../services/rent-arrears.service';
import type { ArrearsRecord, ArrearsStatus } from '../../services/rent-arrears.service';

const STATUS_LABELS: Record<ArrearsStatus, string> = {
  overdue: 'Overdue',
  partial: 'Partial',
  reminder_sent: 'Reminder Sent',
  payment_plan: 'Payment Plan',
  legal: 'Legal',
  resolved: 'Resolved',
};

/**
 * RentArrearsComponent — landlord-facing rent arrears management dashboard.
 *
 * Shows portfolio-level KPIs (total outstanding, tenants in arrears, avg days overdue,
 * critical cases), a severity-colour-coded list with send-reminder, payment-plan,
 * legal escalation, and resolve actions per record.
 *
 * @example
 * <iu-rent-arrears />
 */
@Component({
  selector: 'iu-rent-arrears',
  standalone: true,
  changeDetection: ChangeDetectionStrategy.OnPush,
  imports: [CommonModule],
  template: `
    <div class="ra-root">

      <!-- Header -->
      <div class="ra-header">
        <span class="material-symbols-outlined ra-header-icon">account_balance_wallet</span>
        <div>
          <h2 class="ra-title">Rent Arrears</h2>
          <p class="ra-subtitle">Outstanding payments across your portfolio</p>
        </div>
      </div>

      <!-- KPI Strip -->
      <div class="ra-kpis">
        <div class="ra-kpi ra-kpi-danger">
          <span class="material-symbols-outlined ra-kpi-icon">euro</span>
          <div>
            <span class="ra-kpi-num">€{{ svc.kpis().totalOutstanding | number:'1.0-0' }}</span>
            <span class="ra-kpi-label">Total Outstanding</span>
          </div>
        </div>
        <div class="ra-kpi ra-kpi-warn">
          <span class="material-symbols-outlined ra-kpi-icon">groups</span>
          <div>
            <span class="ra-kpi-num">{{ svc.kpis().totalTenants }}</span>
            <span class="ra-kpi-label">Tenants in Arrears</span>
          </div>
        </div>
        <div class="ra-kpi ra-kpi-neutral">
          <span class="material-symbols-outlined ra-kpi-icon">schedule</span>
          <div>
            <span class="ra-kpi-num">{{ svc.kpis().avgDaysOverdue }}d</span>
            <span class="ra-kpi-label">Avg Days Overdue</span>
          </div>
        </div>
        <div class="ra-kpi" [class.ra-kpi-critical]="svc.kpis().critical > 0" [class.ra-kpi-ok]="svc.kpis().critical === 0">
          <span class="material-symbols-outlined ra-kpi-icon">warning</span>
          <div>
            <span class="ra-kpi-num">{{ svc.kpis().critical }}</span>
            <span class="ra-kpi-label">Critical Cases</span>
          </div>
        </div>
      </div>

      <!-- Filter Bar -->
      <div class="ra-filters">
        @for (f of filters; track f.value) {
          <button class="ra-filter-btn"
                  [class.ra-filter-active]="svc.filter() === f.value"
                  (click)="svc.setFilter(f.value)">
            {{ f.label }}
          </button>
        }
      </div>

      <!-- Records -->
      <div class="ra-list">
        @if (svc.filtered().length === 0) {
          <div class="ra-empty">
            <span class="material-symbols-outlined ra-empty-icon">check_circle</span>
            <p>No arrears records</p>
          </div>
        }

        @for (r of svc.filtered(); track r.id) {
        <div class="ra-card" [class]="'ra-card-' + svc.severity(r)">
          <div class="ra-card-stripe" [class]="'ra-stripe-' + svc.severity(r)"></div>

          <div class="ra-card-body">
            <!-- Top row -->
            <div class="ra-top-row">
              <div class="ra-tenant-info">
                <div class="ra-avatar">{{ initials(r.tenantName) }}</div>
                <div>
                  <div class="ra-tenant-name">{{ r.tenantName }}</div>
                  <div class="ra-tenant-email">{{ r.tenantEmail }}</div>
                </div>
              </div>
              <div class="ra-amount-block">
                <span class="ra-amount-outstanding">€{{ r.amountOutstanding | number:'1.0-0' }}</span>
                <span class="ra-amount-label">outstanding</span>
              </div>
            </div>

            <!-- Property & Overdue info -->
            <div class="ra-meta-row">
              <span class="ra-meta">
                <span class="material-symbols-outlined">location_on</span>{{ r.propertyAddress }}
              </span>
              <span class="ra-meta">
                <span class="material-symbols-outlined">calendar_today</span>Due since {{ r.dueSince }}
              </span>
              <span class="ra-overdue-badge" [class]="'ra-overdue-' + svc.severity(r)">
                {{ r.daysOverdue }}d overdue
              </span>
            </div>

            <!-- Progress bar (paid vs total) -->
            @if (r.amountPaid > 0) {
              <div class="ra-progress-wrap">
                <div class="ra-progress-bar">
                  <div class="ra-progress-fill" [style.width.%]="(r.amountPaid / r.amountDue) * 100"></div>
                </div>
                <span class="ra-progress-label">€{{ r.amountPaid | number:'1.0-0' }} paid of €{{ r.amountDue | number:'1.0-0' }}</span>
              </div>
            }

            <!-- Payment plan badge -->
            @if (r.paymentPlanActive) {
              <div class="ra-plan-badge">
                <span class="material-symbols-outlined">payments</span>
                Payment plan active — €{{ r.paymentPlanMonthly }}/month
              </div>
            }

            <!-- Notes -->
            @if (r.notes) {
              <p class="ra-notes">{{ r.notes }}</p>
            }

            <!-- Status + Actions row -->
            <div class="ra-actions-row">
              <span class="ra-status-chip ra-status-{{ r.status }}">
                {{ statusLabel(r.status) }}
              </span>
              @if (r.status !== 'resolved') {
              <div class="ra-action-btns">
                @if (r.status !== 'reminder_sent' && r.status !== 'legal') {
                  <button class="ra-btn ra-btn-remind"
                          (click)="svc.sendReminder(r.id)">
                    <span class="material-symbols-outlined">notifications</span>
                    Remind
                  </button>
                }
                @if (r.status === 'reminder_sent') {
                  <button class="ra-btn ra-btn-remind ra-btn-disabled" disabled>
                    <span class="material-symbols-outlined">check</span>
                    Reminder Sent ({{ r.reminderCount }}×)
                  </button>
                }
                @if (!r.paymentPlanActive && r.status !== 'legal') {
                  <button class="ra-btn ra-btn-plan"
                          (click)="openPlanForm(r)">
                    <span class="material-symbols-outlined">payments</span>
                    Payment Plan
                  </button>
                }
                @if (r.status !== 'legal' && r.daysOverdue > 45) {
                  <button class="ra-btn ra-btn-legal"
                          (click)="svc.escalateToLegal(r.id)">
                    <span class="material-symbols-outlined">gavel</span>
                    Escalate
                  </button>
                }
                <button class="ra-btn ra-btn-resolve"
                        (click)="svc.markResolved(r.id)">
                  <span class="material-symbols-outlined">check_circle</span>
                  Resolve
                </button>
              </div>
              }
            </div>

            <!-- Inline payment plan form -->
            @if (planFormId() === r.id) {
            <div class="ra-plan-form">
              <p class="ra-plan-form-title">Set Up Payment Plan</p>
              <label class="ra-plan-label">
                Monthly Instalment (€)
                <input type="number" [value]="planAmount()" min="50"
                       (input)="planAmount.set(+$any($event.target).value)"
                       class="ra-plan-input" />
              </label>
              @if (planAmount() > 0) {
                <p class="ra-plan-months">
                  Estimated {{ Math.ceil(r.amountOutstanding / planAmount()) }} months to clear
                </p>
              }
              <div class="ra-plan-actions">
                <button class="ra-btn ra-btn-plan" (click)="submitPlan(r)">
                  <span class="material-symbols-outlined">check</span>
                  Activate Plan
                </button>
                <button class="ra-btn ra-btn-ghost" (click)="planFormId.set(null)">Cancel</button>
              </div>
            </div>
            }
          </div>
        </div>
        }
      </div>
    </div>
  `,
  styles: [`
    :host { display: block; }

    .ra-root {
      font-family: var(--md-sys-typescale-body-large-font, sans-serif);
      color: var(--md-sys-color-on-surface, #1c1b1f);
      background: var(--md-sys-color-surface, #fffbfe);
      border-radius: 16px;
      padding: 24px;
    }

    .ra-header { display: flex; align-items: center; gap: 16px; margin-bottom: 24px; }
    .ra-header-icon { font-size: 36px; color: var(--md-sys-color-primary, #6750a4); }
