export class RentArrearsComponent {
  protected readonly svc = inject(RentArrearsService);
  protected readonly Math = Math;

  readonly planFormId = signal<string | null>(null);
  readonly planAmount = signal<number>(0);

  readonly filters = [
    { value: 'all' as const, label: 'All' },
    { value: 'overdue' as const, label: 'Overdue' },
    { value: 'partial' as const, label: 'Partial' },
    { value: 'reminder_sent' as const, label: 'Reminder Sent' },
    { value: 'payment_plan' as const, label: 'Payment Plan' },
    { value: 'legal' as const, label: 'Legal' },
    { value: 'resolved' as const, label: 'Resolved' },
  ];

  /** @internal */
  statusLabel(s: string): string {
    return (STATUS_LABELS as Record<string, string>)[s] ?? s;
  }

  /** @internal Generate initials from name. */
  initials(name: string): string {
    return name.split(' ').map(w => w[0]).join('').slice(0, 2).toUpperCase();
  }

  /** @internal Open payment plan form. */
  openPlanForm(r: ArrearsRecord): void {
    this.planFormId.set(r.id);
    this.planAmount.set(Math.ceil(r.amountOutstanding / 4));
  }

  /** @internal Submit payment plan. */
  submitPlan(r: ArrearsRecord): void {
    if (this.planAmount() > 0) {
      this.svc.setPaymentPlan(r.id, this.planAmount());
    }
    this.planFormId.set(null);
  }
}

import { ComponentFixture, TestBed } from '@angular/core/testing';
import { RentPaymentPortalComponent } from './rent-payment-portal.component';
import { RentPaymentPortalService } from '../../services/rent-payment-portal.service';

describe('RentPaymentPortalComponent', () => {
  let fixture: ComponentFixture<RentPaymentPortalComponent>;
  let component: RentPaymentPortalComponent;
  let svc: RentPaymentPortalService;

  beforeEach(async () => {
    await TestBed.configureTestingModule({
      imports: [RentPaymentPortalComponent],
    }).compileComponents();

    fixture = TestBed.createComponent(RentPaymentPortalComponent);
    component = fixture.componentInstance;
    svc = TestBed.inject(RentPaymentPortalService);
  });

  it('should create', () => {
    fixture.detectChanges();
    expect(component).toBeTruthy();
  });

  it('defaults to tenant mode', () => {
    expect(component.mode).toBe('tenant');
  });

  // ── overdue detection (seed has exactly one overdue: rp-005) ──────────────────────

  it('detects overdue payments from the seed data', () => {
    expect((component as any).hasOverdue()).toBe(true);
    expect((component as any).overdueCount()).toBe(1);
  });

  it('reports no overdue once the overdue entry is settled', () => {
    svc.makePayment('rp-005', 850); // fully pay the only overdue record
    expect((component as any).hasOverdue()).toBe(false);
    expect((component as any).overdueCount()).toBe(0);
  });

  // ── rowClass ─────────────────────────────────────────────────────────────────────

  it('builds a status-specific row class', () => {
    expect((component as any).rowClass('paid')).toBe('rpp-table-row rpp-row--paid');
    expect((component as any).rowClass('overdue')).toBe('rpp-table-row rpp-row--overdue');
  });

  // ── onPay / onReceipt ────────────────────────────────────────────────────────────

  it('delegates a payment to the service with the full amount', () => {
    const spy = jest.spyOn(svc, 'makePayment');
    const payment = svc.payments().find((p) => p.id === 'rp-004')!;
    (component as any).onPay(payment);
    expect(spy).toHaveBeenCalledWith('rp-004', payment.amount);
  });

  it('opens a receipt without throwing', () => {
    const log = jest.spyOn(console, 'log').mockImplementation(() => undefined);
    const payment = svc.payments().find((p) => p.id === 'rp-001')!;
    expect(() => (component as any).onReceipt(payment)).not.toThrow();
    expect(log).toHaveBeenCalled();
    log.mockRestore();
  });

  // ── ngOnInit loading (async via setTimeout → fake timers) ─────────────────────────

  describe('ngOnInit loading', () => {
    beforeEach(() => jest.useFakeTimers());
    afterEach(() => jest.useRealTimers());

    it('loads tenant payments when mode=tenant and tenantId is set', () => {
      const spy = jest.spyOn(svc, 'loadForTenant');
      component.mode = 'tenant';
      component.tenantId = 'tenant-002';
      component.ngOnInit();
      jest.advanceTimersByTime(300);
      expect(spy).toHaveBeenCalledWith('tenant-002');
      expect(svc.payments().every((p) => p.tenantId === 'tenant-002')).toBe(true);
    });

    it('loads landlord payments when mode=landlord and landlordId is set', () => {
      const spy = jest.spyOn(svc, 'loadForLandlord');
      component.mode = 'landlord';
      component.landlordId = 'landlord-001';
      component.ngOnInit();
      jest.advanceTimersByTime(300);
      expect(spy).toHaveBeenCalledWith('landlord-001');
      expect(svc.payments().every((p) => p.landlordId === 'landlord-001')).toBe(true);
    });

    it('does not load anything when no id is provided', () => {
      const tenant = jest.spyOn(svc, 'loadForTenant');
      const landlord = jest.spyOn(svc, 'loadForLandlord');
      component.mode = 'tenant';
      component.ngOnInit();
      expect(tenant).not.toHaveBeenCalled();
      expect(landlord).not.toHaveBeenCalled();
    });
  });
});

import { ComponentFixture, TestBed } from '@angular/core/testing';
import { RentReceiptGeneratorComponent } from './rent-receipt-generator.component';
import { RentReceiptService } from '../../services/rent-receipt.service';

// A valid Portuguese NIF (passes the mod-11 checksum used by isValidNIF).
const VALID_NIF_A = '123456789';
const VALID_NIF_B = '500000000';

describe('RentReceiptGeneratorComponent', () => {
  let fixture: ComponentFixture<RentReceiptGeneratorComponent>;
  let component: RentReceiptGeneratorComponent;
  let service: RentReceiptService;

  const set = (sig: string, value: string | number): void => {
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    (component as any)[sig].set(value);
  };
  const submitBtn = (): HTMLButtonElement =>
    fixture.nativeElement.querySelector('.rrg-submit');
  const docTotal = (): HTMLElement | null =>
    fixture.nativeElement.querySelector('.rrg-doc-total .rrg-doc-num');

  beforeEach(async () => {
    await TestBed.configureTestingModule({
      imports: [RentReceiptGeneratorComponent],
    }).compileComponents();

    fixture = TestBed.createComponent(RentReceiptGeneratorComponent);
    component = fixture.componentInstance;
    service = TestBed.inject(RentReceiptService);
    service.clear();
    fixture.detectChanges();
  });

  it('should create', () => {
    expect(component).toBeTruthy();
  });

  it('should render the title', () => {
    expect(fixture.nativeElement.querySelector('.rrg-title').textContent).toContain('Recibo de Renda');
  });

  it('should show the empty preview before any receipt is issued', () => {
    expect(fixture.nativeElement.querySelector('.rrg-preview-empty')).toBeTruthy();
  });

  // ── canSubmit gating ───────────────────────────────────────────────────────

  it('should disable submit until the form is complete and valid', () => {
    expect(component['canSubmit']()).toBe(false);
    expect(submitBtn().disabled).toBe(true);

    set('senhNome', 'Senhorio Lda');
    set('inqNome', 'Inquilino Silva');
    set('senhNif', VALID_NIF_A);
    set('inqNif', VALID_NIF_B);
    set('valor', 800);
    expect(component['canSubmit']()).toBe(true);
  });

  it('should reject invalid NIFs', () => {
    set('senhNome', 'A');
    set('inqNome', 'B');
    set('senhNif', '111111111'); // fails checksum
    set('inqNif', VALID_NIF_B);
    set('valor', 800);
    expect(component['senhNifValid']()).toBe(false);
    expect(component['canSubmit']()).toBe(false);
  });

  it('should reject non-positive rent', () => {
    set('senhNome', 'A');
    set('inqNome', 'B');
    set('senhNif', VALID_NIF_A);
    set('inqNif', VALID_NIF_B);
    set('valor', 0);
    expect(component['canSubmit']()).toBe(false);
  });

  // ── Generation + financial computeds ────────────────────────────────────────

  it('should generate a receipt with correct withholding and net amounts', () => {
    set('senhNome', 'Senhorio Lda');
    set('inqNome', 'Inquilino Silva');
    set('senhNif', VALID_NIF_A);
    set('inqNif', VALID_NIF_B);
    set('morada', 'Rua A, Lisboa');
    set('valor', 1000);
    set('retencao', 25);

    component['onSubmit'](new Event('submit'));

    expect(service.count()).toBe(1);
    const r = service.receipts()[0];
    expect(r.valorMensal).toBe(1000);
    expect(r.valorRetido).toBe(250);
    expect(r.valorLiquido).toBe(750);
    expect(r.retencaoIRSPct).toBe(25);
  });

  it('should not generate when the form is invalid', () => {
    component['onSubmit'](new Event('submit'));
    expect(service.count()).toBe(0);
  });

  it('should render the issued receipt in the preview', () => {
    set('senhNome', 'Senhorio Lda');
    set('inqNome', 'Inquilino Silva');
    set('senhNif', VALID_NIF_A);
    set('inqNif', VALID_NIF_B);
    set('valor', 500);
    component['onSubmit'](new Event('submit'));
    fixture.detectChanges();

    expect(fixture.nativeElement.querySelector('.rrg-doc')).toBeTruthy();
    expect(docTotal()!.textContent).toContain('375.00'); // 500 − 25% = 375
  });

  it('should clear history via clearAll', () => {
    set('senhNome', 'A');
    set('inqNome', 'B');
    set('senhNif', VALID_NIF_A);
    set('inqNif', VALID_NIF_B);
    set('valor', 500);
    component['onSubmit'](new Event('submit'));
    expect(service.count()).toBe(1);

    component['clearAll']();
    expect(service.count()).toBe(0);
  });

  // ── formatMes helper ────────────────────────────────────────────────────────

  it('should format the reference month in Portuguese', () => {
    expect(component['formatMes']('2026-06')).toBe('Junho 2026');
    expect(component['formatMes']('2026-01')).toBe('Janeiro 2026');
  });

  it('should pass through an out-of-range month string', () => {
    expect(component['formatMes']('2026-13')).toBe('2026-13');
    expect(component['formatMes']('2026-00')).toBe('2026-00');
  });

  // ── input coercion helpers ──────────────────────────────────────────────────

  it('should coerce numeric input, flooring negatives to 0', () => {
    const ev = { target: { value: '-5' } } as unknown as Event;
    expect(component['getNum'](ev)).toBe(0);
    const ok = { target: { value: '42' } } as unknown as Event;
    expect(component['getNum'](ok)).toBe(42);
  });
});

