            <button type="button" class="as-filter-btn"
              [class.active]="activeFilter() === f.value"
              (click)="activeFilter.set(f.value)">
              {{ f.label }}
              @if (countByStatus(f.value) > 0) {
                <span class="as-badge">{{ countByStatus(f.value) }}</span>
              }
            </button>
