  /** Whether this is the active/current item */
  active?: boolean;
}

export type TimelineOrientation = 'vertical' | 'horizontal';
export type TimelineAlign = 'start' | 'alternate' | 'end';

/**
 * Timeline — Displays a chronological list of events with connectors.
 *
 * Supports vertical/horizontal orientation and left/right/alternate alignment.
 * Uses M3 design tokens. No external dependencies.
 *
 * @example
 * ```html
 * <iu-timeline
 *   [items]="events"
 *   orientation="vertical"
 *   align="alternate"
 * />
 * ```
 */
@Component({
  selector: 'iu-timeline',
  standalone: true,
  imports: [CommonModule],
  template: `
    <div
      class="iu-timeline"
      [class.iu-timeline--vertical]="orientation() === 'vertical'"
      [class.iu-timeline--horizontal]="orientation() === 'horizontal'"
      [class]="'iu-timeline--' + orientation() + ' iu-timeline--align-' + align()"
      role="list"
    >
      @for (item of items(); track item.title; let i = $index; let last = $last) {
        <div
          class="iu-timeline__item"
          [class.iu-timeline__item--active]="item.active"
          [class.iu-timeline__item--last]="last"
          role="listitem"
        >
          <!-- Left/top content (alternate mode) -->
          @if (align() === 'alternate' && i % 2 !== 0 && orientation() === 'vertical') {
            <div class="iu-timeline__content iu-timeline__content--opposite">
              <ng-container [ngTemplateOutlet]="contentTpl" [ngTemplateOutletContext]="{item}" />
            </div>
          } @else {
            <div class="iu-timeline__content--spacer"></div>
          }

          <!-- Spine: connector + dot -->
          <div class="iu-timeline__spine">
            @if (!isFirst(i)) {
              <div class="iu-timeline__connector iu-timeline__connector--before"
                   [class.iu-timeline__connector--active]="item.active"></div>
            }
            <div
              class="iu-timeline__dot"
              [class.iu-timeline__dot--active]="item.active"
              [style.background-color]="resolveColor(item)"
            >
              @if (item.icon) {
                <span class="material-symbols-outlined">{{ item.icon }}</span>
              }
            </div>
            @if (!last) {
              <div class="iu-timeline__connector iu-timeline__connector--after"></div>
            }
          </div>

          <!-- Right/bottom content -->
          @if (align() !== 'alternate' || i % 2 === 0 || orientation() === 'horizontal') {
            <div class="iu-timeline__content">
              <ng-container [ngTemplateOutlet]="contentTpl" [ngTemplateOutletContext]="{item}" />
            </div>
          } @else {
            <div class="iu-timeline__content--spacer"></div>
          }
        </div>
      }
    </div>

    <ng-template #contentTpl let-item="item">
      <div class="iu-timeline__card" [class.iu-timeline__card--active]="item.active">
        @if (item.date) {
          <span class="iu-timeline__date">{{ item.date }}</span>
        }
        <h4 class="iu-timeline__title">{{ item.title }}</h4>
        @if (item.description) {
          <p class="iu-timeline__desc">{{ item.description }}</p>
        }
      </div>
    </ng-template>
  `,
  styles: [`
    :host { display: block; }

    .iu-timeline {
      display: flex;

      &.iu-timeline--vertical {
        flex-direction: column;
      }

      &.iu-timeline--horizontal {
        flex-direction: row;
        overflow-x: auto;
      }
    }

    /* ── Item ── */
    .iu-timeline__item {
      display: flex;
      flex: 1;

      .iu-timeline--vertical & {
        flex-direction: row;
        align-items: stretch;
        gap: 16px;
        min-height: 60px;
      }

      .iu-timeline--horizontal & {
        flex-direction: column;
        align-items: center;
        gap: 8px;
        min-width: 140px;
      }
    }

    /* ── Spine ── */
    .iu-timeline__spine {
      display: flex;
      align-items: center;
      flex-shrink: 0;

      .iu-timeline--vertical & {
        flex-direction: column;
        width: 32px;
      }

      .iu-timeline--horizontal & {
        flex-direction: row;
        height: 32px;
        width: 100%;
        justify-content: center;
      }
    }

    /* ── Dot ── */
    .iu-timeline__dot {
      width: 32px;
      height: 32px;
      border-radius: 50%;
      flex-shrink: 0;
      display: flex;
      align-items: center;
      justify-content: center;
      background: var(--md-sys-color-outline-variant, #cac4d0);
      color: var(--md-sys-color-on-primary, #fff);
      transition: background 0.2s, transform 0.2s;
      z-index: 1;

      .material-symbols-outlined { font-size: 16px; }

      &.iu-timeline__dot--active {
        background: var(--md-sys-color-primary, #6750a4) !important;
        box-shadow: 0 0 0 4px var(--md-sys-color-primary-container, #eaddff);
        transform: scale(1.1);
      }
    }

    /* ── Connector ── */
    .iu-timeline__connector {
      background: var(--md-sys-color-outline-variant, #cac4d0);
      flex: 1;

      .iu-timeline--vertical & {
        width: 2px;
        min-height: 16px;
      }

      .iu-timeline--horizontal & {
        height: 2px;
        min-width: 16px;
      }

      &.iu-timeline__connector--active {
        background: var(--md-sys-color-primary, #6750a4);
      }
    }

    /* ── Content ── */
    .iu-timeline__content {
      flex: 1;
      padding-bottom: 24px;

      .iu-timeline--horizontal & {
        padding-bottom: 0;
        text-align: center;
      }
    }

    .iu-timeline__content--spacer {
      flex: 1;
    }

    .iu-timeline__content--opposite {
      flex: 1;
      padding-bottom: 24px;
      text-align: right;
    }

    /* ── Card ── */
    .iu-timeline__card {
      padding: 12px 16px;
      border-radius: 12px;
      background: var(--md-sys-color-surface-container, #f3edf7);
      border: 1px solid transparent;
      transition: border-color 0.2s, background 0.2s;

      &.iu-timeline__card--active {
        border-color: var(--md-sys-color-primary, #6750a4);
        background: var(--md-sys-color-primary-container, #eaddff);
      }

      .iu-timeline--horizontal & {
        text-align: center;
      }
    }

    .iu-timeline__date {
      display: block;
      font-size: 11px;
      font-weight: 500;
      color: var(--md-sys-color-primary, #6750a4);
      text-transform: uppercase;
      letter-spacing: 0.08em;
      margin-bottom: 4px;
    }

    .iu-timeline__title {
      font-size: 14px;
      font-weight: 600;
      color: var(--md-sys-color-on-surface, #1c1b1f);
      margin: 0 0 4px;
    }

    .iu-timeline__desc {
      font-size: 13px;
      color: var(--md-sys-color-on-surface-variant, #49454f);
      margin: 0;
      line-height: 1.5;
    }
  `],
  encapsulation: ViewEncapsulation.None,
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class TimelineComponent {
  /** Timeline items to display */
  items = input<TimelineItem[]>([]);
  /** Layout direction */
  orientation = input<TimelineOrientation>('vertical');
  /** Content alignment (vertical only) */
  align = input<TimelineAlign>('start');

  /** @internal */
  isFirst(index: number): boolean { return index === 0; }

  /** @internal — resolves color token or raw CSS value */
  resolveColor(item: TimelineItem): string | null {
    if (!item.color) return null;
    const map: Record<string, string> = {
      primary: 'var(--md-sys-color-primary, #6750a4)',
      success: '#4caf50',
      warning: '#ff9800',
      error: 'var(--md-sys-color-error, #b3261e)',
    };
    return map[item.color] ?? item.color;
  }
}

import { Component, signal } from '@angular/core';
import { ComponentFixture, TestBed } from '@angular/core/testing';
import {
  TooltipDirective,
  type TooltipPosition,
  type TooltipVariant,
} from './tooltip.directive';

const SHOW_DELAY = 500;
const HIDE_DELAY = 100;

@Component({
  standalone: true,
  imports: [TooltipDirective],
  template: `
    <button
      type="button"
      [iuTooltip]="text()"
      [tooltipVariant]="variant()"
      [tooltipPosition]="position()"
    >
      Hover me
    </button>
  `,
})
class HostComponent {
  readonly text = signal('Save draft');
  readonly variant = signal<TooltipVariant>('plain');
  readonly position = signal<TooltipPosition>('top');
}

describe('TooltipDirective', () => {
  let fixture: ComponentFixture<HostComponent>;
  let host: HostComponent;
  let button: HTMLButtonElement;

  const tip = () => document.querySelector('.iu-tooltip');

  beforeEach(async () => {
    jest.useFakeTimers();
    await TestBed.configureTestingModule({
      imports: [HostComponent],
    }).compileComponents();

    fixture = TestBed.createComponent(HostComponent);
    host = fixture.componentInstance;
    fixture.detectChanges();
    button = fixture.nativeElement.querySelector('button');
  });

  afterEach(() => {
    fixture.destroy();
    document.querySelectorAll('.iu-tooltip').forEach((el) => el.remove());
    jest.useRealTimers();
  });

  it('shows the tooltip after the hover delay', () => {
    button.dispatchEvent(new MouseEvent('mouseenter'));
    expect(tip()).toBeNull(); // not yet — waiting out the delay
    jest.advanceTimersByTime(SHOW_DELAY);
    expect(tip()).not.toBeNull();
    expect(tip()!.textContent).toBe('Save draft');
  });

  it('hides the tooltip after leave delay', () => {
    button.dispatchEvent(new MouseEvent('mouseenter'));
    jest.advanceTimersByTime(SHOW_DELAY);
    expect(tip()).not.toBeNull();

    button.dispatchEvent(new MouseEvent('mouseleave'));
    jest.advanceTimersByTime(HIDE_DELAY);
    expect(tip()).toBeNull();
  });

  it('shows and hides on focus / blur too', () => {
    button.dispatchEvent(new FocusEvent('focus'));
    jest.advanceTimersByTime(SHOW_DELAY);
    expect(tip()).not.toBeNull();

    button.dispatchEvent(new FocusEvent('blur'));
    jest.advanceTimersByTime(HIDE_DELAY);
    expect(tip()).toBeNull();
  });

  it('cancels a pending show when the pointer leaves before the delay elapses', () => {
    button.dispatchEvent(new MouseEvent('mouseenter'));
    jest.advanceTimersByTime(200); // still within the 500ms window
    button.dispatchEvent(new MouseEvent('mouseleave'));
    jest.advanceTimersByTime(SHOW_DELAY);
    expect(tip()).toBeNull();
  });

  it('applies the variant and position modifier classes', () => {
    host.variant.set('rich');
    host.position.set('bottom');
    fixture.detectChanges();

    button.dispatchEvent(new MouseEvent('mouseenter'));
    jest.advanceTimersByTime(SHOW_DELAY);

    expect(tip()!.classList).toContain('iu-tooltip--rich');
    expect(tip()!.classList).toContain('iu-tooltip--bottom');
  });

  it('injects the shared stylesheet once', () => {
    button.dispatchEvent(new MouseEvent('mouseenter'));
    jest.advanceTimersByTime(SHOW_DELAY);
    expect(document.getElementById('iu-tooltip-styles')).not.toBeNull();
  });

  it('does not create a tooltip for empty text', () => {
    host.text.set('');
    fixture.detectChanges();
    button.dispatchEvent(new MouseEvent('mouseenter'));
    jest.advanceTimersByTime(SHOW_DELAY);
    expect(tip()).toBeNull();
  });

  it('removes the tooltip and detaches listeners on destroy', () => {
    button.dispatchEvent(new MouseEvent('mouseenter'));
    jest.advanceTimersByTime(SHOW_DELAY);
    expect(tip()).not.toBeNull();

    fixture.destroy();
    expect(tip()).toBeNull();

    // listeners are gone — a further hover must not resurrect the tooltip
    button.dispatchEvent(new MouseEvent('mouseenter'));
    jest.advanceTimersByTime(SHOW_DELAY);
    expect(tip()).toBeNull();
  });
});

import {
  Directive,
  ElementRef,
  input,
  OnDestroy,
  Renderer2,
  inject,
} from '@angular/core';

export type TooltipVariant = 'plain' | 'rich';
export type TooltipPosition = 'top' | 'bottom' | 'left' | 'right';

/**
 * IU Tooltip — M3 Directive-based tooltip.
 *
 * Usage:
 *   <button [iuTooltip]="'Save draft'" tooltipPosition="bottom">Save</button>
 *   <span [iuTooltip]="'Details here'" tooltipVariant="rich">Info</span>
 */
@Directive({
  selector: '[iuTooltip]',
  standalone: true,
})
export class TooltipDirective implements OnDestroy {
  private el = inject(ElementRef);
  private renderer = inject(Renderer2);

  /** Tooltip text */
  iuTooltip = input.required<string>();

  /** Variant: plain (default) or rich */
  tooltipVariant = input<TooltipVariant>('plain');

  /** Position */
  tooltipPosition = input<TooltipPosition>('top');

  private tooltipEl: HTMLElement | null = null;
  private showTimeout: ReturnType<typeof setTimeout> | null = null;
  private hideTimeout: ReturnType<typeof setTimeout> | null = null;

  private onMouseEnter = () => this.show();
  private onMouseLeave = () => this.hide();
  private onFocus = () => this.show();
  private onBlur = () => this.hide();

  constructor() {
    const native = this.el.nativeElement;
    native.addEventListener('mouseenter', this.onMouseEnter);
    native.addEventListener('mouseleave', this.onMouseLeave);
    native.addEventListener('focus', this.onFocus);
    native.addEventListener('blur', this.onBlur);
  }

  ngOnDestroy(): void {
    this.removeTooltip();
    const native = this.el.nativeElement;
    native.removeEventListener('mouseenter', this.onMouseEnter);
    native.removeEventListener('mouseleave', this.onMouseLeave);
    native.removeEventListener('focus', this.onFocus);
    native.removeEventListener('blur', this.onBlur);
  }

  private show(): void {
    if (this.hideTimeout) {
      clearTimeout(this.hideTimeout);
      this.hideTimeout = null;
    }
    this.showTimeout = setTimeout(() => {
      this.createTooltip();
    }, 500);
  }

  private hide(): void {
    if (this.showTimeout) {
      clearTimeout(this.showTimeout);
      this.showTimeout = null;
    }
    this.hideTimeout = setTimeout(() => {
      this.removeTooltip();
    }, 100);
  }

  private createTooltip(): void {
    if (this.tooltipEl) return;

    const text = this.iuTooltip();
    if (!text) return;

    const variant = this.tooltipVariant();
    const position = this.tooltipPosition();

    this.tooltipEl = this.renderer.createElement('div');
    this.tooltipEl!.className = `iu-tooltip iu-tooltip--${variant} iu-tooltip--${position}`;
    this.tooltipEl!.textContent = text;

    // Inject styles if not present
    this.ensureStyles();

    document.body.appendChild(this.tooltipEl!);

    // Position relative to host
    const hostRect = this.el.nativeElement.getBoundingClientRect();
    const tipEl = this.tooltipEl!;

    // Need to measure after append
    requestAnimationFrame(() => {
      if (!this.tooltipEl) return;
      const tipRect = tipEl.getBoundingClientRect();
      const gap = 8;
      let top = 0;
      let left = 0;

      switch (position) {
        case 'top':
          top = hostRect.top - tipRect.height - gap;
          left = hostRect.left + (hostRect.width - tipRect.width) / 2;
          break;
        case 'bottom':
          top = hostRect.bottom + gap;
          left = hostRect.left + (hostRect.width - tipRect.width) / 2;
          break;
        case 'left':
          top = hostRect.top + (hostRect.height - tipRect.height) / 2;
          left = hostRect.left - tipRect.width - gap;
          break;
        case 'right':
          top = hostRect.top + (hostRect.height - tipRect.height) / 2;
          left = hostRect.right + gap;
          break;
      }

      tipEl.style.top = `${top + window.scrollY}px`;
      tipEl.style.left = `${left + window.scrollX}px`;
      tipEl.classList.add('iu-tooltip--visible');
    });
  }

  private removeTooltip(): void {
    if (this.tooltipEl) {
      this.tooltipEl.remove();
      this.tooltipEl = null;
    }
  }

  private stylesInjected = false;
  private ensureStyles(): void {
    if (this.stylesInjected || document.getElementById('iu-tooltip-styles')) return;
    this.stylesInjected = true;
    const style = document.createElement('style');
    style.id = 'iu-tooltip-styles';
    style.textContent = `
      .iu-tooltip {
        position: absolute;
        z-index: 1000;
        padding: 6px 8px;
        border-radius: 4px;
        font-family: 'Roboto', sans-serif;
        font-size: 12px;
        line-height: 16px;
        pointer-events: none;
        opacity: 0;
        transition: opacity 0.15s ease;
        max-width: 200px;
        word-wrap: break-word;
      }
      .iu-tooltip--visible {
        opacity: 1;
      }
      .iu-tooltip--plain {
        background: var(--md-sys-color-inverse-surface, #313033);
        color: var(--md-sys-color-inverse-on-surface, #f4eff4);
      }
      .iu-tooltip--rich {
        background: var(--md-sys-color-surface-container, #f1ecf1);
        color: var(--md-sys-color-on-surface, #1d1b20);
        padding: 12px 16px;
        border-radius: 12px;
        max-width: 320px;
        font-size: 14px;
        line-height: 20px;
        box-shadow: 0 2px 6px 2px rgba(0,0,0,.15), 0 1px 2px rgba(0,0,0,.3);
      }
    `;
    document.head.appendChild(style);
  }
}

