import { TestBed } from '@angular/core/testing';
import { CommunicationCenterStateService } from './communication-center-state.service';
import {
  LandlordCommunicationTemplatesService,
  type CommunicationTemplate,
  type CommunicationVars,
} from './landlord-communication-templates.service';

describe('CommunicationCenterStateService', () => {
  let service: CommunicationCenterStateService;
  let templatesStub: jest.Mocked<Pick<LandlordCommunicationTemplatesService, 'getTemplate' | 'fillTemplate'>>;

  const tplA: CommunicationTemplate = {
    id: 'tpl-a',
    titulo: 'Template A',
    category: 'rent',
    requiresSignature: false,
    placeholders: ['nome', 'morada'],
    body: 'Olá {{nome}}, sobre {{morada}}.',
  };

  const tplB: CommunicationTemplate = {
    id: 'tpl-b',
    titulo: 'Template B',
    category: 'visits',
    requiresSignature: true,
    placeholders: ['data'],
    body: 'Visita marcada para {{data}}.',
  };

  beforeEach(() => {
    templatesStub = {
      getTemplate: jest.fn((id: string) =>
        id === 'tpl-a' ? tplA : id === 'tpl-b' ? tplB : undefined,
      ),
      fillTemplate: jest.fn((id: string, vars: CommunicationVars) => {
        const tpl = id === 'tpl-a' ? tplA : id === 'tpl-b' ? tplB : undefined;
        if (!tpl) return undefined;
        const missing: string[] = [];
        let body = tpl.body;
        for (const key of tpl.placeholders) {
          const v = vars[key];
          if (v === undefined || v === null || v === '') {
            missing.push(key);
          } else {
            body = body.replace(`{{${key}}}`, String(v));
          }
        }
        return { body, missing };
      }),
    };

    TestBed.configureTestingModule({
      providers: [
        { provide: LandlordCommunicationTemplatesService, useValue: templatesStub },
      ],
    });
    service = TestBed.inject(CommunicationCenterStateService);
  });

  it('starts with no template selected and empty state', () => {
    expect(service.selectedTemplateId()).toBeNull();
    expect(service.currentTemplate()).toBeUndefined();
    expect(service.filledResult()).toBeUndefined();
    expect(service.filledBody()).toBe('');
    expect(service.missingPlaceholders()).toEqual([]);
    expect(service.canSend()).toBe(false);
    expect(service.historyEntries()).toEqual([]);
  });

  it('selectTemplate sets the current template and clears placeholder values', () => {
    service.setPlaceholder('nome', 'leftover');
    service.selectTemplate('tpl-a');
    expect(service.selectedTemplateId()).toBe('tpl-a');
    expect(service.currentTemplate()).toBe(tplA);
    expect(service.placeholderValues()).toEqual({});
  });

  it('selectTemplate(null) clears the selection', () => {
    service.selectTemplate('tpl-a');
    service.selectTemplate(null);
    expect(service.selectedTemplateId()).toBeNull();
    expect(service.currentTemplate()).toBeUndefined();
  });

  it('setPlaceholder updates one key without dropping the others', () => {
    service.setPlaceholder('nome', 'Israel');
    service.setPlaceholder('morada', 'Rua Augusta');
    expect(service.placeholderValues()).toEqual({ nome: 'Israel', morada: 'Rua Augusta' });
    service.setPlaceholder('nome', 'Maria');
    expect(service.placeholderValues()).toEqual({ nome: 'Maria', morada: 'Rua Augusta' });
  });

  it('exposes missing placeholders while incomplete and clears them once filled', () => {
    service.selectTemplate('tpl-a');
    expect(service.missingPlaceholders()).toEqual(['nome', 'morada']);
    expect(service.canSend()).toBe(false);

    service.setPlaceholder('nome', 'Israel');
    expect(service.missingPlaceholders()).toEqual(['morada']);
    expect(service.canSend()).toBe(false);

    service.setPlaceholder('morada', 'Lisboa');
    expect(service.missingPlaceholders()).toEqual([]);
    expect(service.filledBody()).toBe('Olá Israel, sobre Lisboa.');
    expect(service.canSend()).toBe(true);
  });

  it('send() returns undefined and does not record history when not ready', () => {
    expect(service.send()).toBeUndefined();
    service.selectTemplate('tpl-a');
    service.setPlaceholder('nome', 'Israel'); // morada ainda em falta
    expect(service.send()).toBeUndefined();
    expect(service.historyEntries()).toEqual([]);
  });

  it('send() appends a sent entry with the filled body', () => {
    service.selectTemplate('tpl-a');
    service.setPlaceholder('nome', 'Israel');
    service.setPlaceholder('morada', 'Lisboa');

    const entry = service.send();
    expect(entry).toBeDefined();
    expect(entry!.mode).toBe('sent');
    expect(entry!.templateId).toBe('tpl-a');
    expect(entry!.templateTitle).toBe('Template A');
    expect(entry!.body).toBe('Olá Israel, sobre Lisboa.');
    expect(entry!.sentAt).toBeInstanceOf(Date);
    expect(service.historyEntries()).toHaveLength(1);
    expect(service.historyEntries()[0]).toBe(entry);
  });

  it('copyToClipboard() appends a copied entry without writing to the clipboard', () => {
    service.selectTemplate('tpl-b');
    service.setPlaceholder('data', '2026-06-01');

    const entry = service.copyToClipboard();
    expect(entry).toBeDefined();
    expect(entry!.mode).toBe('copied');
    expect(entry!.templateId).toBe('tpl-b');
    expect(entry!.body).toBe('Visita marcada para 2026-06-01.');
    expect(service.historyEntries()).toHaveLength(1);
  });

  it('history is most-recent-first', () => {
    service.selectTemplate('tpl-a');
    service.setPlaceholder('nome', 'Ana');
    service.setPlaceholder('morada', 'Porto');
    const first = service.send()!;

    service.selectTemplate('tpl-b');
    service.setPlaceholder('data', '2026-07-10');
    const second = service.copyToClipboard()!;

    expect(service.historyEntries()).toEqual([second, first]);
  });

  it('generates unique ids across consecutive entries', () => {
    service.selectTemplate('tpl-b');
    service.setPlaceholder('data', 'X');
    const a = service.send()!;
    const b = service.copyToClipboard()!;
    expect(a.id).not.toEqual(b.id);
  });

  it('clearHistory empties the history but keeps current draft', () => {
    service.selectTemplate('tpl-b');
    service.setPlaceholder('data', '2026-07-10');
    service.send();
    expect(service.historyEntries()).toHaveLength(1);

    service.clearHistory();
    expect(service.historyEntries()).toEqual([]);
    expect(service.selectedTemplateId()).toBe('tpl-b');
    expect(service.placeholderValues()).toEqual({ data: '2026-07-10' });
    expect(service.canSend()).toBe(true);
  });
});

import { Injectable, computed, inject, signal } from '@angular/core';
import {
  LandlordCommunicationTemplatesService,
  CommunicationVars,
} from './landlord-communication-templates.service';

/** A message that was prepared (filled) and sent / copied through the center. */
export interface CommunicationHistoryEntry {
  readonly id: string;
  readonly templateId: string;
  readonly templateTitle: string;
  readonly body: string;
  readonly sentAt: Date;
  /** `'sent'` once the user clicked "Send"; `'copied'` for clipboard copy. */
  readonly mode: 'sent' | 'copied';
}

let __histSeq = 0;
const nextHistId = () => `comm-${++__histSeq}-${Date.now().toString(36)}`;

/**
 * Editor state for {@link CommunicationCenterComponent}.
 *
 * Holds the currently-selected template, the placeholder values the landlord
 * has typed, and the local history of dispatched messages. All filling logic
 * is delegated to {@link LandlordCommunicationTemplatesService.fillTemplate}.
 *
 * No RxJS — pure signals.
 */
@Injectable({ providedIn: 'root' })
export class CommunicationCenterStateService {
  private readonly templates = inject(LandlordCommunicationTemplatesService);

  /** Currently selected template id, or `null` when nothing is chosen. */
  readonly selectedTemplateId = signal<string | null>(null);

  /** Free-form values keyed by placeholder name. */
  readonly placeholderValues = signal<Record<string, string>>({});

  private readonly _history = signal<CommunicationHistoryEntry[]>([]);

  /** Read-only history of sent / copied messages (most-recent first). */
  readonly historyEntries = this._history.asReadonly();

  /** The currently-selected `CommunicationTemplate`, or `undefined`. */
  readonly currentTemplate = computed(() => {
    const id = this.selectedTemplateId();
    return id == null ? undefined : this.templates.getTemplate(id);
  });

  /** Result of filling the current template with current placeholder values. */
  readonly filledResult = computed(() => {
    const id = this.selectedTemplateId();
    if (id == null) return undefined;
    return this.templates.fillTemplate(id, this.placeholderValues() as CommunicationVars);
  });

  /** Body with placeholders substituted (or empty when no template). */
  readonly filledBody = computed(() => this.filledResult()?.body ?? '');

  /** Placeholder names still empty in the current template. */
  readonly missingPlaceholders = computed<ReadonlyArray<string>>(() => this.filledResult()?.missing ?? []);

  /** True when a template is selected and all placeholders are filled. */
  readonly canSend = computed(
    () => this.currentTemplate() !== undefined && this.missingPlaceholders().length === 0,
  );

  /** Replace the current template selection. Resets placeholder values. */
  selectTemplate(id: string | null): void {
    this.selectedTemplateId.set(id);
    this.placeholderValues.set({});
  }

  /** Update a single placeholder value. */
  setPlaceholder(key: string, value: string): void {
    this.placeholderValues.update(prev => ({ ...prev, [key]: value }));
  }

  /** Append a `'sent'` entry to history (no-op when not ready to send). */
  send(): CommunicationHistoryEntry | undefined {
    if (!this.canSend()) return undefined;
    return this.appendHistory('sent');
  }

  /**
   * Append a `'copied'` entry to history. Returns the entry; the caller is
   * responsible for the actual clipboard write (the service stays UI-free).
   */
  copyToClipboard(): CommunicationHistoryEntry | undefined {
    if (!this.canSend()) return undefined;
    return this.appendHistory('copied');
  }

  /** Wipe the local history (does not affect templates or current draft). */
  clearHistory(): void {
    this._history.set([]);
  }

  private appendHistory(mode: 'sent' | 'copied'): CommunicationHistoryEntry {
    const tpl = this.currentTemplate()!;
    const entry: CommunicationHistoryEntry = {
      id: nextHistId(),
      templateId: tpl.id,
      templateTitle: tpl.titulo,
      body: this.filledBody(),
      sentAt: new Date(),
      mode,
    };
    this._history.update(list => [entry, ...list]);
    return entry;
  }
}

import { TestBed } from '@angular/core/testing';
import { FavouritesService } from './favourites.service';

const STORAGE_KEY = 'iu_favourites_v1';

describe('FavouritesService', () => {
  let storage: Record<string, string>;
  let getItemSpy: jest.SpyInstance;
  let setItemSpy: jest.SpyInstance;
  let storageListener: ((e: StorageEvent) => void) | undefined;
  let originalAddEventListener: typeof window.addEventListener;

  beforeEach(() => {
    storage = {};
    storageListener = undefined;

    getItemSpy = jest
      .spyOn(Storage.prototype, 'getItem')
      .mockImplementation((k: string) => storage[k] ?? null);
    setItemSpy = jest
      .spyOn(Storage.prototype, 'setItem')
      .mockImplementation((k: string, v: string) => {
        storage[k] = String(v);
      });

    // Capture the 'storage' listener so we can dispatch synthetic events
    originalAddEventListener = window.addEventListener.bind(window);
    jest.spyOn(window, 'addEventListener').mockImplementation((type: string, cb: EventListenerOrEventListenerObject) => {
      if (type === 'storage') {
        storageListener = cb as (e: StorageEvent) => void;
      } else {
        originalAddEventListener(type as keyof WindowEventMap, cb);
      }
    });
  });

  afterEach(() => {
    jest.restoreAllMocks();
  });

  const createService = (): FavouritesService => {
    TestBed.resetTestingModule();
    TestBed.configureTestingModule({});
    const svc = TestBed.inject(FavouritesService);
    // Flush the persistence effect()
    TestBed.tick();
    return svc;
  };

  it('starts empty when localStorage has nothing', () => {
    const service = createService();
    expect(service.ids()).toEqual([]);
    expect(service.count()).toBe(0);
    expect(service.hasAny()).toBe(false);
  });

  it('loads previously persisted favourites on construction', () => {
    storage[STORAGE_KEY] = JSON.stringify(['p1', 'p2', 'p3']);
    const service = createService();
    expect(service.ids().sort()).toEqual(['p1', 'p2', 'p3']);
    expect(service.count()).toBe(3);
    expect(service.hasAny()).toBe(true);
  });

  it('falls back to empty when stored payload is not an array', () => {
    storage[STORAGE_KEY] = JSON.stringify({ not: 'an array' });
    const service = createService();
    expect(service.ids()).toEqual([]);
  });

  it('falls back to empty when stored payload is malformed JSON', () => {
    storage[STORAGE_KEY] = '{not-json';
    const service = createService();
    expect(service.ids()).toEqual([]);
  });

  it('add() inserts a new id and persists', () => {
    const service = createService();
    service.add('p1');
    TestBed.tick();
    expect(service.isFavourited('p1')).toBe(true);
    expect(service.count()).toBe(1);
    expect(storage[STORAGE_KEY]).toBe(JSON.stringify(['p1']));
  });

  it('add() is idempotent for the same id', () => {
    const service = createService();
    service.add('p1');
    service.add('p1');
    expect(service.count()).toBe(1);
  });

  it('coerces numeric ids to strings', () => {
    const service = createService();
    service.add(42);
    expect(service.isFavourited(42)).toBe(true);
    expect(service.isFavourited('42')).toBe(true);
    expect(service.ids()).toEqual(['42']);
  });

  it('remove() drops an existing id and persists', () => {
    const service = createService();
    service.add('p1');
    service.add('p2');
    service.remove('p1');
    TestBed.tick();
    expect(service.isFavourited('p1')).toBe(false);
    expect(service.isFavourited('p2')).toBe(true);
    expect(JSON.parse(storage[STORAGE_KEY])).toEqual(['p2']);
  });

  it('remove() is a no-op when id is not present', () => {
    const service = createService();
    service.add('p1');
    expect(() => service.remove('nope')).not.toThrow();
    expect(service.ids()).toEqual(['p1']);
  });

  it('toggle() adds when absent and returns true', () => {
    const service = createService();
    const result = service.toggle('p1');
    expect(result).toBe(true);
    expect(service.isFavourited('p1')).toBe(true);
  });

  it('toggle() removes when present and returns false', () => {
    const service = createService();
    service.add('p1');
    const result = service.toggle('p1');
    expect(result).toBe(false);
    expect(service.isFavourited('p1')).toBe(false);
  });

  it('clearAll() wipes state and persists empty array', () => {
    const service = createService();
    service.add('p1');
    service.add('p2');
    service.clearAll();
    TestBed.tick();
    expect(service.count()).toBe(0);
    expect(JSON.parse(storage[STORAGE_KEY])).toEqual([]);
  });

  it('filterFavourited returns only items whose id is favourited', () => {
    const service = createService();
    service.add('a');
    service.add('c');
    const items = [{ id: 'a' }, { id: 'b' }, { id: 'c' }, { id: 'd' }];
    expect(service.filterFavourited(items)).toEqual([{ id: 'a' }, { id: 'c' }]);
  });

  it('filterFavourited handles numeric ids via string coercion', () => {
    const service = createService();
    service.add(1);
    service.add(3);
    const items = [{ id: 1 }, { id: 2 }, { id: 3 }];
    expect(service.filterFavourited(items)).toEqual([{ id: 1 }, { id: 3 }]);
  });

  it('count and hasAny are reactive to add/remove', () => {
    const service = createService();
    expect(service.hasAny()).toBe(false);
    service.add('p1');
    expect(service.hasAny()).toBe(true);
    expect(service.count()).toBe(1);
    service.remove('p1');
    expect(service.hasAny()).toBe(false);
    expect(service.count()).toBe(0);
  });

  it('syncs in from a cross-tab storage event with a valid array', () => {
    const service = createService();
    expect(storageListener).toBeDefined();
    storageListener!({
      key: STORAGE_KEY,
      newValue: JSON.stringify(['x1', 'x2']),
    } as StorageEvent);
    expect(service.ids().sort()).toEqual(['x1', 'x2']);
  });

  it('ignores cross-tab storage events for unrelated keys', () => {
    const service = createService();
    service.add('p1');
    storageListener!({
      key: 'something-else',
      newValue: JSON.stringify(['x1']),
    } as StorageEvent);
    expect(service.ids()).toEqual(['p1']);
  });

  it('ignores cross-tab storage events with malformed payloads', () => {
    const service = createService();
    service.add('p1');
    storageListener!({
      key: STORAGE_KEY,
      newValue: '{not-json',
    } as StorageEvent);
    expect(service.ids()).toEqual(['p1']);
  });

  it('ignores cross-tab storage events with non-array payloads', () => {
    const service = createService();
    service.add('p1');
    storageListener!({
      key: STORAGE_KEY,
      newValue: JSON.stringify({ not: 'array' }),
    } as StorageEvent);
    expect(service.ids()).toEqual(['p1']);
  });

  it('swallows localStorage write failures (quota / private mode)', () => {
    const service = createService();
    setItemSpy.mockImplementation(() => {
      throw new Error('QuotaExceeded');
    });
    expect(() => {
      service.add('p1');
      TestBed.tick();
    }).not.toThrow();
    expect(service.isFavourited('p1')).toBe(true);
  });

  it('returns empty when localStorage read throws', () => {
    getItemSpy.mockImplementation(() => {
      throw new Error('SecurityError');
    });
    const service = createService();
    expect(service.ids()).toEqual([]);
  });
});

import { TestBed } from '@angular/core/testing';
import { HttpErrorResponse } from '@angular/common/http';
import { Router } from '@angular/router';
import { HttpErrorService } from './http-error.service';

describe('HttpErrorService', () => {
  let service: HttpErrorService;
  let routerNavigate: jest.Mock;
  let routerUrl: string;

  const makeError = (over: Partial<{ status: number; error: unknown; url: string | null }> = {}) =>
    new HttpErrorResponse({
      status: over.status ?? 500,
      error: over.error,
      url: over.url ?? 'https://api.example.com/x',
    });

  let consoleErrorSpy: jest.SpyInstance;

  beforeEach(() => {
    consoleErrorSpy = jest.spyOn(console, 'error').mockImplementation(() => undefined);
    routerUrl = '/dashboard';
    routerNavigate = jest.fn();
    TestBed.configureTestingModule({
      providers: [
        {
          provide: Router,
          useValue: {
            navigate: routerNavigate,
            get url() { return routerUrl; },
          },
        },
      ],
    });
    service = TestBed.inject(HttpErrorService);
  });

  afterEach(() => {
    consoleErrorSpy.mockRestore();
  });

  it('starts with no error and zero count', () => {
    expect(service.lastError()).toBeNull();
    expect(service.errorCount()).toBe(0);
  });

  it('handleHttpError populates lastError and increments errorCount', () => {
    service.handleHttpError(makeError({ status: 404 }));
    const info = service.lastError();
    expect(info).not.toBeNull();
    expect(info!.status).toBe(404);
    expect(info!.url).toBe('https://api.example.com/x');
    expect(info!.timestamp).toBeInstanceOf(Date);
    expect(service.errorCount()).toBe(1);

    service.handleHttpError(makeError({ status: 500 }));
    expect(service.errorCount()).toBe(2);
  });

  it('prefers server-provided error.message when present', () => {
    service.handleHttpError(makeError({ status: 422, error: { message: 'NIF inválido' } }));
    expect(service.lastError()!.message).toBe('NIF inválido');
  });

  it('maps known status codes to user-facing messages', () => {
    const cases: Array<[number, string]> = [
      [0,   'Network error — check your connection.'],
      [400, 'Bad request. Please check your input.'],
      [401, 'Session expired. Please log in again.'],
      [403, 'You don\'t have permission to do this.'],
      [404, 'The requested resource was not found.'],
      [409, 'Conflict — the resource may already exist.'],
      [422, 'Validation error. Please check your input.'],
      [429, 'Too many requests. Please slow down.'],
      [500, 'Server error. Please try again later.'],
      [503, 'Service unavailable. Please try again shortly.'],
    ];
    for (const [status, expected] of cases) {
      service.handleHttpError(makeError({ status }));
      expect(service.lastError()!.message).toBe(expected);
    }
  });

  it('falls back to a generic message for unknown status codes', () => {
    service.handleHttpError(makeError({ status: 418 }));
    expect(service.lastError()!.message).toBe('Unexpected error (418).');
  });

  it('navigates to /auth/login on 401 when not already in auth area', () => {
    routerUrl = '/dashboard';
    service.handleHttpError(makeError({ status: 401 }));
    expect(routerNavigate).toHaveBeenCalledWith(['/auth/login']);
  });

  it('does NOT redirect on 401 when already inside /auth', () => {
    routerUrl = '/auth/login';
    service.handleHttpError(makeError({ status: 401 }));
    expect(routerNavigate).not.toHaveBeenCalled();
  });

  it('logs server errors (>= 500) via console.error', () => {
    service.handleHttpError(makeError({ status: 503 }));
    expect(consoleErrorSpy).toHaveBeenCalled();
  });

  it('clearError resets lastError but preserves errorCount', () => {
    service.handleHttpError(makeError({ status: 500 }));
    expect(service.errorCount()).toBe(1);
    service.clearError();
    expect(service.lastError()).toBeNull();
    expect(service.errorCount()).toBe(1);
  });
});

import { TestBed } from '@angular/core/testing';
import { InsuranceTrackerService, type InsurancePolicy } from './insurance-tracker.service';

describe('InsuranceTrackerService', () => {
  let service: InsuranceTrackerService;

  /** Build a policy fixture; `id` is generated by addPolicy in tests that hit the real path. */
  const policyInput = (over: Partial<Omit<InsurancePolicy, 'id'>> = {}): Omit<InsurancePolicy, 'id'> => ({
    propertyId: 'prop-1',
    insurer: 'Fidelidade',
    policyNumber: 'P-0001',
    type: 'multirriscos',
    startDate: '2026-01-01',
    endDate: '2027-01-01',
    premium: 240,
    ...over,
  });

  beforeEach(() => {
    TestBed.configureTestingModule({});
    service = TestBed.inject(InsuranceTrackerService);
  });

  it('starts with an empty policy list', () => {
    expect(service.policies()).toEqual([]);
    expect(service.activePolicies()).toEqual([]);
    expect(service.expiringSoon()).toEqual([]);
    expect(service.expired()).toEqual([]);
    expect(service.byProperty().size).toBe(0);
  });

  it('addPolicy assigns a unique id and appends to the list', () => {
    const a = service.addPolicy(policyInput());
    const b = service.addPolicy(policyInput({ policyNumber: 'P-0002' }));
    expect(a.id).toBeTruthy();
    expect(b.id).toBeTruthy();
    expect(a.id).not.toBe(b.id);
    expect(service.policies().length).toBe(2);
    expect(service.policies()[0]).toEqual(a);
  });

  it('removePolicy strips by id and is a no-op for unknown ids', () => {
    const a = service.addPolicy(policyInput());
    const b = service.addPolicy(policyInput({ policyNumber: 'P-0002' }));
    service.removePolicy(a.id);
    expect(service.policies()).toEqual([b]);
    service.removePolicy('does-not-exist');
    expect(service.policies()).toEqual([b]);
  });

  it('renewPolicy updates endDate of a matched policy only', () => {
    const a = service.addPolicy(policyInput({ endDate: '2026-06-01' }));
    const b = service.addPolicy(policyInput({ policyNumber: 'P-0002', endDate: '2026-08-01' }));
    service.renewPolicy(a.id, '2027-06-01');
    const found = service.policies().find(p => p.id === a.id)!;
    const other = service.policies().find(p => p.id === b.id)!;
    expect(found.endDate).toBe('2027-06-01');
    expect(other.endDate).toBe('2026-08-01');
  });

  it('renewPolicy on unknown id is a no-op', () => {
    service.addPolicy(policyInput({ endDate: '2026-06-01' }));
    const before = service.policies();
    service.renewPolicy('nope', '2099-01-01');
    expect(service.policies()).toEqual(before);
  });

  it('activePolicies excludes lapsed policies based on today()', () => {
    service.today.set('2026-06-01');
    service.addPolicy(policyInput({ endDate: '2026-12-31' })); // active
    service.addPolicy(policyInput({ policyNumber: 'P-0002', endDate: '2026-05-31' })); // expired
    expect(service.activePolicies().length).toBe(1);
    expect(service.activePolicies()[0].endDate).toBe('2026-12-31');
  });

  it('expiringSoon flags policies ending in 0..30 days inclusive', () => {
    service.today.set('2026-06-01');
    service.addPolicy(policyInput({ endDate: '2026-06-01' })); // 0 days → flagged
    service.addPolicy(policyInput({ policyNumber: 'P-0002', endDate: '2026-07-01' })); // 30 days → flagged
    service.addPolicy(policyInput({ policyNumber: 'P-0003', endDate: '2026-07-02' })); // 31 days → not flagged
    service.addPolicy(policyInput({ policyNumber: 'P-0004', endDate: '2026-05-31' })); // expired → not flagged
    const nums = service.expiringSoon().map(p => p.policyNumber).sort();
    expect(nums).toEqual(['P-0001', 'P-0002']);
  });

  it('expired returns only policies past their endDate', () => {
    service.today.set('2026-06-01');
    service.addPolicy(policyInput({ endDate: '2026-05-30' }));
    service.addPolicy(policyInput({ policyNumber: 'P-0002', endDate: '2026-06-01' })); // today → still active
    service.addPolicy(policyInput({ policyNumber: 'P-0003', endDate: '2026-12-31' }));
    expect(service.expired().length).toBe(1);
    expect(service.expired()[0].policyNumber).toBe('P-0001');
  });

  it('byProperty groups policies under their propertyId', () => {
    service.addPolicy(policyInput({ propertyId: 'prop-1' }));
    service.addPolicy(policyInput({ propertyId: 'prop-1', policyNumber: 'P-0002', type: 'rc' }));
    service.addPolicy(policyInput({ propertyId: 'prop-2', policyNumber: 'P-0003' }));
    const grouped = service.byProperty();
    expect(grouped.size).toBe(2);
    expect(grouped.get('prop-1')!.length).toBe(2);
    expect(grouped.get('prop-2')!.length).toBe(1);
  });

  it('reset clears the policy list', () => {
    service.addPolicy(policyInput());
    service.addPolicy(policyInput({ policyNumber: 'P-0002' }));
    expect(service.policies().length).toBe(2);
    service.reset();
    expect(service.policies()).toEqual([]);
    expect(service.byProperty().size).toBe(0);
  });

  it('treats invalid endDate as 0 days remaining (flagged as expiringSoon, not expired)', () => {
    // daysBetween returns 0 on NaN parse → policy is treated as "expiring today" (>= 0 && <= 30).
    service.today.set('2026-06-01');
    service.addPolicy(policyInput({ endDate: 'not-a-date' }));
    expect(service.expired().length).toBe(0);
    expect(service.expiringSoon().length).toBe(1);
  });
});

import { TestBed } from '@angular/core/testing';
import {
  LandlordCommunicationTemplatesService,
  type TemplateCategory,
} from './landlord-communication-templates.service';

describe('LandlordCommunicationTemplatesService', () => {
  const createService = (): LandlordCommunicationTemplatesService => {
    TestBed.resetTestingModule();
    TestBed.configureTestingModule({});
    return TestBed.inject(LandlordCommunicationTemplatesService);
  };

  // ── Catalog shape ────────────────────────────────────────────────────────

  it('exposes the 5 curated templates', () => {
    const svc = createService();
    const ids = svc.templates().map(t => t.id).sort();
    expect(ids).toEqual([
      'aviso_aumento_renda',
      'confirmacao_visita',
      'denuncia_contrato_arrendamento',
      'notificacao_obras',
      'recibo_caucao',
    ]);
  });

  it('every template carries the required metadata fields', () => {
    const svc = createService();
    for (const t of svc.templates()) {
      expect(t.id).toBeTruthy();
      expect(t.titulo).toBeTruthy();
      expect(t.category).toBeTruthy();
      expect(t.body.length).toBeGreaterThan(0);
      expect(typeof t.requiresSignature).toBe('boolean');
      expect(Array.isArray(t.placeholders)).toBe(true);
    }
  });

  it('templates needing signature have a legalReference attached', () => {
    const svc = createService();
    for (const t of svc.templates()) {
      if (t.requiresSignature) {
        expect(t.legalReference).toBeTruthy();
      }
    }
  });

  it('every declared placeholder actually appears in the body', () => {
    const svc = createService();
    for (const t of svc.templates()) {
      for (const ph of t.placeholders) {
        expect(t.body).toContain(`{{${ph}}}`);
      }
    }
  });

  // ── byCategory grouping ──────────────────────────────────────────────────

  it('byCategory groups templates under their category key', () => {
    const svc = createService();
    const groups = svc.byCategory();
    expect(groups.get('lease')?.map(t => t.id)).toEqual(['denuncia_contrato_arrendamento']);
    expect(groups.get('rent')?.map(t => t.id)).toEqual(['aviso_aumento_renda']);
    expect(groups.get('deposit')?.map(t => t.id)).toEqual(['recibo_caucao']);
    expect(groups.get('works')?.map(t => t.id)).toEqual(['notificacao_obras']);
    expect(groups.get('visits')?.map(t => t.id)).toEqual(['confirmacao_visita']);
  });

  it('byCategory total across groups matches templates count', () => {
    const svc = createService();
    let total = 0;
    for (const [, arr] of svc.byCategory()) {
      total += arr.length;
    }
    expect(total).toBe(svc.templates().length);
  });

  it('byCategory does not surface empty categories', () => {
    const svc = createService();
    const groups = svc.byCategory();
    for (const [, arr] of groups) {
      expect(arr.length).toBeGreaterThan(0);
    }
  });

  // ── getTemplate ──────────────────────────────────────────────────────────

  it('getTemplate returns the matching template by id', () => {
    const svc = createService();
    const t = svc.getTemplate('aviso_aumento_renda');
