  it('loadForTenant with unknown id leaves requests empty after flush', () => {
    jest.useFakeTimers();
    try {
      service.loadForTenant('tenant-unknown');
      jest.advanceTimersByTime(300);
      expect(service.requests()).toEqual([]);
      expect(service.pendingCount()).toBe(0);
      expect(service.urgentCount()).toBe(0);
    } finally {
      jest.useRealTimers();
    }
  });

  it('create prepends a new pending request with generated id and timestamps', () => {
    const before = service.requests().length;
    const created = service.create(basePayload({ title: 'Heater broken' }));
    const after = service.requests();
    expect(after.length).toBe(before + 1);
    expect(after[0]).toBe(created);
    expect(created.id).toMatch(/^mr-\d+/);
    expect(created.status).toBe('pending');
    expect(created.title).toBe('Heater broken');
    expect(created.createdAt).toMatch(/^\d{4}-\d{2}-\d{2}T/);
    expect(created.updatedAt).toBe(created.createdAt);
  });

  it('create reflects new entry in pendingCount and urgentCount when applicable', () => {
    expect(service.pendingCount()).toBe(1);
    service.create(basePayload({ priority: 'urgent' }));
    expect(service.pendingCount()).toBe(2);
    expect(service.urgentCount()).toBe(2);
  });

  it('updateStatus mutates status + resolution + updatedAt for the targeted request', () => {
    const before = service.requests().find(r => r.id === 'mr-002')!;
    const payload: UpdateMaintenanceStatusPayload = {
      status: 'resolved',
      resolution: 'Electrician repaired the socket',
    };
    service.updateStatus('mr-002', payload);
    const after = service.requests().find(r => r.id === 'mr-002')!;
    expect(after.status).toBe('resolved');
    expect(after.resolution).toBe('Electrician repaired the socket');
    expect(after.updatedAt).not.toBe(before.updatedAt);
  });

  it('updateStatus can carry scheduledDate without resolution', () => {
    service.updateStatus('mr-002', {
      status: 'in-progress',
      scheduledDate: '2026-04-10T09:00:00Z',
    });
    const r = service.requests().find(x => x.id === 'mr-002')!;
    expect(r.status).toBe('in-progress');
    expect(r.scheduledDate).toBe('2026-04-10T09:00:00Z');
  });

  it('updateStatus on unknown id is a no-op (no entries mutated)', () => {
    const before = service.requests();
    service.updateStatus('mr-zzz', { status: 'resolved' });
    expect(service.requests()).toEqual(before);
  });

  it('delete removes the request matching the given id', () => {
    const before = service.requests().length;
    service.delete('mr-001');
    const after = service.requests();
    expect(after.length).toBe(before - 1);
    expect(after.some(r => r.id === 'mr-001')).toBe(false);
  });

  it('delete on unknown id leaves requests unchanged', () => {
    const before = service.requests();
    service.delete('mr-does-not-exist');
    expect(service.requests()).toEqual(before);
  });

  it('urgentCount only counts urgent priority that is not yet resolved', () => {
    service.create(basePayload({ priority: 'urgent' }));
    expect(service.urgentCount()).toBe(2);
    // Resolving an urgent request should drop the count
    const urgentId = service.requests().find(r => r.priority === 'urgent')!.id;
    service.updateStatus(urgentId, { status: 'resolved' });
    expect(service.urgentCount()).toBe(1);
  });

  it('pendingCount recomputes after status transitions', () => {
    expect(service.pendingCount()).toBe(1);
    service.updateStatus('mr-002', { status: 'in-progress' });
    expect(service.pendingCount()).toBe(0);
  });
});

import { TestBed } from '@angular/core/testing';
import { MoveInChecklistService, type MoveInCategory } from './move-in-checklist.service';

describe('MoveInChecklistService', () => {
  let service: MoveInChecklistService;

  beforeEach(() => {
    TestBed.configureTestingModule({});
    service = TestBed.inject(MoveInChecklistService);
  });

  it('seeds with the full default task list, all unchecked', () => {
    const tasks = service.tasks();
    expect(tasks.length).toBeGreaterThan(0);
    expect(tasks.every(t => t.done === false)).toBe(true);
    expect(service.completed()).toBe(0);
  });

  it('seeds tasks across all five categories', () => {
    const cats = new Set(service.tasks().map(t => t.category));
    const expected: MoveInCategory[] = ['utilities', 'admin', 'financial', 'logistics', 'inspection'];
    for (const c of expected) {
      expect(cats.has(c)).toBe(true);
    }
  });

  it('total reflects the seeded task count', () => {
    expect(service.total()).toBe(service.tasks().length);
  });

  it('progressPct starts at 0 and is 100 when every task is done', () => {
    expect(service.progressPct()).toBe(0);
    service.completeAll();
    expect(service.progressPct()).toBe(100);
    expect(service.isComplete()).toBe(true);
  });

  it('toggle flips done flag on a known id and leaves others untouched', () => {
    const firstId = service.tasks()[0].id;
    service.toggle(firstId);
    const t = service.tasks().find(x => x.id === firstId)!;
    expect(t.done).toBe(true);
    expect(service.completed()).toBe(1);

    // Re-toggle returns to unchecked
    service.toggle(firstId);
    expect(service.tasks().find(x => x.id === firstId)!.done).toBe(false);
    expect(service.completed()).toBe(0);
  });

  it('toggle on an unknown id is a no-op', () => {
    const before = service.tasks();
    service.toggle('does-not-exist');
    expect(service.tasks()).toEqual(before);
    expect(service.completed()).toBe(0);
  });

  it('completeAll marks every task as done', () => {
    service.completeAll();
    expect(service.tasks().every(t => t.done)).toBe(true);
    expect(service.completed()).toBe(service.total());
    expect(service.isComplete()).toBe(true);
  });

  it('resetAll restores the original unchecked seed', () => {
    service.completeAll();
    expect(service.completed()).toBeGreaterThan(0);
    service.resetAll();
    expect(service.completed()).toBe(0);
    expect(service.tasks().every(t => t.done === false)).toBe(true);
  });

  it('byCategory groups tasks under their category key', () => {
    const grouped = service.byCategory();
    let sumGroups = 0;
    for (const items of grouped.values()) {
      sumGroups += items.length;
    }
    expect(sumGroups).toBe(service.total());
    // utilities should hold ≥ 4 transfer tasks (electricity, water, gas, internet)
    expect((grouped.get('utilities') ?? []).length).toBeGreaterThanOrEqual(4);
  });

  it('categoryProgress reports per-bucket completion and stays in sync after toggle', () => {
    const grouped = service.byCategory();
    const beforeUtil = service.categoryProgress().get('utilities')!;
    expect(beforeUtil.done).toBe(0);
    expect(beforeUtil.total).toBe((grouped.get('utilities') ?? []).length);
    expect(beforeUtil.pct).toBe(0);

    const firstUtility = (grouped.get('utilities') ?? [])[0];
    service.toggle(firstUtility.id);

    const afterUtil = service.categoryProgress().get('utilities')!;
    expect(afterUtil.done).toBe(1);
    expect(afterUtil.pct).toBe(Math.round((1 / afterUtil.total) * 100));
  });

  it('isComplete is false until every task is checked', () => {
    expect(service.isComplete()).toBe(false);
    const ids = service.tasks().map(t => t.id);
    for (let i = 0; i < ids.length - 1; i++) {
      service.toggle(ids[i]);
    }
    expect(service.isComplete()).toBe(false);
    service.toggle(ids[ids.length - 1]);
    expect(service.isComplete()).toBe(true);
  });

  it('seeds include daysBeforeMoveIn metadata covering pre- and post-move tasks', () => {
    const days = service.tasks().map(t => t.daysBeforeMoveIn);
    expect(days.some(d => d > 0)).toBe(true);   // pre-move
    expect(days.some(d => d === 0)).toBe(true); // move day
