        expect(() => svc.toggleChannel(c, ch)).not.toThrow();
      }
    }
    expect(svc.prefs().length).toBe(8);
  });
});

import { TestBed } from '@angular/core/testing';
import {
  PropertyInspectionService,
  type CreateInspectionPayload,
  type RoomCondition,
} from './property-inspection.service';

describe('PropertyInspectionService', () => {
  let service: PropertyInspectionService;

  beforeEach(() => {
    TestBed.configureTestingModule({});
    service = TestBed.inject(PropertyInspectionService);
  });

  const samplePayload = (overrides: Partial<CreateInspectionPayload> = {}): CreateInspectionPayload => ({
    propertyId: 'prop-099',
    propertyTitle: 'Test Property',
    tenantId: 'tenant-099',
    landlordId: 'landlord-099',
    type: 'routine',
    scheduledDate: '2026-05-20',
    rooms: ['Living Room', 'Bedroom'],
    ...overrides,
  });

  it('seeds with two inspection reports', () => {
    expect(service.reports().length).toBe(2);
    expect(service.loading()).toBe(false);
    expect(service.error()).toBeNull();
  });

  it('completedReports buckets only "completed" and "signed" statuses', () => {
    const completed = service.completedReports();
    expect(completed.length).toBe(1);
    expect(completed[0].status).toBe('signed');
  });

  it('pendingReports buckets only "draft" and "in-progress" statuses', () => {
    const pending = service.pendingReports();
    expect(pending.length).toBe(1);
    expect(pending[0].status).toBe('in-progress');
  });

  it('create() prepends a draft with rooms mapped from name list', () => {
    const before = service.reports().length;
    const report = service.create(samplePayload());

    expect(service.reports().length).toBe(before + 1);
    expect(service.reports()[0].id).toBe(report.id);
    expect(report.id).toMatch(/^insp-\d+/);
    expect(report.status).toBe('draft');
    expect(report.rooms.length).toBe(2);
    expect(report.rooms[0]).toMatchObject({
      id: 'room-0',
      name: 'Living Room',
      condition: 'good',
      notes: '',
      photos: [],
    });
    expect(report.tenantSigned).toBe(false);
    expect(report.landlordSigned).toBe(false);
  });

  it('create() with an empty room list yields a draft with zero rooms', () => {
    const report = service.create(samplePayload({ rooms: [] }));
    expect(report.rooms).toEqual([]);
    expect(report.status).toBe('draft');
  });

  it('updateRoom() patches the named room and transitions draft → in-progress', () => {
    const report = service.create(samplePayload());
    service.updateRoom(report.id, 'room-0', {
      condition: 'fair',
      notes: 'Floor scuff near window',
    });

    const updated = service.reports().find(r => r.id === report.id)!;
    expect(updated.status).toBe('in-progress');
    const room = updated.rooms.find(r => r.id === 'room-0')!;
    expect(room.condition).toBe('fair');
    expect(room.notes).toBe('Floor scuff near window');
    // Other room untouched
    expect(updated.rooms.find(r => r.id === 'room-1')!.condition).toBe('good');
  });

  it('updateRoom() does not regress status once past draft', () => {
    // Seed report 'insp-001' is already signed
    service.updateRoom('insp-001', 'r1', { notes: 'Post-signature annotation' });
    const r = service.reports().find(x => x.id === 'insp-001')!;
    expect(r.status).toBe('signed');
    expect(r.rooms.find(rm => rm.id === 'r1')!.notes).toBe('Post-signature annotation');
  });

  it('updateRoom() on unknown report id is a no-op', () => {
    const before = service.reports();
    service.updateRoom('does-not-exist', 'r1', { notes: 'x' });
    expect(service.reports()).toEqual(before);
  });

  it('complete() stamps date + notes and sets status="completed"', () => {
    const report = service.create(samplePayload());
    service.complete(report.id, 'All rooms inspected, no issues.');

    const completed = service.reports().find(r => r.id === report.id)!;
    expect(completed.status).toBe('completed');
    expect(completed.inspectorNotes).toBe('All rooms inspected, no issues.');
    expect(completed.completedDate).toMatch(/^\d{4}-\d{2}-\d{2}$/);
    expect(completed.overallCondition).toBeDefined();
  });

  it('complete() derives overallCondition from the worst room across the report', () => {
    const report = service.create(samplePayload({ rooms: ['A', 'B', 'C'] }));
    // A=excellent, B=good, C=poor
    service.updateRoom(report.id, 'room-0', { condition: 'excellent' });
    service.updateRoom(report.id, 'room-1', { condition: 'good' });
    service.updateRoom(report.id, 'room-2', { condition: 'poor' });

    service.complete(report.id, 'Mixed condition');
    const completed = service.reports().find(r => r.id === report.id)!;
    expect(completed.overallCondition).toBe<RoomCondition>('poor');
  });

  it('complete() with all excellent rooms produces overallCondition="excellent"', () => {
    const report = service.create(samplePayload({ rooms: ['A', 'B'] }));
    service.updateRoom(report.id, 'room-0', { condition: 'excellent' });
    service.updateRoom(report.id, 'room-1', { condition: 'excellent' });
    service.complete(report.id, 'Pristine');
    const completed = service.reports().find(r => r.id === report.id)!;
    expect(completed.overallCondition).toBe<RoomCondition>('excellent');
  });

  it('sign() flips only the requested role flag without finalising', () => {
    const report = service.create(samplePayload());
    service.sign(report.id, 'tenant');
    const r = service.reports().find(x => x.id === report.id)!;
    expect(r.tenantSigned).toBe(true);
    expect(r.landlordSigned).toBe(false);
    expect(r.status).toBe('draft');
  });

  it('sign() by both roles promotes status to "signed"', () => {
    const report = service.create(samplePayload());
    service.complete(report.id, 'Done');
    service.sign(report.id, 'tenant');
    service.sign(report.id, 'landlord');

    const r = service.reports().find(x => x.id === report.id)!;
    expect(r.status).toBe('signed');
    expect(r.tenantSigned).toBe(true);
    expect(r.landlordSigned).toBe(true);

    // Now appears in completedReports
    expect(service.completedReports().some(x => x.id === report.id)).toBe(true);
    expect(service.pendingReports().some(x => x.id === report.id)).toBe(false);
  });

  it('sign() on unknown id is a no-op', () => {
    const before = service.reports();
    service.sign('does-not-exist', 'tenant');
    expect(service.reports()).toEqual(before);
  });

  it('seed insp-001 has dual signatures and reflects in completedReports', () => {
    const r = service.reports().find(x => x.id === 'insp-001')!;
    expect(r.tenantSigned).toBe(true);
    expect(r.landlordSigned).toBe(true);
    expect(r.status).toBe('signed');
  });
});

import { Injectable, signal, computed } from '@angular/core';

/** Categoria do item — usada para agrupar e direccionar deduções fiscais/caução. */
export type InventoryItemCategory =
  | 'furniture'        // sofá, cama, mesa, cadeiras, armários
  | 'appliance'        // frigorífico, máquina lavar, forno, micro-ondas
  | 'electronics'      // televisão, router, aspirador
  | 'kitchenware'      // tachos, talheres, pratos, copos
  | 'textiles'         // cortinas, alcatifa, almofadas
  | 'fixture';         // candeeiros, suportes, persianas

/** Estado de cada item registado. */
export type InventoryItemCondition = 'new' | 'good' | 'fair' | 'worn' | 'damaged' | 'missing';

/**
 * Item itemizado do inventário (recheio) do imóvel.
 *
 * Um item é registado no move-in com uma condição inicial e revisitado no
 * move-out — a delta entre as duas condições alimenta directamente o
 * `DepositReturnEstimator` para deduções por danos legítimos versus desgaste
 * normal (NRAU art. 5.º responsabilidade por danos).
 */
export interface InventoryItem {
  /** Identificador estável. */
  readonly id: string;
  /** Etiqueta humana ("Frigorífico Bosch KGN"). */
  readonly label: string;
  /** Local do imóvel onde o item se encontra ("Cozinha", "Sala", etc.). */
  readonly room: string;
  /** Categoria do item. */
  readonly category: InventoryItemCategory;
  /** Quantidade (ex: 4 cadeiras, 2 candeeiros). */
  readonly quantity: number;
  /** Condição registada na vistoria de entrada. */
  readonly conditionAtMoveIn: InventoryItemCondition;
  /** Condição na vistoria de saída — undefined antes de move-out. */
  readonly conditionAtMoveOut?: InventoryItemCondition;
  /** Custo de substituição estimado, em euros (usado para cálculo de retenção). */
  readonly replacementCostEur: number;
  /** Notas adicionais (manchas, riscos, modelo). */
  readonly notes?: string;
}

/** Severidade derivada do par (entrada → saída). */
export type ConditionDeltaSeverity = 'unchanged' | 'wear' | 'damage' | 'loss';

/** Linha agregada por sala — útil para a UI agrupar visualmente. */
export interface InventoryRoomGroup {
  readonly room: string;
  readonly items: ReadonlyArray<InventoryItem>;
  readonly totalReplacementCost: number;
}

/** Linha de delta por item após move-out. */
export interface InventoryDeltaLine {
  readonly item: InventoryItem;
  readonly severity: ConditionDeltaSeverity;
  /** Custo retido sugerido (0 para wear & tear; replacement total para loss). */
  readonly suggestedDeduction: number;
}

/** Ranking ordinal das condições — quanto maior, pior. */
const CONDITION_RANK: Record<InventoryItemCondition, number> = {
  new: 0,
  good: 1,
  fair: 2,
  worn: 3,
  damaged: 4,
  missing: 5,
};

let __invSeq = 0;
const nextId = () => `inv-${++__invSeq}-${Date.now().toString(36)}`;

/**
 * Default seed — apartamento PT mobilado típico (T2 com cozinha equipada).
 * Permite à UI ter algo a mostrar imediatamente sem onboarding.
 */
const DEFAULT_ITEMS: ReadonlyArray<InventoryItem> = [
  { id: 'i-frigo',     label: 'Frigorífico Bosch KGN',          room: 'Cozinha', category: 'appliance',   quantity: 1, conditionAtMoveIn: 'good', replacementCostEur: 850 },
  { id: 'i-fogao',     label: 'Fogão indução Teka 4 zonas',     room: 'Cozinha', category: 'appliance',   quantity: 1, conditionAtMoveIn: 'good', replacementCostEur: 480 },
  { id: 'i-maq-louca', label: 'Máquina lavar loiça AEG',        room: 'Cozinha', category: 'appliance',   quantity: 1, conditionAtMoveIn: 'fair', replacementCostEur: 520 },
  { id: 'i-microondas', label: 'Micro-ondas LG',                room: 'Cozinha', category: 'appliance',   quantity: 1, conditionAtMoveIn: 'good', replacementCostEur: 110 },
  { id: 'i-loica',     label: 'Conjunto loiça (12 peças)',      room: 'Cozinha', category: 'kitchenware', quantity: 12, conditionAtMoveIn: 'good', replacementCostEur: 80 },
  { id: 'i-talheres',  label: 'Talheres (set 24)',              room: 'Cozinha', category: 'kitchenware', quantity: 24, conditionAtMoveIn: 'good', replacementCostEur: 45 },
  { id: 'i-sofa',      label: 'Sofá 3 lugares cinza IKEA',      room: 'Sala',    category: 'furniture',   quantity: 1, conditionAtMoveIn: 'good', replacementCostEur: 600 },
  { id: 'i-tv',        label: 'Televisão LG 50"',                room: 'Sala',    category: 'electronics', quantity: 1, conditionAtMoveIn: 'good', replacementCostEur: 450 },
  { id: 'i-mesa-jantar', label: 'Mesa de jantar carvalho 6 lug.', room: 'Sala',  category: 'furniture',   quantity: 1, conditionAtMoveIn: 'good', replacementCostEur: 350 },
  { id: 'i-cadeiras',  label: 'Cadeiras (set 6)',                room: 'Sala',    category: 'furniture',   quantity: 6, conditionAtMoveIn: 'good', replacementCostEur: 210 },
  { id: 'i-cama-prin', label: 'Cama queen-size c/ colchão',     room: 'Quarto principal', category: 'furniture', quantity: 1, conditionAtMoveIn: 'good', replacementCostEur: 700 },
  { id: 'i-armario-prin', label: 'Armário 3 portas c/ espelho', room: 'Quarto principal', category: 'furniture', quantity: 1, conditionAtMoveIn: 'good', replacementCostEur: 420 },
  { id: 'i-cama-sec',  label: 'Cama solteiro c/ colchão',       room: 'Quarto secundário', category: 'furniture', quantity: 1, conditionAtMoveIn: 'fair', replacementCostEur: 380 },
  { id: 'i-cortinas',  label: 'Cortinas + varões (3 conjuntos)', room: 'Geral',  category: 'textiles',    quantity: 3, conditionAtMoveIn: 'good', replacementCostEur: 180 },
  { id: 'i-router',    label: 'Router MEO Smart',                room: 'Sala',   category: 'electronics', quantity: 1, conditionAtMoveIn: 'good', replacementCostEur: 60 },
];

/**
 * Calcula a severidade da delta entre duas condições.
 * - inalterado / melhorado → 'unchanged'
 * - desce 1 nível (ex: good → fair) → 'wear' (desgaste normal, não dedutível)
 * - desce 2+ níveis → 'damage' (dedutível parcialmente)
 * - 'missing' no move-out → 'loss' (custo total de reposição)
 */
export function classifyDelta(
  before: InventoryItemCondition,
  after: InventoryItemCondition,
): ConditionDeltaSeverity {
  if (after === 'missing') return 'loss';
  const drop = CONDITION_RANK[after] - CONDITION_RANK[before];
  if (drop <= 0) return 'unchanged';
  if (drop === 1) return 'wear';
  return 'damage';
}

/**
 * Heurística de retenção sugerida com base na severidade.
 * - unchanged / wear → 0 (desgaste normal não retém caução, NRAU art. 5.º)
 * - damage → 50% do custo de reposição (estimativa pragmática)
 * - loss → 100% do custo de reposição
 */
export function suggestedDeduction(
  item: InventoryItem,
  severity: ConditionDeltaSeverity,
): number {
  if (severity === 'loss') return round2(item.replacementCostEur * item.quantity);
  if (severity === 'damage') return round2(item.replacementCostEur * 0.5);
  return 0;
}

/**
 * State + computeds para o registo de inventário (recheio) do imóvel.
 *
 * Liga o triângulo `PropertyInspection` (vistoria) → `PropertyInventory`
 * (descritivo do recheio) → `DepositReturnEstimator` (retenção fundamentada).
 * NRAU art. 5.º exige descritivo prévio para defender deduções; este service
 * fornece esse descritivo + delta automatizada move-in → move-out.
 *
 * Sem RxJS — pure signals.
 */
@Injectable({ providedIn: 'root' })
export class PropertyInventoryService {
  private readonly _items = signal<InventoryItem[]>(
    DEFAULT_ITEMS.map(i => ({ ...i })),
  );

  /** Lista completa de items (read-only). */
  readonly items = this._items.asReadonly();

  /** Total agregado de items distintos. */
  readonly totalItems = computed(() => this._items().length);

  /** Soma de unidades (Σ quantity). */
  readonly totalUnits = computed(() =>
    this._items().reduce((acc, it) => acc + Math.max(0, it.quantity), 0),
  );

  /** Custo total de reposição (Σ replacementCost × quantity). */
  readonly totalReplacementCost = computed(() =>
    round2(this._items().reduce((acc, it) =>
      acc + Math.max(0, it.replacementCostEur) * Math.max(0, it.quantity), 0)),
  );

  /** Items agrupados por sala, ordenados pela ordem de inserção. */
  readonly byRoom = computed<ReadonlyArray<InventoryRoomGroup>>(() => {
    const map = new Map<string, InventoryItem[]>();
    for (const it of this._items()) {
      const arr = map.get(it.room) ?? [];
      arr.push(it);
      map.set(it.room, arr);
    }
    const groups: InventoryRoomGroup[] = [];
    for (const [room, items] of map) {
      const totalReplacementCost = round2(
        items.reduce((acc, it) =>
          acc + Math.max(0, it.replacementCostEur) * Math.max(0, it.quantity), 0),
      );
      groups.push({ room, items, totalReplacementCost });
    }
    return groups;
  });

  /** Quantos items já têm condição registada no move-out. */
  readonly inspectedAtMoveOut = computed(() =>
    this._items().filter(i => i.conditionAtMoveOut !== undefined).length,
  );

  /** Percentagem inspeccionada no move-out (0..100). */
  readonly moveOutInspectionPct = computed(() => {
    const total = this.totalItems();
    return total === 0 ? 0 : Math.round((this.inspectedAtMoveOut() / total) * 100);
  });

  /** Linhas de delta para items com condição registada no move-out. */
  readonly deltaLines = computed<ReadonlyArray<InventoryDeltaLine>>(() =>
    this._items()
      .filter(i => i.conditionAtMoveOut !== undefined)
      .map(item => {
        const severity = classifyDelta(item.conditionAtMoveIn, item.conditionAtMoveOut!);
        return {
          item,
          severity,
          suggestedDeduction: suggestedDeduction(item, severity),
        };
      }),
  );

  /** Soma da retenção sugerida — alimenta directamente o DepositReturnEstimator. */
  readonly totalSuggestedDeduction = computed(() =>
    round2(this.deltaLines().reduce((acc, l) => acc + l.suggestedDeduction, 0)),
  );

  /** Adiciona um novo item ao inventário. */
  addItem(input: {
    label: string;
    room: string;
    category: InventoryItemCategory;
    quantity: number;
    conditionAtMoveIn: InventoryItemCondition;
    replacementCostEur: number;
    notes?: string;
  }): void {
    const item: InventoryItem = {
      id: nextId(),
      label: input.label.trim() || 'Sem descrição',
      room: input.room.trim() || 'Geral',
      category: input.category,
      quantity: safePositiveInt(input.quantity),
      conditionAtMoveIn: input.conditionAtMoveIn,
      replacementCostEur: safeNum(input.replacementCostEur),
      notes: input.notes?.trim() || undefined,
    };
    this._items.update(list => [...list, item]);
  }

  /** Remove um item do inventário. */
  removeItem(id: string): void {
    this._items.update(list => list.filter(i => i.id !== id));
  }

  /** Marca a condição do item no momento do move-out. */
  setMoveOutCondition(id: string, condition: InventoryItemCondition): void {
    this._items.update(list =>
      list.map(i => i.id === id ? { ...i, conditionAtMoveOut: condition } : i),
    );
  }

  /** Limpa apenas as condições de saída (mantém os items). */
  clearMoveOutConditions(): void {
    this._items.update(list =>
      list.map(i => ({
        id: i.id,
        label: i.label,
        room: i.room,
        category: i.category,
        quantity: i.quantity,
        conditionAtMoveIn: i.conditionAtMoveIn,
        replacementCostEur: i.replacementCostEur,
        notes: i.notes,
      })),
    );
  }

  /** Reset total — volta ao seed inicial. */
  resetAll(): void {
    this._items.set(DEFAULT_ITEMS.map(i => ({ ...i })));
  }

  /** Substitui completamente a lista (útil para integração com PropertyInspection). */
  setItems(list: ReadonlyArray<InventoryItem>): void {
    this._items.set(list.map(i => ({ ...i })));
  }
}

function safeNum(v: number): number {
  return Number.isFinite(v) && v >= 0 ? v : 0;
}

function safePositiveInt(v: number): number {
  if (!Number.isFinite(v) || v <= 0) return 1;
  return Math.floor(v);
}

function round2(n: number): number {
  return Math.round(n * 100) / 100;
}

import { TestBed } from '@angular/core/testing';
import { RentArrearsService, type ArrearsRecord } from './rent-arrears.service';

describe('RentArrearsService', () => {
  let service: RentArrearsService;

  beforeEach(() => {
    TestBed.configureTestingModule({});
    service = TestBed.inject(RentArrearsService);
  });

  it('seeds with the 4 mock arrears records (1 legal, 1 plan, 1 reminder, 1 partial)', () => {
    expect(service.records().length).toBe(4);
    const statuses = service.records().map(r => r.status);
    expect(statuses).toEqual(expect.arrayContaining(['legal', 'payment_plan', 'reminder_sent', 'partial']));
  });

  it('kpis aggregate total outstanding across non-resolved records', () => {
    const expected = service.records()
      .filter(r => r.status !== 'resolved')
      .reduce((s, r) => s + r.amountOutstanding, 0);
    expect(service.kpis().totalOutstanding).toBe(expected);
  });

  it('kpis.critical counts legal status OR daysOverdue > 60', () => {
    const expected = service.records().filter(
      r => r.status !== 'resolved' && (r.status === 'legal' || r.daysOverdue > 60),
    ).length;
    expect(service.kpis().critical).toBe(expected);
  });

  it('kpis.avgDaysOverdue is rounded mean of non-resolved days overdue', () => {
    const open = service.records().filter(r => r.status !== 'resolved');
    const avg = Math.round(open.reduce((s, r) => s + r.daysOverdue, 0) / open.length);
    expect(service.kpis().avgDaysOverdue).toBe(avg);
  });

  it('filtered defaults to all records when filter is "all"', () => {
    expect(service.filtered().length).toBe(service.records().length);
    service.setFilter('legal');
    expect(service.filtered().every(r => r.status === 'legal')).toBe(true);
  });

  it('sendReminder bumps count, updates status to reminder_sent, sets today ISO date', () => {
    const before = service.records().find(r => r.id === 'ar003')!;
    service.sendReminder('ar003');
    const after = service.records().find(r => r.id === 'ar003')!;
    expect(after.reminderCount).toBe(before.reminderCount + 1);
    expect(after.status).toBe('reminder_sent');
    expect(after.lastReminderSent).toBe(new Date().toISOString().split('T')[0]);
  });

  it('setPaymentPlan flips status + activates plan + stores monthly amount', () => {
    service.setPaymentPlan('ar001', 600);
    const r = service.records().find(rec => rec.id === 'ar001')!;
    expect(r.status).toBe('payment_plan');
    expect(r.paymentPlanActive).toBe(true);
    expect(r.paymentPlanMonthly).toBe(600);
  });

  it('escalateToLegal sets status to legal without touching amounts', () => {
    const before = service.records().find(r => r.id === 'ar001')!;
    service.escalateToLegal('ar001');
    const after = service.records().find(r => r.id === 'ar001')!;
    expect(after.status).toBe('legal');
    expect(after.amountOutstanding).toBe(before.amountOutstanding);
  });

  it('markResolved zeroes outstanding and credits the full due amount', () => {
    const before = service.records().find(r => r.id === 'ar003')!;
    service.markResolved('ar003');
    const after = service.records().find(r => r.id === 'ar003')!;
    expect(after.status).toBe('resolved');
    expect(after.amountOutstanding).toBe(0);
    expect(after.amountPaid).toBe(before.amountDue);
  });

  it('resolved records drop out of kpis (open arrears only)', () => {
    const before = service.kpis().totalTenants;
    service.markResolved('ar001');
    expect(service.kpis().totalTenants).toBe(before - 1);
  });

  it('severity buckets: legal/>90 critical, >60 high, >30 medium, ≤30 low', () => {
    const make = (over: ArrearsRecord) => service.severity(over);
    const legal: ArrearsRecord = { ...service.records()[0], status: 'legal', daysOverdue: 10 };
    const critical: ArrearsRecord = { ...service.records()[0], status: 'overdue', daysOverdue: 100 };
    const high: ArrearsRecord = { ...service.records()[0], status: 'overdue', daysOverdue: 75 };
    const medium: ArrearsRecord = { ...service.records()[0], status: 'overdue', daysOverdue: 45 };
    const low: ArrearsRecord = { ...service.records()[0], status: 'overdue', daysOverdue: 10 };
    expect(make(legal)).toBe('critical');
    expect(make(critical)).toBe('critical');
    expect(make(high)).toBe('high');
    expect(make(medium)).toBe('medium');
    expect(make(low)).toBe('low');
  });

  it('unknown record ids are no-ops across mutations', () => {
    const snapshot = service.records();
    service.sendReminder('zzz');
    service.setPaymentPlan('zzz', 100);
    service.escalateToLegal('zzz');
    service.markResolved('zzz');
    expect(service.records()).toEqual(snapshot);
  });
});

import { TestBed } from '@angular/core/testing';
import { RentPaymentPortalService } from './rent-payment-portal.service';

describe('RentPaymentPortalService', () => {
  let service: RentPaymentPortalService;

  beforeEach(() => {
    TestBed.configureTestingModule({});
    service = TestBed.inject(RentPaymentPortalService);
  });

  it('seeds with 6 payment records spanning 3 paid + 2 pending + 1 overdue', () => {
    expect(service.payments().length).toBe(6);
    const byStatus = service.payments().reduce<Record<string, number>>((acc, p) => {
      acc[p.status] = (acc[p.status] ?? 0) + 1;
      return acc;
    }, {});
    expect(byStatus.paid).toBe(3);
    expect(byStatus.pending).toBe(2);
    expect(byStatus.overdue).toBe(1);
  });

  it('outstanding includes both pending and overdue (3 records in seed)', () => {
    expect(service.outstanding().length).toBe(3);
    expect(service.outstanding().every(p => p.status === 'pending' || p.status === 'overdue')).toBe(true);
  });

  it('paidPayments filters to status="paid" only (3 records in seed)', () => {
    expect(service.paidPayments().length).toBe(3);
    expect(service.paidPayments().every(p => p.status === 'paid')).toBe(true);
  });

  it('paymentStreak equals the number of paid payments', () => {
    expect(service.paymentStreak()).toBe(3);
  });

  it('totalOutstanding sums (amount − paidAmount) across pending+overdue', () => {
    // Seed: rp-004 pending 1200, rp-005 overdue 850, rp-006 pending 850 → total 2900
    expect(service.totalOutstanding()).toBe(2900);
  });

  it('totalPaidThisYear sums paid amounts whose paidDate begins with the current year', () => {
    const year = new Date().getFullYear().toString();
    const expected = service.paidPayments()
      .filter(p => (p.paidDate ?? '').startsWith(year))
      .reduce((s, p) => s + (p.paidAmount ?? p.amount), 0);
    expect(service.totalPaidThisYear()).toBe(expected);
  });

  it('nextDueDate returns the outstanding payment with the earliest dueDate', () => {
    // Seed earliest outstanding dueDate: 2026-03-05 (rp-005 overdue)
    const next = service.nextDueDate();
    expect(next?.id).toBe('rp-005');
    expect(next?.dueDate).toBe('2026-03-05');
  });

  it('nextDueDate returns null when there are no outstanding payments', () => {
    // Mark every outstanding as paid
    service.outstanding().forEach(p => service.markPaid(p.id));
    expect(service.nextDueDate()).toBeNull();
  });

  it('makePayment full amount transitions the entry to paid with paidDate + receiptId', () => {
    const target = service.outstanding()[0];
    service.makePayment(target.id, target.amount);
    const updated = service.payments().find(p => p.id === target.id);
    expect(updated?.status).toBe('paid');
    expect(updated?.paidAmount).toBe(target.amount);
    expect(updated?.paidDate).toBeDefined();
    expect(updated?.receiptId).toMatch(/^rcpt-\d+$/);
  });

  it('makePayment with partial amount transitions to status="partial"', () => {
    const target = service.outstanding().find(p => p.amount === 1200);
    expect(target).toBeDefined();
    service.makePayment(target!.id, 600);
    const updated = service.payments().find(p => p.id === target!.id);
    expect(updated?.status).toBe('partial');
    expect(updated?.paidAmount).toBe(600);
  });

  it('markPaid is equivalent to makePayment(id, fullAmount)', () => {
    const target = service.outstanding()[0];
    service.markPaid(target.id);
    const updated = service.payments().find(p => p.id === target.id);
    expect(updated?.status).toBe('paid');
    expect(updated?.paidAmount).toBe(target.amount);
  });

  it('markPaid on unknown id is a silent no-op', () => {
    const before = service.payments();
    service.markPaid('not-a-real-id');
    expect(service.payments()).toEqual(before);
  });

  it('loadForTenant flips loading on, then off, and narrows payments to that tenant', () => {
    jest.useFakeTimers();
    try {
      service.loadForTenant('tenant-002');
      expect(service.loading()).toBe(true);
      jest.advanceTimersByTime(300);
      expect(service.loading()).toBe(false);
      expect(service.payments().every(p => p.tenantId === 'tenant-002')).toBe(true);
    } finally {
      jest.useRealTimers();
    }
  });

  it('loadForLandlord narrows payments to that landlord scope', () => {
    jest.useFakeTimers();
    try {
      service.loadForLandlord('landlord-001');
      jest.advanceTimersByTime(300);
      expect(service.payments().every(p => p.landlordId === 'landlord-001')).toBe(true);
    } finally {
      jest.useRealTimers();
    }
  });
});

/**
 * @fileoverview resource() API service utility — Sprint 027 / Sprint 031
 *
 * Wraps Angular's `resource()` / `httpResource()` APIs with common patterns
 * for error handling, loading states, and retry logic.
 *
 * Uses Angular 21's signal-based resource APIs (no RxJS).
 *
 * Sprint 031 additions (RESOURCE_SNAPSHOT flag):
 * - `ResourceSnapshot<T>` — unified frozen-state type (preserves last data across reloads)
 * - `snapshot` field on `ResourceState<T>` — exposes current state as a snapshot signal
 * - `resourceFromSnapshots<T>()` — compose multiple snapshot signals into one derived resource
 *
 * @example
 * ```ts
 * // Simple HTTP resource
 * readonly properties = createHttpResource<Property[]>(
 *   () => `/api/properties?city=${this.city()}`
 * );
 *
 * // In template
 * @if (properties.loading()) { <iu-progress /> }
 * @if (properties.error()) { <p>Error: {{ properties.error() }}</p> }
 * @for (p of properties.data(); track p.id) { ... }
 *
 * // Snapshot — data is preserved during reloads (no flicker)
 * @if (properties.snapshot().isLoading) { <iu-progress /> }
 * {{ properties.snapshot().data | json }}
 * ```
 */

import {
  Signal,
  signal,
  computed,
  isSignal,
  resource,
  ResourceRef,
  inject,
  type WritableSignal,
} from '@angular/core';
import { HttpClient, HttpErrorResponse } from '@angular/common/http';
import { lastValueFrom } from 'rxjs';

// ─── Types ────────────────────────────────────────────────────────────────────

/** Status of a resource fetch lifecycle */
export type ResourceStatus = 'idle' | 'loading' | 'success' | 'error';

/**
 * ResourceSnapshot<T> — Sprint 031 (RESOURCE_SNAPSHOT)
 *
 * A frozen point-in-time view of the resource state. Unlike `data` (which goes
 * `undefined` during a reload), `snapshot.data` is preserved across refreshes —
 * enabling flicker-free UIs that show stale data while fresh data loads.
 *
 * Mirrors Angular 21.2's `resource.snapshot()` concept.
 *
 * @example
 * ```ts
 * // No flicker: last known data stays visible while refreshing
 * readonly snap = this.properties.snapshot;
 * // template:
 * @for (p of snap().data ?? []; track p.id) { ... }
 * @if (snap().isLoading) { <iu-progress /> }
 * ```
 */
export interface ResourceSnapshot<T> {
  /**
   * Last known data value.
   * Preserved across reloads — does NOT go `undefined` while loading.
   */
  readonly data: T | undefined;
  /** Lifecycle status of the most-recent fetch */
  readonly status: ResourceStatus;
  /** Last error, or `null` */
  readonly error: HttpErrorResponse | Error | null;
  /** Whether a fetch is currently in progress */
  readonly isLoading: boolean;
  /** Unix timestamp (ms) when this snapshot was captured */
  readonly timestamp: number;
}

/**
 * Unified state shape returned by createHttpResource.
 * All fields are signals for reactive template consumption.
 */
export interface ResourceState<T> {
  /** The fetched data (undefined before first successful load) */
  readonly data: Signal<T | undefined>;
  /** True while a fetch is in-flight */
  readonly loading: Signal<boolean>;
  /** The last error, or null if no error */
  readonly error: Signal<HttpErrorResponse | Error | null>;
  /** Lifecycle status string */
  readonly status: Signal<ResourceStatus>;
  /**
   * Snapshot signal — exposes all resource state in one unified object.
   * The `data` field is preserved across reloads (no flicker).
   * Sprint 031 — RESOURCE_SNAPSHOT.
   */
  readonly snapshot: Signal<ResourceSnapshot<T>>;
  /** Trigger a manual reload */
  reload: () => void;
}

/** Options for createHttpResource */
export interface CreateHttpResourceOptions<T> {
  /**
   * Transform the raw response before storing.
   * @param raw - raw HTTP response body
   */
  transform?: (raw: unknown) => T;

  /**
   * Number of automatic retry attempts on error.
   * Defaults to 0 (no retry).
   */
  retries?: number;

  /**
   * Initial/default value before the first load completes.
   */
  defaultValue?: T;
}

// ─── Implementation ───────────────────────────────────────────────────────────

/**
 * Creates a signal-based HTTP resource that automatically fetches data
 * whenever the URL signal changes.
 *
 * Built on Angular's `resource()` API — no RxJS required.
 *
 * @param urlOrSignal - A static URL string or a Signal/function returning a URL.
 *   When provided as a Signal or function, the resource re-fetches whenever
 *   the value changes.
 * @param options - Optional configuration (transform, retries, defaultValue)
 * @returns ResourceState with reactive signals for data, loading, error, status, snapshot
 *
 * @example
 * ```ts
 * // Static URL
 * const users = createHttpResource<User[]>('/api/users');
 *
 * // Reactive URL (re-fetches on city change)
 * const city = signal('Lisbon');
 * const properties = createHttpResource<Property[]>(
 *   () => `/api/properties?city=${city()}`
 * );
 *
 * // Snapshot — last known data preserved during reloads
 * const snap = properties.snapshot;
 * // template: @if (snap().isLoading) { <iu-progress /> }
 * ```
 */
export function createHttpResource<T>(
  urlOrSignal: Signal<string> | (() => string) | string,
  options: CreateHttpResourceOptions<T> = {}
): ResourceState<T> {
  const http = inject(HttpClient);
  const { transform, retries = 0, defaultValue } = options;

  // Normalise to a plain function so Angular resource() can track it
  const urlFn: () => string =
    typeof urlOrSignal === 'string'
      ? () => urlOrSignal
      : isSignal(urlOrSignal)
        ? () => (urlOrSignal as Signal<string>)()
        : (urlOrSignal as () => string);

  // Internal writeable signals for retry counter (forces re-read inside loader)
  const retryCounter: WritableSignal<number> = signal(0);

  // Angular resource() — loader runs reactively whenever URL or retryCounter changes
  const ref: ResourceRef<T | undefined> = resource<T | undefined, string>({
    params: () => {
      void retryCounter(); // track retryCounter so reload() works
      return urlFn();
    },
    loader: async ({ params: url }) => {
      let lastError: Error | null = null;
      const maxAttempts = retries + 1;

      for (let attempt = 0; attempt < maxAttempts; attempt++) {
        try {
          const raw = await lastValueFrom(
            http.get<unknown>(url)
          );
          return (transform ? transform(raw) : (raw as T));
        } catch (err) {
          lastError = err instanceof Error ? err : new Error(String(err));
          if (attempt < maxAttempts - 1) {
            // Simple exponential back-off: 200ms, 400ms, …
            await new Promise<void>((r) => setTimeout(r, 200 * Math.pow(2, attempt)));
          }
        }
      }
      throw lastError!;
    },
  });

  // Derived status signal
  const status = computed<ResourceStatus>(() => {
    if (ref.isLoading()) return 'loading';
    if (ref.error()) return 'error';
    if (ref.value() !== undefined) return 'success';
    return 'idle';
  });

  // Normalise error to a typed signal
  const error = computed<HttpErrorResponse | Error | null>(() => {
    const e = ref.error();
    if (!e) return null;
    return e instanceof HttpErrorResponse || e instanceof Error
      ? e
      : new Error(String(e));
  });

  const data = computed<T | undefined>(() => ref.value() ?? defaultValue);

  // ── Snapshot — Sprint 031 (RESOURCE_SNAPSHOT) ─────────────────────────────
  //
  // The `_lastData` writeable signal holds the most-recent successfully
  // fetched value. It is intentionally NOT cleared when a new fetch starts,
  // so snapshot.data stays visible during reloads (anti-flicker pattern).
  //
  const _lastData: WritableSignal<T | undefined> = signal(defaultValue);

  // Derived snapshot — merges all state into one object
  const snapshot = computed<ResourceSnapshot<T>>(() => {
    const currentData = ref.value();
    const currentStatus = status();
    const currentError = error();
    const isLoading = ref.isLoading();

    // Persist last known data when a new load is in progress
    if (currentData !== undefined) {
      // Note: computed() is read-only so we track via effect in the reload path;
      // here we derive from ref.value() directly — if it's defined, use it.
    }

    // The snapshot exposes the fresher of (current data, last known data).
    // We rely on the fact that ref.value() becomes undefined only while loading;
    // the _lastData signal is updated via the reload wrapper below.
    const snapshotData = currentData ?? _lastData();

    return {
      data: snapshotData,
      status: currentStatus,
      error: currentError,
      isLoading,
      timestamp: Date.now(),
    } satisfies ResourceSnapshot<T>;
  });

  // Reload wrapper — updates _lastData BEFORE triggering a new fetch,
  // so snapshot.data always has the previous value during the in-flight period.
  const reload = () => {
    const current = ref.value();
    if (current !== undefined) {
      _lastData.set(current);
    }
    retryCounter.update((n) => n + 1);
  };

  return {
    data,
    loading: ref.isLoading,
    error,
    status,
    snapshot,
    reload,
  };
}

// ─── resourceFromSnapshots ────────────────────────────────────────────────────

/**
 * resourceFromSnapshots — Sprint 031 (RESOURCE_SNAPSHOT)
 *
 * Composes multiple `ResourceSnapshot<T>` signals into a single derived
 * snapshot. Useful for merging parallel resource streams (e.g. combining
 * local cache + remote data) without losing intermediate state.
 *
 * The combined snapshot is `loading` if ANY source is loading.
 * The combined snapshot is `error` if ANY source errored (and none are loading).
 * Data is produced by the `merge` function (defaults to last non-undefined wins).
 *
 * @param snapshotSignals - Two or more snapshot signals to merge
 * @param merge - Custom merge function (receives all current snapshots, returns merged data)
 * @returns A derived `Signal<ResourceSnapshot<T>>` combining all sources
 *
 * @example
 * ```ts
 * // Merge remote + local-cache resources into one flicker-free stream
 * readonly combined = resourceFromSnapshots(
 *   [this.remoteAvail.snapshot, this.localCache.snapshot],
 *   (snaps) => snaps.find(s => s.status === 'success')?.data
 * );
 * // template: @if (combined().isLoading) { <iu-progress /> }
 * ```
 */
export function resourceFromSnapshots<T>(
  snapshotSignals: Signal<ResourceSnapshot<T>>[],
  merge?: (snapshots: ResourceSnapshot<T>[]) => T | undefined
): Signal<ResourceSnapshot<T>> {
  const defaultMerge = (snaps: ResourceSnapshot<T>[]): T | undefined => {
    // Last non-undefined data wins
    for (let i = snaps.length - 1; i >= 0; i--) {
      if (snaps[i].data !== undefined) return snaps[i].data;
    }
    return undefined;
  };

  const mergeFn = merge ?? defaultMerge;

  return computed<ResourceSnapshot<T>>(() => {
    const all = snapshotSignals.map(s => s());

    const isLoading = all.some(s => s.isLoading);
    const errors = all.map(s => s.error).filter((e): e is HttpErrorResponse | Error => e !== null);
    const firstError = errors[0] ?? null;

    let derivedStatus: ResourceStatus = 'idle';
    if (isLoading) {
      derivedStatus = 'loading';
    } else if (firstError) {
      derivedStatus = 'error';
    } else if (all.some(s => s.status === 'success')) {
      derivedStatus = 'success';
    }

    return {
      data: mergeFn(all),
      status: derivedStatus,
      error: firstError,
      isLoading,
      timestamp: Math.max(...all.map(s => s.timestamp)),
    } satisfies ResourceSnapshot<T>;
  });
}

import { TestBed } from '@angular/core/testing';
import { RevenueAnalyticsService } from './revenue-analytics.service';

describe('RevenueAnalyticsService', () => {
  let service: RevenueAnalyticsService;

  beforeEach(() => {
    TestBed.configureTestingModule({});
    service = TestBed.inject(RevenueAnalyticsService);
  });

  it('should be created', () => expect(service).toBeTruthy());

  it('starts with no analytics, not loading', () => {
    expect(service.analytics()).toBeNull();
    expect(service.loading()).toBe(false);
  });

  it('derived KPI/data/topProperties are null/empty before load', () => {
    expect(service.kpis()).toBeNull();
    expect(service.monthlyData()).toEqual([]);
    expect(service.topProperties()).toEqual([]);
    expect(service.bestMonth()).toBeNull();
    expect(service.currentMonth()).toBeNull();
    expect(service.previousMonth()).toBeNull();
  });

  it('load() flips loading to true synchronously, then back to false on completion', async () => {
    const promise = service.load();
    expect(service.loading()).toBe(true);
    await promise;
    expect(service.loading()).toBe(false);
  });

  it('load() populates analytics with kpis, monthlyData and topProperties', async () => {
    await service.load();
    const a = service.analytics();
    expect(a).not.toBeNull();
    expect(a!.kpis).toBeDefined();
    expect(a!.monthlyData).toHaveLength(12);
    expect(a!.topProperties).toHaveLength(3);
    expect(typeof a!.lastUpdated).toBe('string');
  });

  it('kpis aggregates monthly data correctly (totals + currency)', async () => {
    await service.load();
    const kpis = service.kpis()!;
    expect(kpis.currency).toBe('EUR');

    const monthly = service.monthlyData();
    const expectedRevenue = monthly.reduce((s, m) => s + m.revenue, 0);
    const expectedExpenses = monthly.reduce((s, m) => s + m.expenses, 0);
    const expectedBookings = monthly.reduce((s, m) => s + m.bookings, 0);

    expect(kpis.totalRevenueTtm).toBe(expectedRevenue);
    expect(kpis.totalExpensesTtm).toBe(expectedExpenses);
    expect(kpis.netProfitTtm).toBe(expectedRevenue - expectedExpenses);
    expect(kpis.totalBookingsTtm).toBe(expectedBookings);
  });

  it('mrr equals last month revenue and ARR = mrr * 12', async () => {
    await service.load();
    const monthly = service.monthlyData();
    const kpis = service.kpis()!;
    expect(kpis.mrr).toBe(monthly[monthly.length - 1].revenue);
    expect(kpis.arrProjected).toBe(kpis.mrr * 12);
  });

  it('growthMoM is computed from last two monthly revenue values', async () => {
    await service.load();
    const monthly = service.monthlyData();
    const last = monthly[monthly.length - 1].revenue;
    const prev = monthly[monthly.length - 2].revenue;
    const expected = +(((last - prev) / prev) * 100).toFixed(1);
    expect(service.kpis()!.growthMoM).toBe(expected);
  });

  it('avgOccupancyRate is the rounded mean of monthly occupancyRate', async () => {
    await service.load();
    const monthly = service.monthlyData();
    const expectedAvg = Math.round(
      monthly.reduce((s, m) => s + m.occupancyRate, 0) / monthly.length
    );
    expect(service.kpis()!.avgOccupancyRate).toBe(expectedAvg);
  });

  it('bestMonth returns the month with the highest net profit', async () => {
    await service.load();
    const monthly = service.monthlyData();
    const expectedBest = monthly.reduce((best, m) => (m.net > best.net ? m : best));
    expect(service.bestMonth()).toEqual(expectedBest);
  });

  it('currentMonth equals last entry of monthlyData', async () => {
    await service.load();
    const monthly = service.monthlyData();
    expect(service.currentMonth()).toEqual(monthly[monthly.length - 1]);
  });

  it('previousMonth equals second-to-last entry of monthlyData', async () => {
    await service.load();
    const monthly = service.monthlyData();
    expect(service.previousMonth()).toEqual(monthly[monthly.length - 2]);
  });

  it('topProperties returns at least one property with a known trend value', async () => {
    await service.load();
    const tops = service.topProperties();
    expect(tops.length).toBeGreaterThan(0);
    for (const p of tops) {
      expect(['up', 'down', 'flat']).toContain(p.trend);
      expect(p.totalRevenue).toBeGreaterThanOrEqual(0);
      expect(p.occupancyRate).toBeGreaterThanOrEqual(0);
      expect(p.occupancyRate).toBeLessThanOrEqual(100);
    }
  });

  it('formatAmount returns a pt-PT currency string defaulting to EUR', () => {
    const formatted = service.formatAmount(1500);
    expect(formatted).toMatch(/1.?500/);
    expect(formatted).toContain('€');
  });

  it('formatAmount respects a custom currency argument', () => {
    const formatted = service.formatAmount(1500, 'USD');
    expect(formatted).toMatch(/US\$|\$/);
  });

  it('formatAmount drops fractional digits', () => {
    const formatted = service.formatAmount(1234.56);
    expect(formatted).not.toContain(',56');
    expect(formatted).not.toContain('.56');
  });

  it('reset() clears analytics back to null and unloading', async () => {
    await service.load();
    expect(service.analytics()).not.toBeNull();
    service.reset();
    expect(service.analytics()).toBeNull();
    expect(service.loading()).toBe(false);
    expect(service.kpis()).toBeNull();
  });

  it('reset() leaves derived month signals at their empty/null state', async () => {
    await service.load();
    service.reset();
    expect(service.monthlyData()).toEqual([]);
    expect(service.bestMonth()).toBeNull();
    expect(service.currentMonth()).toBeNull();
    expect(service.previousMonth()).toBeNull();
  });

  it('load() can be re-invoked and produces fresh analytics', async () => {
    await service.load('landlord-a');
    const first = service.analytics()!.lastUpdated;
    await new Promise(r => setTimeout(r, 5));
    await service.load('landlord-b');
    const second = service.analytics()!.lastUpdated;
    expect(second >= first).toBe(true);
  });
});

/**
 * @fileoverview RevenueAnalyticsService — Sprint 030
 *
 * Signal-based analytics service for landlord revenue data.
 * Provides computed signals for MRR, total bookings, occupancy rate, and top properties.
 * Companion to LANDLORD_ANALYTICS + PAYMENT_GATEWAY — aggregates transaction signals.
 *
 * Feature flag: LANDLORD_REVENUE
 */
import { Injectable, signal, computed } from '@angular/core';

// ─── Types ────────────────────────────────────────────────────────────────────

/** A single monthly revenue data point */
export interface MonthlyRevenue {
  month: string;   // e.g. 'Jan', 'Fev', 'Mar'
  year: number;
  revenue: number;
  expenses: number;
  net: number;
  bookings: number;
  occupancyRate: number; // 0-100
}

/** Per-property summary for the leaderboard */
export interface PropertyRevenueSummary {
  propertyId: string;
  propertyTitle: string;
  monthlyRent: number;
  totalRevenue: number;
  totalBookings: number;
  occupancyRate: number;
  trend: 'up' | 'down' | 'flat';
}

/** Top-level KPI snapshot */
export interface RevenueKPIs {
  mrr: number;             // Monthly Recurring Revenue (current month)
  arrProjected: number;    // Annualised Revenue Run Rate
  totalRevenueTtm: number; // Trailing 12 months
  totalExpensesTtm: number;
  netProfitTtm: number;
  totalBookingsTtm: number;
  avgOccupancyRate: number;
  growthMoM: number;       // Month-over-month growth %
  currency: string;
}

/** Complete analytics dataset for a landlord */
export interface LandlordAnalytics {
  kpis: RevenueKPIs;
  monthlyData: MonthlyRevenue[];
  topProperties: PropertyRevenueSummary[];
  lastUpdated: string;
}

// ─── Mock data helpers ────────────────────────────────────────────────────────

