// ─── Service ──────────────────────────────────────────────────────────────────

@Injectable({ providedIn: 'root' })
export class RevenueAnalyticsService {
  private readonly _analytics = signal<LandlordAnalytics | null>(null);
  private readonly _loading = signal(false);

  /** Whether analytics data is being loaded */
  readonly loading = this._loading.asReadonly();

  /** Raw analytics snapshot (null until loaded) */
  readonly analytics = this._analytics.asReadonly();

  /** KPIs — null if not loaded */
  readonly kpis = computed(() => this._analytics()?.kpis ?? null);

  /** Monthly revenue array (TTM) */
  readonly monthlyData = computed(() => this._analytics()?.monthlyData ?? []);

  /** Top properties by revenue */
  readonly topProperties = computed(() => this._analytics()?.topProperties ?? []);

  /** Best month by net profit */
  readonly bestMonth = computed(() => {
    const data = this.monthlyData();
    if (!data.length) return null;
    return data.reduce((best, m) => m.net > best.net ? m : best);
  });

  /** Current (latest) month */
  readonly currentMonth = computed(() => {
    const data = this.monthlyData();
    return data.length ? data[data.length - 1] : null;
  });

  /** Previous month (for MoM comparison) */
  readonly previousMonth = computed(() => {
    const data = this.monthlyData();
    return data.length >= 2 ? data[data.length - 2] : null;
  });

  /**
   * Load mock analytics data for a landlord.
   * In production: replace with createHttpResource() call.
   *
   * @param landlordId Used for future API integration
   */
  async load(landlordId = 'default'): Promise<void> {
    this._loading.set(true);
    // Simulate network delay
    await new Promise(r => setTimeout(r, 600));

    const monthly = buildMockMonthly();
    const properties = buildMockProperties();

    const totalRevenueTtm = monthly.reduce((s, m) => s + m.revenue, 0);
    const totalExpensesTtm = monthly.reduce((s, m) => s + m.expenses, 0);
    const totalBookingsTtm = monthly.reduce((s, m) => s + m.bookings, 0);
    const avgOccupancy = Math.round(monthly.reduce((s, m) => s + m.occupancyRate, 0) / monthly.length);
    const mrr = monthly[monthly.length - 1].revenue;
    const prevMrr = monthly[monthly.length - 2].revenue;
    const growthMoM = prevMrr > 0 ? +((mrr - prevMrr) / prevMrr * 100).toFixed(1) : 0;

    const kpis: RevenueKPIs = {
      mrr,
      arrProjected: mrr * 12,
      totalRevenueTtm,
      totalExpensesTtm,
      netProfitTtm: totalRevenueTtm - totalExpensesTtm,
      totalBookingsTtm,
      avgOccupancyRate: avgOccupancy,
      growthMoM,
      currency: 'EUR',
    };

    this._analytics.set({
      kpis,
      monthlyData: monthly,
      topProperties: properties,
      lastUpdated: new Date().toISOString(),
    });
    this._loading.set(false);
  }

  /**
   * Format currency using pt-PT locale.
   */
  formatAmount(amount: number, currency = 'EUR'): string {
    return new Intl.NumberFormat('pt-PT', { style: 'currency', currency, maximumFractionDigits: 0 }).format(amount);
  }

  /**
   * Reset analytics state.
   */
  reset(): void {
    this._analytics.set(null);
    this._loading.set(false);
  }
}

import { TestBed } from '@angular/core/testing';
import { SignatureStateService } from './signature-state.service';
import { LeaseAgreementService } from './lease-agreement.service';
import { NotificationBellService } from '../components/notification-bell/notification-bell.service';

describe('SignatureStateService', () => {
  let service: SignatureStateService;
  let leaseSvc: LeaseAgreementService;
  let notifSvc: NotificationBellService;

  beforeEach(() => {
    TestBed.resetTestingModule();
    TestBed.configureTestingModule({});
    service = TestBed.inject(SignatureStateService);
    leaseSvc = TestBed.inject(LeaseAgreementService);
    notifSvc = TestBed.inject(NotificationBellService);
  });

  // ─── Initial state ───────────────────────────────────────────────────────

  it('starts idle with no active flow', () => {
    expect(service.flow()).toBeNull();
    expect(service.state()).toBe('idle');
    expect(service.isActive()).toBe(false);
    expect(service.isCompleted()).toBe(false);
    expect(service.landlordSignature()).toBeNull();
    expect(service.tenantSignature()).toBeNull();
  });

  // ─── startFlow ───────────────────────────────────────────────────────────

  it('startFlow defaults to landlord initiator → landlord_pending', () => {
    service.startFlow('lease-001');
    expect(service.state()).toBe('landlord_pending');
    expect(service.isActive()).toBe(true);
    expect(service.flow()?.leaseId).toBe('lease-001');
  });

  it('startFlow with tenant initiator → tenant_pending', () => {
    service.startFlow('lease-002', 'tenant');
    expect(service.state()).toBe('tenant_pending');
  });

  it('startFlow clears any previous signatures', () => {
    service.startFlow('lease-001');
    service.captureSignature('landlord', 'data:image/png;base64,A', 'João');
    service.startFlow('lease-001');
    expect(service.landlordSignature()).toBeNull();
    expect(service.tenantSignature()).toBeNull();
    expect(service.flow()?.completedAt).toBeNull();
  });

  // ─── captureSignature ────────────────────────────────────────────────────

  it('captureSignature is a noop when no flow is active', () => {
    service.captureSignature('landlord', 'data:image/png;base64,A', 'João');
    expect(service.flow()).toBeNull();
    expect(service.state()).toBe('idle');
  });

  it('captureSignature(landlord) stores entry and advances to landlord_signed', () => {
    service.startFlow('lease-001');
    service.captureSignature('landlord', 'data:image/png;base64,A', 'João Senhorio');
    expect(service.state()).toBe('landlord_signed');
    const sig = service.landlordSignature();
    expect(sig?.role).toBe('landlord');
    expect(sig?.dataUrl).toBe('data:image/png;base64,A');
    expect(sig?.signerName).toBe('João Senhorio');
    expect(sig?.signedAt).toBeTruthy();
    expect(service.tenantSignature()).toBeNull();
  });

  it('captureSignature(landlord) pushes a tenant notification', () => {
    const before = notifSvc.notifications().length;
    service.startFlow('lease-001');
    service.captureSignature('landlord', 'data:image/png;base64,A', 'João');
    expect(notifSvc.notifications().length).toBe(before + 1);
    const latest = notifSvc.notifications()[0];
    expect(latest.category).toBe('alert');
    expect(latest.title).toContain('Pronto para Assinar');
    expect(latest.body).toContain('João');
    expect(latest.actionRoute).toBe('/lease');
  });

  it('captureSignature(tenant) alone does not push a notification', () => {
    service.startFlow('lease-002', 'tenant');
    const before = notifSvc.notifications().length;
    service.captureSignature('tenant', 'data:image/png;base64,B', 'Ana');
    expect(notifSvc.notifications().length).toBe(before);
    expect(service.state()).toBe('tenant_signed');
    expect(service.tenantSignature()?.signerName).toBe('Ana');
  });

  // ─── advanceToTenant ────────────────────────────────────────────────────

  it('advanceToTenant moves landlord_signed → tenant_pending', () => {
    service.startFlow('lease-001');
    service.captureSignature('landlord', 'data:image/png;base64,A', 'João');
    service.advanceToTenant();
    expect(service.state()).toBe('tenant_pending');
  });

  it('advanceToTenant is a noop when not in landlord_signed', () => {
    service.startFlow('lease-001');
    service.advanceToTenant();
    expect(service.state()).toBe('landlord_pending');
  });

  it('advanceToTenant is a noop when no flow is active', () => {
    service.advanceToTenant();
    expect(service.flow()).toBeNull();
  });

  // ─── Completion ──────────────────────────────────────────────────────────

  it('both signatures captured → state becomes completed with timestamp', () => {
    service.startFlow('lease-001');
    service.captureSignature('landlord', 'data:image/png;base64,A', 'João');
    service.advanceToTenant();
    service.captureSignature('tenant', 'data:image/png;base64,B', 'Ana');
    expect(service.state()).toBe('completed');
    expect(service.isCompleted()).toBe(true);
    expect(service.flow()?.completedAt).toBeTruthy();
  });

  it('completion marks lease as active via LeaseAgreementService', () => {
    service.startFlow('lease-002');
    expect(leaseSvc.getById('lease-002')?.status).toBe('draft');
    service.captureSignature('landlord', 'data:image/png;base64,A', 'João');
    service.captureSignature('tenant', 'data:image/png;base64,B', 'Ana');
    const lease = leaseSvc.getById('lease-002');
    expect(lease?.signedByLandlord).toBe(true);
    expect(lease?.signedByTenant).toBe(true);
    expect(lease?.status).toBe('active');
  });

  it('completion pushes a final "signed by both" notification', () => {
    service.startFlow('lease-001');
    service.captureSignature('landlord', 'data:image/png;base64,A', 'João');
    const after1 = notifSvc.notifications().length;
    service.captureSignature('tenant', 'data:image/png;base64,B', 'Ana');
    expect(notifSvc.notifications().length).toBe(after1 + 1);
    const latest = notifSvc.notifications()[0];
    expect(latest.category).toBe('alert');
    expect(latest.title).toContain('Ambas as Partes');
  });

  // ─── resetFlow ──────────────────────────────────────────────────────────

  it('resetFlow clears all state back to idle', () => {
    service.startFlow('lease-001');
    service.captureSignature('landlord', 'data:image/png;base64,A', 'João');
    service.resetFlow();
    expect(service.flow()).toBeNull();
    expect(service.state()).toBe('idle');
    expect(service.isActive()).toBe(false);
    expect(service.landlordSignature()).toBeNull();
  });

  it('resetFlow after completion still returns to idle', () => {
    service.startFlow('lease-001');
    service.captureSignature('landlord', 'data:image/png;base64,A', 'João');
    service.captureSignature('tenant', 'data:image/png;base64,B', 'Ana');
    expect(service.isCompleted()).toBe(true);
    service.resetFlow();
    expect(service.state()).toBe('idle');
    expect(service.isCompleted()).toBe(false);
  });

  // ─── Edge cases ─────────────────────────────────────────────────────────

  it('captureSignature is idempotent role-wise (re-signing landlord re-emits push)', () => {
    service.startFlow('lease-001');
    service.captureSignature('landlord', 'data:image/png;base64,A', 'João');
    const after1 = notifSvc.notifications().length;
    service.captureSignature('landlord', 'data:image/png;base64,AA', 'João');
    expect(notifSvc.notifications().length).toBe(after1 + 1);
    expect(service.landlordSignature()?.dataUrl).toBe('data:image/png;base64,AA');
  });

  it('signedAt is a valid ISO 8601 string', () => {
    service.startFlow('lease-001');
    service.captureSignature('landlord', 'data:image/png;base64,A', 'João');
    const signedAt = service.landlordSignature()!.signedAt;
    expect(new Date(signedAt).toISOString()).toBe(signedAt);
  });
});

import { TestBed } from '@angular/core/testing';
import {
  TenantApplicationService,
  type CreateApplicationPayload,
} from './tenant-application.service';

function basePayload(
  overrides: Partial<CreateApplicationPayload> = {},
): CreateApplicationPayload {
  return {
    tenantId: 'tenant-099',
    tenantName: 'New Tenant',
    tenantEmail: 'new.tenant@email.pt',
    tenantPhone: '+351 911 222 333',
    landlordId: 'landlord-005',
    propertyId: 'p9',
    propertyTitle: 'Test Property',
    employmentType: 'employed',
    monthlyIncome: 1800,
    employer: 'Test Co.',
    nif: '987654321',
    nationality: 'Portuguesa',
    occupation: 'Designer',
    numOccupants: 1,
    hasPets: false,
    coverLetter: 'Some cover letter',
    references: [],
    ...overrides,
  };
}

describe('TenantApplicationService', () => {
  let service: TenantApplicationService;

  beforeEach(() => {
    TestBed.configureTestingModule({});
    service = TestBed.inject(TenantApplicationService);
  });

  it('seeds with two mock applications', () => {
    const all = service.applications();
    expect(all.length).toBe(2);
    expect(all.map(a => a.id)).toEqual(['app-001', 'app-002']);
  });

  it('initial loading=false and error=null', () => {
    expect(service.loading()).toBe(false);
    expect(service.error()).toBeNull();
  });

  it('pendingReview computed includes submitted + under-review applications', () => {
    expect(service.pendingReview().map(a => a.id)).toEqual(['app-002']);
  });

  it('approved computed includes only status=approved applications', () => {
    expect(service.approved().map(a => a.id)).toEqual(['app-001']);
  });

  it('byStatus(status) returns matching applications', () => {
    const approved = service.byStatus('approved');
    const draft = service.byStatus('draft');
    expect(approved().map(a => a.id)).toEqual(['app-001']);
    expect(draft()).toEqual([]);
  });

  it('loadForTenant flips loading true synchronously then false after 300ms', () => {
    jest.useFakeTimers();
    try {
      service.loadForTenant('tenant-001');
      expect(service.loading()).toBe(true);
      jest.advanceTimersByTime(300);
      expect(service.loading()).toBe(false);
      expect(service.applications().every(a => a.tenantId === 'tenant-001')).toBe(true);
      expect(service.applications().length).toBe(2);
    } finally {
      jest.useRealTimers();
    }
  });

  it('loadForLandlord filters mock data to that landlord after timer flush', () => {
    jest.useFakeTimers();
    try {
      service.loadForLandlord('landlord-001');
      expect(service.loading()).toBe(true);
      jest.advanceTimersByTime(300);
      expect(service.loading()).toBe(false);
      expect(service.applications().every(a => a.landlordId === 'landlord-001')).toBe(true);
      expect(service.applications().length).toBe(1);
    } finally {
      jest.useRealTimers();
    }
  });

  it('loadForTenant with unknown id leaves applications empty after flush', () => {
    jest.useFakeTimers();
    try {
      service.loadForTenant('tenant-zzz');
      jest.advanceTimersByTime(300);
      expect(service.applications()).toEqual([]);
      expect(service.pendingReview()).toEqual([]);
      expect(service.approved()).toEqual([]);
    } finally {
      jest.useRealTimers();
    }
  });

  it('getById returns the application matching the id', () => {
    expect(service.getById('app-001')?.tenantName).toBe('Ana Ferreira');
    expect(service.getById('app-zzz')).toBeUndefined();
  });

  it('submit prepends a new submitted application with generated id + reference ids', () => {
    const before = service.applications().length;
    const created = service.submit(
      basePayload({
        references: [
          { name: 'Ref One', relationship: 'landlord', phone: '+351 999' },
        ],
      }),
    );
    const after = service.applications();
    expect(after.length).toBe(before + 1);
    expect(after[0]).toBe(created);
    expect(created.id).toMatch(/^app-/);
    expect(created.status).toBe('submitted');
    expect(created.references[0].id).toBeTruthy();
    expect(created.references[0].name).toBe('Ref One');
    expect(created.submittedAt).toBe(created.createdAt);
    expect(created.updatedAt).toBe(created.createdAt);
  });

  it('submit reflects new entry in pendingReview computed', () => {
    expect(service.pendingReview().length).toBe(1);
    service.submit(basePayload());
    expect(service.pendingReview().length).toBe(2);
  });

  it('approve mutates status + reviewNotes + reviewedAt for the targeted application', () => {
    const before = service.applications().find(a => a.id === 'app-002')!;
    service.approve('app-002', 'All checks passed');
    const after = service.applications().find(a => a.id === 'app-002')!;
    expect(after.status).toBe('approved');
    expect(after.reviewNotes).toBe('All checks passed');
    expect(after.reviewedAt).toBeTruthy();
    expect(after.updatedAt).not.toBe(before.updatedAt);
  });

  it('approve without notes leaves reviewNotes undefined', () => {
    service.approve('app-002');
    const r = service.applications().find(a => a.id === 'app-002')!;
    expect(r.status).toBe('approved');
    expect(r.reviewNotes).toBeUndefined();
  });

  it('reject mutates status + rejectionReason + reviewedAt', () => {
    service.reject('app-002', 'Income below threshold');
    const r = service.applications().find(a => a.id === 'app-002')!;
    expect(r.status).toBe('rejected');
    expect(r.rejectionReason).toBe('Income below threshold');
    expect(r.reviewedAt).toBeTruthy();
  });

  it('markUnderReview transitions status to under-review', () => {
    service.submit(basePayload());
    const newId = service.applications()[0].id;
    service.markUnderReview(newId);
    expect(service.applications().find(a => a.id === newId)!.status).toBe('under-review');
  });

  it('withdraw transitions status to withdrawn', () => {
    service.withdraw('app-002');
    expect(service.applications().find(a => a.id === 'app-002')!.status).toBe('withdrawn');
  });

  it('approve on unknown id is a no-op', () => {
    const before = service.applications();
    service.approve('app-zzz', 'note');
    expect(service.applications()).toEqual(before);
  });

  it('reject on unknown id is a no-op', () => {
    const before = service.applications();
    service.reject('app-zzz', 'reason');
    expect(service.applications()).toEqual(before);
  });

  it('pendingReview recomputes after status transitions', () => {
    expect(service.pendingReview().length).toBe(1);
    service.approve('app-002');
    expect(service.pendingReview().length).toBe(0);
  });
});

import { TestBed } from '@angular/core/testing';
