  });

  it('paidCount matches the number of paid payments (11 of 12)', async () => {
    await service.load();
    expect(service.paidCount()).toBe(11);
  });

  it('totalPaidTtm sums only paid payments', async () => {
    await service.load();
    const expected = service
      .payments()
      .filter((p) => p.status === 'paid')
      .reduce((s, p) => s + p.amount, 0);
    expect(service.totalPaidTtm()).toBe(expected);
    expect(service.kpis()!.totalPaidTtm).toBe(expected);
  });

  it('avgMonthlySpend equals round(totalPaidTtm / 11)', async () => {
    await service.load();
    const kpis = service.kpis()!;
    expect(kpis.avgMonthlySpend).toBe(Math.round(kpis.totalPaidTtm / 11));
  });

  it('activeRental returns the single active booking', async () => {
    await service.load();
    const active = service.activeRental();
    expect(active).not.toBeNull();
    expect(active!.status).toBe('active');
  });

  it('nextBooking returns the upcoming booking with daysUntilStart set', async () => {
    await service.load();
    const next = service.nextBooking();
    expect(next).not.toBeNull();
    expect(next!.status).toBe('upcoming');
    expect(next!.daysUntilStart).toBeGreaterThan(0);
  });

  it('kpis exposes a fixed snapshot (currency, counts, peak month)', async () => {
    await service.load();
    const kpis = service.kpis()!;
    expect(kpis.currency).toBe('EUR');
    expect(kpis.activeBookings).toBe(1);
    expect(kpis.completedRentals).toBe(2);
    expect(kpis.savedFavourites).toBe(4);
    expect(kpis.peakMonth).toBe('Set 2025');
  });

  it('spendingHistory entries satisfy total = rent + fees', async () => {
    await service.load();
    for (const point of service.spendingHistory()) {
      expect(point.total).toBe(point.rent + point.fees);
    }
  });

  it('favourites contains both available and unavailable properties', async () => {
    await service.load();
    const favs = service.favourites();
    expect(favs.some((f) => f.available)).toBe(true);
    expect(favs.some((f) => !f.available)).toBe(true);
  });

  it('formatAmount returns a pt-PT EUR currency string', () => {
    const formatted = service.formatAmount(1250);
    expect(formatted).toMatch(/1.?250/);
    expect(formatted).toContain('€');
  });

  it('formatAmount drops fractional digits', () => {
    const formatted = service.formatAmount(1234.56);
    expect(formatted).not.toContain(',56');
    expect(formatted).not.toContain('.56');
  });

  it('load() can be re-invoked with a tenantId and refreshes lastUpdated', async () => {
    await service.load('tenant-a');
    const first = service.dashboard()!.lastUpdated;
    await new Promise((r) => setTimeout(r, 5));
    await service.load('tenant-b');
    const second = service.dashboard()!.lastUpdated;
    expect(second >= first).toBe(true);
  });

  it('clears error to null on successful load', async () => {
    await service.load();
    expect(service.error()).toBeNull();
  });
});

/**
 * @fileoverview TenantDashboardService — Sprint 033
 *
 * Signal-based analytics service for tenant (renter) dashboard data.
 * Provides computed signals for payment history, upcoming bookings,
 * spending analytics, and favourite properties.
 *
 * Companion to PaymentReceiptComponent, MyBookingsComponent, and
 * the ResourceSnapshot pattern (RESOURCE_SNAPSHOT).
 *
 * Feature flag: TENANT_DASHBOARD
 */
import { Injectable, signal, computed } from '@angular/core';

// ─── Types ────────────────────────────────────────────────────────────────────

/** A single tenant payment record */
export interface TenantPayment {
  /** Unique payment id */
  id: string;
  /** Invoice reference (e.g. INV-2026-0042) */
  invoiceRef: string;
  /** Property title */
  propertyTitle: string;
  /** Property address */
  propertyAddress: string;
  /** ISO date of payment */
  paidAt: string;
  /** Amount in EUR */
  amount: number;
  /** Payment status */
  status: 'paid' | 'pending' | 'overdue';
  /** Month label (e.g. "Jan 2026") */
  monthLabel: string;
}

/** An upcoming booking / active rental */
export interface TenantBooking {
  /** Unique booking id */
  id: string;
  /** Property title */
  propertyTitle: string;
  /** Property address */
  propertyAddress: string;
  /** Optional property thumbnail */
  propertyImageUrl?: string;
  /** Lease/booking start date (ISO) */
  startDate: string;
  /** Lease/booking end date (ISO) */
  endDate: string;
  /** Monthly rent in EUR */
  monthlyRent: number;
  /** Booking state */
  status: 'active' | 'upcoming' | 'past';
  /** Days until move-in (0 if active) */
  daysUntilStart?: number;
}

/** A favourite property summary */
export interface TenantFavouriteProperty {
  /** Unique property id */
  id: string;
  /** Property title */
  title: string;
  /** Full address */
  address: string;
  /** Neighbourhood / area */
  neighbourhood: string;
  /** Monthly rent in EUR */
  monthlyRent: number;
  /** Optional thumbnail URL */
  imageUrl?: string;
  /** Date saved (ISO) */
  savedAt: string;
  /** Whether still available */
  available: boolean;
  /** Average rating */
  rating?: number;
}

/** Monthly spending data point */
export interface TenantSpendingPoint {
  /** Month label (e.g. "Jan") */
  month: string;
  /** Rent paid in EUR */
  rent: number;
  /** Other fees (service, cleaning, etc.) in EUR */
  fees: number;
  /** Total amount */
  total: number;
}

/** Top-level KPI snapshot for the tenant */
export interface TenantKPIs {
  /** Total rent paid in trailing 12 months */
  totalPaidTtm: number;
  /** Average monthly spend TTM */
  avgMonthlySpend: number;
  /** Number of active/upcoming bookings */
  activeBookings: number;
  /** Number of completed rentals */
  completedRentals: number;
  /** Number of saved favourite properties */
  savedFavourites: number;
  /** Most expensive month label */
  peakMonth: string;
  /** Currency code */
  currency: string;
}

/** Full tenant dashboard dataset */
export interface TenantDashboard {
  kpis: TenantKPIs;
  payments: TenantPayment[];
  bookings: TenantBooking[];
  favourites: TenantFavouriteProperty[];
  spendingHistory: TenantSpendingPoint[];
  lastUpdated: string;
}

