/**
 * TenantDashboardService — Sprint 033
 *
 * Signal-based service providing renter analytics and dashboard state.
 * Mirrors the landlord-side RevenueAnalyticsService pattern.
 *
 * Feature flag: TENANT_DASHBOARD
 */
@Injectable({ providedIn: 'root' })
export class TenantDashboardService {
  // ── State signals ──────────────────────────────────────────────────────────

  private readonly _isLoading = signal(false);
  private readonly _error = signal<string | null>(null);
  private readonly _dashboard = signal<TenantDashboard | null>(null);

  // ── Public reads ───────────────────────────────────────────────────────────

  /** Whether data is loading */
  readonly isLoading = this._isLoading.asReadonly();

  /** Error message, if any */
  readonly error = this._error.asReadonly();

  /** Full dashboard dataset */
  readonly dashboard = this._dashboard.asReadonly();

  // ── Computed KPIs ──────────────────────────────────────────────────────────

  /** Top-level KPIs, null until loaded */
  readonly kpis = computed(() => this._dashboard()?.kpis ?? null);

  /** Payment history, newest first */
  readonly payments = computed(() => this._dashboard()?.payments ?? []);

  /** Active + upcoming bookings */
  readonly bookings = computed(() => this._dashboard()?.bookings ?? []);

  /** Favourite properties */
  readonly favourites = computed(() => this._dashboard()?.favourites ?? []);

  /** Monthly spending history (12 months) */
  readonly spendingHistory = computed(() => this._dashboard()?.spendingHistory ?? []);

  /** Count of paid invoices */
  readonly paidCount = computed(() => this.payments().filter(p => p.status === 'paid').length);

  /** Total paid TTM (from payments signal) */
  readonly totalPaidTtm = computed(() =>
    this.payments().filter(p => p.status === 'paid').reduce((sum, p) => sum + p.amount, 0)
  );

  /** Active rental (the one with status=active) */
  readonly activeRental = computed(() => this.bookings().find(b => b.status === 'active') ?? null);

  /** Next upcoming booking */
  readonly nextBooking = computed(() => this.bookings().find(b => b.status === 'upcoming') ?? null);

  // ── Methods ────────────────────────────────────────────────────────────────

  /**
   * Load tenant dashboard data for the given tenantId.
   * Returns mock data after a short simulated delay.
   *
   * @param tenantId - Optional tenant identifier (used for multi-tenant scenarios)
   */
  async load(tenantId?: string): Promise<void> {
    this._isLoading.set(true);
    this._error.set(null);

    try {
      // Simulate network delay
      await new Promise(resolve => setTimeout(resolve, 550));

      const payments = buildMockPayments();
      const spendingHistory = buildMockSpending();
      const totalPaid = payments.filter(p => p.status === 'paid').reduce((s, p) => s + p.amount, 0);
      const avgMonthly = Math.round(totalPaid / 11); // 11 paid months

      const kpis: TenantKPIs = {
        totalPaidTtm: totalPaid,
        avgMonthlySpend: avgMonthly,
        activeBookings: 1,
        completedRentals: 2,
        savedFavourites: 4,
        peakMonth: 'Set 2025', // highest rent + fees month
        currency: 'EUR',
      };

      this._dashboard.set({
        kpis,
        payments,
        bookings: buildMockBookings(),
        favourites: buildMockFavourites(),
        spendingHistory,
        lastUpdated: new Date().toISOString(),
      });
    } catch (err) {
      this._error.set('Failed to load tenant dashboard data');
    } finally {
      this._isLoading.set(false);
    }
  }

  /**
   * Format a currency amount using pt-PT locale.
   *
   * @param amount - Numeric value in EUR
   * @returns Formatted string like "1.250,00 €"
   */
  formatAmount(amount: number): string {
    return new Intl.NumberFormat('pt-PT', {
      style: 'currency',
      currency: 'EUR',
      minimumFractionDigits: 0,
      maximumFractionDigits: 0,
    }).format(amount);
  }
}

import { TestBed } from '@angular/core/testing';
import {
  UtilityBillsService,
  type AddBillPayload,
  type BillStatus,
  type UtilityType,
} from './utility-bills.service';

describe('UtilityBillsService', () => {
  let service: UtilityBillsService;

  beforeEach(() => {
    TestBed.configureTestingModule({});
    service = TestBed.inject(UtilityBillsService);
  });

  it('seeds with the mock bill list spanning every utility type seeded', () => {
    const bills = service.bills();
    expect(bills.length).toBe(6);
    const types = new Set(bills.map(b => b.type));
    for (const t of ['electricity', 'water', 'gas', 'internet', 'waste'] as UtilityType[]) {
      expect(types.has(t)).toBe(true);
    }
  });

  it('filtered returns the full list when every filter is "all"', () => {
    expect(service.filtered().length).toBe(service.bills().length);
  });

  it('setFilterStatus narrows filtered to bills with that status', () => {
    service.setFilterStatus('paid');
    expect(service.filterStatus()).toBe('paid');
    expect(service.filtered().every(b => b.status === 'paid')).toBe(true);
    expect(service.filtered().length).toBe(3);
  });

  it('setFilterType narrows filtered to bills of that utility type', () => {
    service.setFilterType('electricity');
    expect(service.filterType()).toBe('electricity');
    expect(service.filtered().every(b => b.type === 'electricity')).toBe(true);
    expect(service.filtered().length).toBe(2);
  });

  it('setFilterProperty narrows filtered to one propertyId', () => {
    service.setFilterProperty('prop-001');
    expect(service.filtered().every(b => b.propertyId === 'prop-001')).toBe(true);
    expect(service.filtered().length).toBe(2);
  });

  it('filters compose — status + type combined intersect', () => {
    service.setFilterStatus('paid');
    service.setFilterType('electricity');
    const out = service.filtered();
    expect(out.every(b => b.status === 'paid' && b.type === 'electricity')).toBe(true);
    expect(out.length).toBe(1);
  });

  it('kpis sums totalDue across pending+overdue, totalPaid across paid only', () => {
    const k = service.kpis();
    // pending: ub003 (56.80) + overdue: ub002 (34.20) = 91.00
    expect(k.totalDue).toBeCloseTo(91.0, 2);
    // paid: ub001 (87.40) + ub004 (39.99) + ub006 (18.00) = 145.39
    expect(k.totalPaid).toBeCloseTo(145.39, 2);
    expect(k.overdue).toBe(1);
    expect(k.disputed).toBe(1);
  });

  it('addBill prepends to bills with defaulted currency/status and generated id', () => {
    const payload: AddBillPayload = {
      propertyId: 'prop-009',
      propertyAddress: 'Test 1, Lisboa',
      type: 'gas',
      provider: 'Galp',
      amount: 42.5,
      payer: 'tenant',
      dueDate: '2026-06-01',
      period: 'May 2026',
    };
    const before = service.bills().length;
    service.addBill(payload);
    const after = service.bills();
    expect(after.length).toBe(before + 1);
    const added = after[0];
    expect(added.id).toMatch(/^ub\d+/);
    expect(added.currency).toBe('EUR');
    expect(added.status).toBe('pending');
    expect(added.issueDate).toMatch(/^\d{4}-\d{2}-\d{2}$/);
    expect(added.propertyId).toBe('prop-009');
  });

  it('addBill preserves caller-provided currency, status and issueDate over defaults', () => {
    const payload: AddBillPayload & { currency?: string; issueDate?: string } = {
      propertyId: 'prop-010',
      propertyAddress: 'Test 2, Lisboa',
      type: 'water',
      provider: 'EPAL',
      amount: 12,
      currency: 'USD',
      payer: 'landlord',
      issueDate: '2026-01-01',
      dueDate: '2026-01-31',
      period: 'January 2026',
    };
    service.addBill(payload);
    const added = service.bills()[0];
    expect(added.currency).toBe('USD');
    expect(added.issueDate).toBe('2026-01-01');
  });

  it('markPaid switches status to "paid" and stamps paidDate', () => {
    // ub002 is overdue at seed; flip it to paid
    service.markPaid('ub002');
    const b = service.bills().find(x => x.id === 'ub002')!;
    expect(b.status).toBe('paid');
    expect(b.paidDate).toMatch(/^\d{4}-\d{2}-\d{2}$/);
    expect(service.kpis().overdue).toBe(0);
  });

  it('markPaid on unknown id is a no-op', () => {
    const before = service.bills();
    service.markPaid('does-not-exist');
    expect(service.bills()).toEqual(before);
  });

  it('disputeBill sets status to "disputed" and stores provided notes', () => {
    service.disputeBill('ub001', 'Charge mismatch with meter reading');
    const b = service.bills().find(x => x.id === 'ub001')!;
    expect(b.status).toBe('disputed');
    expect(b.notes).toBe('Charge mismatch with meter reading');
    expect(service.kpis().disputed).toBe(2);
  });

  it('typeIcon returns a non-empty glyph for each defined utility type', () => {
    const types: UtilityType[] = ['electricity', 'water', 'gas', 'internet', 'waste', 'other'];
    for (const t of types) {
      expect(service.typeIcon(t).length).toBeGreaterThan(0);
    }
  });

  it('statusColor returns hex-like values for each bill status', () => {
    const statuses: BillStatus[] = ['pending', 'paid', 'overdue', 'disputed'];
    for (const s of statuses) {
      expect(service.statusColor(s)).toMatch(/^#[0-9A-Fa-f]{6}$/);
    }
  });

  it('split bills retain their splitRatio when filtered through type', () => {
    service.setFilterType('gas');
    const out = service.filtered();
    expect(out.length).toBe(1);
    expect(out[0].payer).toBe('split');
    expect(out[0].splitRatio).toBe(40);
  });
});

import { TestBed } from '@angular/core/testing';
import {
  ViewingSchedulerService,
  type RequestViewingPayload,
  type ViewingStatus,
} from './viewing-scheduler.service';

describe('ViewingSchedulerService', () => {
  let service: ViewingSchedulerService;

  beforeEach(() => {
    TestBed.configureTestingModule({});
    service = TestBed.inject(ViewingSchedulerService);
  });

  it('seeds with the mock viewing list covering every status used in fixtures', () => {
    const all = service.viewings();
    expect(all.length).toBe(5);
    const statuses = new Set(all.map(v => v.status));
    for (const s of ['pending', 'confirmed', 'cancelled', 'completed'] as ViewingStatus[]) {
      expect(statuses.has(s)).toBe(true);
    }
  });

  it('kpis aggregates counts per status from seed data', () => {
    const k = service.kpis();
    expect(k.total).toBe(5);
    expect(k.pending).toBe(2);
    expect(k.confirmed).toBe(1);
    expect(k.completed).toBe(1);
    expect(k.cancelled).toBe(1);
  });

  it('default filter is "all" and filtered mirrors viewings', () => {
    expect(service.filter()).toBe('all');
    expect(service.filtered().length).toBe(service.viewings().length);
  });

  it('setFilter narrows filtered to viewings with that status', () => {
    service.setFilter('pending');
    expect(service.filter()).toBe('pending');
    expect(service.filtered().every(v => v.status === 'pending')).toBe(true);
    expect(service.filtered().length).toBe(2);
  });

  it('upcoming only returns pending+confirmed viewings, sorted by date+time ascending', () => {
    const up = service.upcoming();
    expect(up.every(v => v.status === 'pending' || v.status === 'confirmed')).toBe(true);
    expect(up.length).toBe(3);
    const keys = up.map(v => v.date + v.time);
    const sorted = [...keys].sort();
    expect(keys).toEqual(sorted);
  });

  it('request prepends a pending viewing with generated id and default duration/type', () => {
    const payload: RequestViewingPayload = {
      propertyId: 'prop-009',
      propertyAddress: 'New Street, Lisboa',
      tenantId: 'tenant-099',
      tenantName: 'New Tenant',
      tenantEmail: 'new@email.com',
      date: '2026-06-01',
      time: '12:00',
    };
    const before = service.viewings().length;
    const slot = service.request(payload);
    const after = service.viewings();
    expect(after.length).toBe(before + 1);
    expect(after[0]).toBe(slot);
    expect(slot.id).toMatch(/^v\d+/);
    expect(slot.status).toBe('pending');
    expect(slot.durationMin).toBe(45);
    expect(slot.type).toBe('in_person');
    expect(slot.createdAt).toMatch(/^\d{4}-\d{2}-\d{2}T/);
  });

  it('request honours caller-provided durationMin, type and notes', () => {
    const slot = service.request({
      propertyId: 'p1',
      propertyAddress: 'A',
      tenantId: 't1',
      tenantName: 'T',
      tenantEmail: 't@e.com',
      date: '2026-06-02',
      time: '09:00',
      durationMin: 30,
      type: 'virtual',
      notes: 'prefers afternoon',
    });
    expect(slot.durationMin).toBe(30);
    expect(slot.type).toBe('virtual');
    expect(slot.notes).toBe('prefers afternoon');
  });

  it('confirm transitions a pending viewing to confirmed', () => {
    service.confirm('v002');
    const v = service.viewings().find(x => x.id === 'v002')!;
    expect(v.status).toBe('confirmed');
  });

  it('cancel transitions a viewing to cancelled', () => {
    service.cancel('v001');
    const v = service.viewings().find(x => x.id === 'v001')!;
    expect(v.status).toBe('cancelled');
  });

  it('complete transitions a viewing to completed', () => {
    service.complete('v001');
    const v = service.viewings().find(x => x.id === 'v001')!;
    expect(v.status).toBe('completed');
  });

  it('markNoShow transitions a viewing to no_show', () => {
    service.markNoShow('v001');
    const v = service.viewings().find(x => x.id === 'v001')!;
    expect(v.status).toBe('no_show');
  });

  it('confirm on unknown id is a no-op (no entries mutated)', () => {
    const before = service.viewings();
    service.confirm('does-not-exist');
    expect(service.viewings()).toEqual(before);
  });

  it('cancel/complete/markNoShow on unknown ids are no-ops', () => {
    const before = service.viewings();
    service.cancel('nope');
    service.complete('nope');
    service.markNoShow('nope');
    expect(service.viewings()).toEqual(before);
  });

  it('kpis recompute reactively after a status transition', () => {
    expect(service.kpis().pending).toBe(2);
    expect(service.kpis().confirmed).toBe(1);
    service.confirm('v002');
    expect(service.kpis().pending).toBe(1);
    expect(service.kpis().confirmed).toBe(2);
  });

  it('upcoming drops a viewing once it is cancelled', () => {
    const beforeIds = service.upcoming().map(v => v.id);
    expect(beforeIds).toContain('v002');
    service.cancel('v002');
    const afterIds = service.upcoming().map(v => v.id);
    expect(afterIds).not.toContain('v002');
  });

  it('upcoming reflects a newly requested viewing in sorted position', () => {
    service.request({
      propertyId: 'p1',
      propertyAddress: 'A',
      tenantId: 't1',
      tenantName: 'T',
      tenantEmail: 't@e.com',
      date: '2026-04-04',
      time: '08:00',
    });
    const up = service.upcoming();
    const keys = up.map(v => v.date + v.time);
    expect(keys).toEqual([...keys].sort());
    expect(up.some(v => v.date === '2026-04-04' && v.time === '08:00')).toBe(true);
  });
});
